1	/**
2	 * Core types for the track system.
3	 * Tracks contain clips; clips are non-destructive references to audio sources.
4	 */
5	
6	export type TrackType = "audio" | "instrument";
7	
8	export type TrackModel = {
9	  readonly id: string;
10	  readonly name: string;
11	  readonly type: TrackType;
12	  readonly color: string;
13	  readonly muted: boolean;
14	  readonly solo: boolean;
15	  readonly armed: boolean;
16	  readonly soloIsolate: boolean;
17	  readonly volume: number; // 0..2
18	  readonly pan: number; // -1..1
19	  readonly clipIds: readonly string[];
20	};
21	
22	export type ClipModel = {
23	  readonly id: string;
24	  readonly trackId: string;
25	  readonly sourceId: string;
26	  readonly startTime: number; // seconds on timeline
27	  readonly sourceOffset: number; // seconds into source
28	  readonly duration: number; // seconds
29	  readonly gain: number; // 0..2
30	  readonly fadeIn: number; // seconds
31	  readonly fadeOut: number; // seconds
32	  readonly name: string;
33	};
