1	/**
2	 * Synthesizer AudioWorklet processor.
3	 * Runs on the audio rendering thread — zero allocations in process().
4	 *
5	 * Architecture: 16 fixed voices, each with:
6	 * - 2 PolyBLEP oscillators
7	 * - Biquad filter (LP/HP/BP)
8	 * - ADSR amplitude envelope
9	 * - ADSR filter envelope
10	 * Shared: 2 LFOs, hardwired modulation matrix.
11	 *
12	 * INV-3/NFR-14: Zero-allocation process().
13	 * MIT-H4-5: Oldest-steal with 5ms crossfade.
14	 * MIT-H4-6: 2ms minimum release time.
15	 * R-STA-05: Legato mode with pitch glide.
16	 */
17	
18	import { createPolyBLEPOsc, type PolyBLEPOsc } from "./dsp/polyblep";
19	import {
20	  createADSREnvelope,
21	  type ADSREnvelope,
22	  type ADSRParams,
23	} from "./dsp/adsr";
24	import {
25	  computeBiquadCoeffs,
26	  createBiquadFilter,
27	  type BiquadFilter,
28	} from "./dsp/biquad-coeffs";
29	import { createLFO, type LFO } from "./dsp/lfo";
30	import {
31	  createVoiceAllocator,
32	  type VoiceAllocator,
33	  MAX_VOICES,
34	} from "./dsp/voice-allocator";
35	import {
36	  midiToFreq,
37	  WAVEFORM_TYPES,
38	  FILTER_TYPES,
39	  LFO_SHAPES,
40	  type SynthVoiceCommand,
41	  type SynthParameterMap,
42	  DEFAULT_SYNTH_PARAMS,
43	} from "./synth-types";
44	
45	// ─── AudioWorklet globals ───
46	declare const sampleRate: number;
47	declare class AudioWorkletProcessor {
48	  readonly port: MessagePort;
49	  constructor();
50	  process(
51	    inputs: Float32Array[][],
52	    outputs: Float32Array[][],
53	    parameters: Record<string, Float32Array>,
54	  ): boolean;
55	}
56	declare function registerProcessor(
57	  name: string,
58	  ctor: typeof AudioWorkletProcessor,
59	): void;
60	
61	// ─── Per-Voice State (pre-allocated) ───
62	
63	type VoiceData = {
64	  osc1: PolyBLEPOsc;
65	  osc2: PolyBLEPOsc;
66	  ampEnv: ADSREnvelope;
67	  filterEnv: ADSREnvelope;
68	  filter: BiquadFilter;
69	  targetFreq: number;
70	  currentFreq: number;
71	  velocity: number;
72	};
73	
74	function createVoiceData(): VoiceData {
75	  return {
76	    osc1: createPolyBLEPOsc("saw"),
77	    osc2: createPolyBLEPOsc("saw"),
78	    ampEnv: createADSREnvelope(),
79	    filterEnv: createADSREnvelope(),
80	    filter: createBiquadFilter("lowpass"),
81	    targetFreq: 440,
82	    currentFreq: 440,
83	    velocity: 0,
84	  };
85	}
86	
87	/** Safe access to pre-allocated arrays */
88	function at<T>(arr: T[], i: number): T {
89	  const val = arr[i];
90	  if (val === undefined) throw new Error("Index out of bounds");
91	  return val;
92	}
93	
94	class SynthProcessor extends AudioWorkletProcessor {
95	  private allocator: VoiceAllocator;
96	  private voiceData: VoiceData[];
97	  private lfo1: LFO;
98	  private lfo2: LFO;
99	  private params: SynthParameterMap;
100	  // Pre-allocated ADSR params (S2-3: avoid per-quantum allocation)
101	  private ampParams: ADSRParams;
102	  private filterParams: ADSRParams;
103	  private alive = true;
104	
105	  constructor() {
106	    super();
107	
108	    this.allocator = createVoiceAllocator();
109	    this.voiceData = Array.from({ length: MAX_VOICES }, () =>
110	      createVoiceData(),
111	    );
112	    this.lfo1 = createLFO("sine");
113	    this.lfo2 = createLFO("sine");
114	    this.params = { ...DEFAULT_SYNTH_PARAMS };
115	    this.ampParams = { attack: 0, decay: 0, sustain: 0, release: 0 };
116	    this.filterParams = { attack: 0, decay: 0, sustain: 0, release: 0 };
117	
118	    this.port.onmessage = (e: MessageEvent) => {
119	      this.handleMessage(e.data as SynthVoiceCommand);
120	    };
121	  }
122	
123	  private handleMessage(cmd: SynthVoiceCommand): void {
124	    switch (cmd.type) {
125	      case "noteOn": {
126	        const legato = cmd.legato;
127	        const idx = this.allocator.noteOn(cmd.note, cmd.velocity, legato);
128	        const voice = at(
129	          this.allocator.voices as unknown[],
130	          idx,
131	        ) as (typeof this.allocator.voices)[number];
132	
133	        // If voice is stealing, don't touch oscillators/envelopes yet —
134	        // the old voice continues rendering during the 5ms crossfade.
135	        // The processor will apply the new note when steal completes.
136	        if (voice.state === "stealing") {
137	          return;
138	        }
139	
140	        this.applyNoteOn(idx, cmd.note, cmd.velocity, legato);
141	        break;
142	      }
143	
144	      case "noteOff": {
145	        const idx = this.allocator.noteOff(cmd.note);
146	        if (idx >= 0) {
147	          const vd = at(this.voiceData, idx);
148	          vd.ampEnv.release();
149	          vd.filterEnv.release();
150	        }
151	        break;
152	      }
153	
154	      case "allNotesOff":
155	        // S1-4: Must also update allocator state
156	        for (let i = 0; i < MAX_VOICES; i++) {
157	          const voice = at(
158	            this.allocator.voices as unknown[],
159	            i,
160	          ) as (typeof this.allocator.voices)[number];
161	          if (voice.state === "active") {
162	            (voice as { state: string }).state = "releasing";
163	          } else if (voice.state === "stealing") {
164	            // Cancel pending steal — clear pending note and release
165	            (voice as { state: string }).state = "releasing";
166	            (voice as { pendingNote: number }).pendingNote = -1;
167	            (voice as { pendingVelocity: number }).pendingVelocity = 0;
168	          }
169	          at(this.voiceData, i).ampEnv.release();
170	          at(this.voiceData, i).filterEnv.release();
171	        }
172	        break;
173	
174	      case "setParam":
175	        this.setParamValue(cmd.key, cmd.value);
176	        break;
177	    }
178	  }
179	
180	  /** Apply a note-on to voice oscillators and envelopes */
181	  private applyNoteOn(
182	    idx: number,
183	    note: number,
184	    velocity: number,
185	    legato: boolean,
186	  ): void {
187	    const vd = at(this.voiceData, idx);
188	
189	    const baseFreq = midiToFreq(note);
190	    vd.targetFreq = baseFreq;
191	    vd.velocity = velocity / 127;
192	
193	    if (!legato || vd.currentFreq === 0) {
194	      vd.currentFreq = baseFreq;
195	    }
196	
197	    if (!legato) {
198	      vd.osc1.reset();
199	      vd.osc2.reset();
200	      vd.filter.reset();
201	    }
202	
203	    vd.osc1.type = this.params.osc1Type;
204	    vd.osc2.type = this.params.osc2Type;
205	    vd.filter.type = this.params.filterType;
206	
207	    vd.ampEnv.gate(legato);
208	    vd.filterEnv.gate(legato);
209	  }
210	
211	  private setParamValue(key: string, value: number): void {
212	    switch (key) {
213	      case "osc1Type":
214	        this.params.osc1Type = WAVEFORM_TYPES[Math.round(value)] ?? "saw";
215	        break;
216	      case "osc2Type":
217	        this.params.osc2Type = WAVEFORM_TYPES[Math.round(value)] ?? "saw";
218	        break;
219	      case "filterType": {
220	        const ft = FILTER_TYPES[Math.round(value)] ?? "lowpass";
221	        this.params.filterType = ft;
222	        for (let i = 0; i < MAX_VOICES; i++) {
223	          at(this.voiceData, i).filter.type = ft;
224	        }
225	        break;
226	      }
227	      case "lfo1Shape":
228	        this.params.lfo1Shape = LFO_SHAPES[Math.round(value)] ?? "sine";
229	        this.lfo1.shape = this.params.lfo1Shape;
230	        break;
231	      case "lfo2Shape":
232	        this.params.lfo2Shape = LFO_SHAPES[Math.round(value)] ?? "sine";
233	        this.lfo2.shape = this.params.lfo2Shape;
234	        break;
235	      default:
236	        (this.params as Record<string, unknown>)[key] = value;
237	        break;
238	    }
239	  }
240	
241	  process(
242	    _inputs: Float32Array[][],
243	    outputs: Float32Array[][],
244	    _parameters: Record<string, Float32Array>,
245	  ): boolean {
246	    const output = outputs[0];
247	    if (!output) return this.alive;
248	
249	    const outL = output[0];
250	    const outR = output[1] ?? output[0];
251	    if (!outL || !outR) return this.alive;
252	
253	    const numSamples = outL.length;
254	    const sr = sampleRate;
255	    const p = this.params;
256	
257	    // Update pre-allocated ADSR params in-place (S2-3)
258	    this.ampParams.attack = p.ampAttack;
259	    this.ampParams.decay = p.ampDecay;
260	    this.ampParams.sustain = p.ampSustain;
261	    this.ampParams.release = p.ampRelease;
262	
263	    this.filterParams.attack = p.filterAttack;
264	    this.filterParams.decay = p.filterDecay;
265	    this.filterParams.sustain = p.filterSustain;
266	    this.filterParams.release = p.filterRelease;
267	
268	    // Pre-compute control-rate values (constant across quantum)
269	    const osc1OctMul = Math.pow(2, p.osc1Octave);
270	    const osc1DetMul = Math.pow(2, p.osc1Detune / 1200);
271	    const osc2OctMul = Math.pow(2, p.osc2Octave);
272	    const osc2DetMul = Math.pow(2, p.osc2Detune / 1200);
273	
274	    for (let s = 0; s < numSamples; s++) {
275	      const lfo1Val = this.lfo1.process(p.lfo1Rate, sr);
276	      const lfo2Val = this.lfo2.process(p.lfo2Rate, sr);
277	
278	      let mixL = 0;
279	      let mixR = 0;
280	
281	      for (let vi = 0; vi < MAX_VOICES; vi++) {
282	        const voice = at(this.allocator.voices as unknown[], vi) as {
283	          state: string;
284	          stealFadeGain: number;
285	        };
286	
287	        // S2-5: Early idle check before any DSP work
288	        if (voice.state === "idle") continue;
289	
290	        const vd = at(this.voiceData, vi);
291	
292	        // Check if envelope finished release — mark idle before processing
293	        if (vd.ampEnv.stage === "idle" && voice.state === "releasing") {
294	          this.allocator.markIdle(vi);
295	          continue;
296	        }
297	
298	        // Pitch glide (R-STA-05)
299	        if (p.glideTime > 0 && vd.currentFreq !== vd.targetFreq) {
300	          const glideCoeff = 1 - Math.exp(-1 / (p.glideTime * sr));
301	          vd.currentFreq += glideCoeff * (vd.targetFreq - vd.currentFreq);
302	        } else {
303	          vd.currentFreq = vd.targetFreq;
304	        }
305	
306	        const baseFreq = vd.currentFreq;
307	
308	        // LFO1 -> pitch modulation (in semitones)
309	        const pitchMod = lfo1Val * p.lfo1Depth * 2;
310	        const pitchMultiplier = Math.pow(2, pitchMod / 12);
311	
312	        const freq1 = baseFreq * osc1OctMul * osc1DetMul * pitchMultiplier;
313	        const freq2 = baseFreq * osc2OctMul * osc2DetMul * pitchMultiplier;
314	
315	        const osc1Out = vd.osc1.next(freq1, sr) * p.osc1Level;
316	        const osc2Out = vd.osc2.next(freq2, sr) * p.osc2Level;
317	        let sample = osc1Out + osc2Out;
318	
319	        // Filter envelope (must process every sample to advance state)
320	        const filterEnvVal = vd.filterEnv.process(this.filterParams, sr);
321	
322	        // Control-rate filter coefficients: recompute once per block per voice
323	        // (avoids expensive Math.sin/cos per-sample; block rate ~3ms at 44.1kHz)
324	        if (s === 0) {
325	          const envCutoffMod = filterEnvVal * p.filterEnvDepth;
326	          const lfoCutoffMod = lfo1Val * p.lfo1Depth * 12;
327	          const velCutoffMod = vd.velocity * 24;
328	          const totalCutoffMod = envCutoffMod + lfoCutoffMod + velCutoffMod;
329	          const modulatedCutoff =
330	            p.filterCutoff * Math.pow(2, totalCutoffMod / 12);
331	          const clampedCutoff = Math.min(
332	            Math.max(modulatedCutoff, 20),
333	            sr / 2 - 100,
334	          );
335	          computeBiquadCoeffs(
336	            p.filterType,
337	            clampedCutoff,
338	            p.filterResonance,
339	            sr,
340	            vd.filter.coeffs,
341	          );
342	        }
343	
344	        sample = vd.filter.process(sample);
345	
346	        // Amplitude envelope
347	        const ampLevel = vd.ampEnv.process(this.ampParams, sr);
348	
349	        // LFO2 -> amplitude modulation (tremolo)
350	        const ampMod = 1 + lfo2Val * p.lfo2Depth * 0.5;
351	
352	        // Velocity -> amplitude
353	        const velAmp = 0.5 + vd.velocity * 0.5;
354	
355	        sample *= ampLevel * ampMod * velAmp * p.masterGain;
356	
357	        // S1-2: Apply steal crossfade gain to old voice audio
358	        if (voice.state === "stealing") {
359	          sample *= voice.stealFadeGain;
360	        }
361	
362	        mixL += sample;
363	        mixR += sample;
364	      }
365	
366	      // Process steal fades and get completed steals
367	      const completed = this.allocator.processStealFade(sr);
368	
369	      // S1-3: Apply pending notes for voices that completed steal crossfade
370	      for (let ci = 0; ci < completed.count; ci++) {
371	        const completedIdx = completed.data[ci];
372	        if (completedIdx !== undefined) {
373	          const voice = at(
374	            this.allocator.voices as unknown[],
375	            completedIdx,
376	          ) as {
377	            note: number;
378	            velocity: number;
379	          };
380	          this.applyNoteOn(completedIdx, voice.note, voice.velocity, false);
381	        }
382	      }
383	
384	      outL[s] = mixL;
385	      outR[s] = mixR;
386	    }
387	
388	    return this.alive;
389	  }
390	}
391	
392	registerProcessor("synth-processor", SynthProcessor);
