1	/**
2	 * Pure canvas renderer for the arrangement view.
3	 * No DOM access -- only draws to the CanvasRenderingContext2D passed in.
4	 */
5	import type { TrackModel, ClipModel } from "@state/track/types";
6	import { RULER_HEIGHT, CLIP_PADDING } from "./constants";
7	
8	// -- Design token constants (canvas cannot read CSS vars) ---------------------
9	
10	const COLOR = {
11	  black: "#000000",
12	  white: "#ffffff",
13	  red: "#ff0000",
14	  gray900: "#111111",
15	  gray700: "#333333",
16	  gray500: "#666666",
17	} as const;
18	
19	const FONT_MONO = "'JetBrains Mono', monospace" as const;
20	const TEXT_XS = 10;
21	const TEXT_SM = 12;
22	const BORDER_WIDTH = 2;
23	const COLOR_STRIP_WIDTH = 4;
24	
25	// -- Public types -------------------------------------------------------------
26	
27	export type ArrangementViewState = {
28	  scrollX: number;
29	  scrollY: number;
30	  pixelsPerSecond: number;
31	  trackHeight: number;
32	  headerWidth: number;
33	};
34	
35	export type RenderContext = {
36	  ctx: CanvasRenderingContext2D;
37	  width: number;
38	  height: number;
39	  view: ArrangementViewState;
40	  tracks: readonly TrackModel[];
41	  clips: Record<string, ClipModel>;
42	  selectedClipIds: readonly string[];
43	  cursorSeconds: number;
44	  bpm: number;
45	};
46	
47	// -- Helpers ------------------------------------------------------------------
48	
49	function secondsToX(seconds: number, view: ArrangementViewState): number {
50	  return view.headerWidth + (seconds - view.scrollX) * view.pixelsPerSecond;
51	}
52	
53	function trackY(index: number, view: ArrangementViewState): number {
54	  return RULER_HEIGHT + index * view.trackHeight - view.scrollY;
55	}
56	
57	/** Convert a hex color (#rrggbb) to rgba with given alpha (0-1). */
58	function hexToRgba(hex: string, alpha: number): string {
59	  if (!/^#[0-9a-fA-F]{6}$/.test(hex)) {
60	    return `rgba(128,128,128,${String(alpha)})`;
61	  }
62	  const r = parseInt(hex.slice(1, 3), 16);
63	  const g = parseInt(hex.slice(3, 5), 16);
64	  const b = parseInt(hex.slice(5, 7), 16);
65	  return `rgba(${String(r)},${String(g)},${String(b)},${String(alpha)})`;
66	}
67	
68	// -- Rendering stages ---------------------------------------------------------
69	
70	function drawBackground(rc: RenderContext): void {
71	  const { ctx, width, height } = rc;
72	  ctx.fillStyle = COLOR.gray900;
73	  ctx.fillRect(0, 0, width, height);
74	}
75	
76	function drawTimeRuler(rc: RenderContext): void {
77	  const { ctx, width, view, bpm } = rc;
78	  const secPerBeat = 60 / bpm;
79	  const secPerBar = secPerBeat * 4;
80	
81	  // Ruler background
82	  ctx.fillStyle = COLOR.black;
83	  ctx.fillRect(0, 0, width, RULER_HEIGHT);
84	
85	  // Bar labels
86	  ctx.font = `${String(TEXT_XS)}px ${FONT_MONO}`;
87	  ctx.fillStyle = COLOR.gray500;
88	  ctx.textBaseline = "middle";
89	  ctx.textAlign = "center";
90	
91	  const startBar = Math.max(0, Math.floor(view.scrollX / secPerBar));
92	  const endSec =
93	    view.scrollX + (width - view.headerWidth) / view.pixelsPerSecond;
94	  const endBar = Math.ceil(endSec / secPerBar) + 1;
95	
96	  for (let bar = startBar; bar < endBar; bar++) {
97	    const x = secondsToX(bar * secPerBar, view);
98	    if (x >= view.headerWidth && x <= width) {
99	      ctx.fillText(String(bar + 1), x, RULER_HEIGHT / 2);
100	    }

1	/**
2	 * Hit-testing utilities for the arrangement canvas.
3	 * Converts pixel coordinates to track/clip references.
4	 */
5	import type { ClipModel, TrackModel } from "@state/track/types";
6	import type { ArrangementViewState } from "./arrangement-renderer";
7	import { RULER_HEIGHT, CLIP_PADDING, TRIM_HANDLE_PX } from "./constants";
8	
9	export type HitResult =
10	  | { kind: "none" }
11	  | { kind: "track-header"; trackIndex: number; trackId: string }
12	  | { kind: "clip-body"; clipId: string; trackId: string }
13	  | { kind: "clip-left-edge"; clipId: string; trackId: string }
14	  | { kind: "clip-right-edge"; clipId: string; trackId: string }
15	  | { kind: "ruler"; timeSeconds: number }
16	  | { kind: "empty-lane"; trackIndex: number; trackId: string };
17	
18	export type GridSnap = "1/4" | "1/8" | "1/16" | "1-bar";
19	
20	export function snapToGrid(
21	  seconds: number,
22	  bpm: number,
23	  snap: GridSnap,
24	): number {
25	  const secPerBeat = 60 / bpm;
26	  let gridSize: number;
27	  switch (snap) {
28	    case "1-bar":
29	      gridSize = secPerBeat * 4;
30	      break;
31	    case "1/4":
32	      gridSize = secPerBeat;
33	      break;
34	    case "1/8":
35	      gridSize = secPerBeat / 2;
36	      break;
37	    case "1/16":
38	      gridSize = secPerBeat / 4;
39	      break;
40	  }
41	  return Math.round(seconds / gridSize) * gridSize;
42	}
43	
44	export function xToSeconds(x: number, view: ArrangementViewState): number {
45	  return view.scrollX + (x - view.headerWidth) / view.pixelsPerSecond;
46	}
47	
48	export function hitTest(
49	  x: number,
50	  y: number,
51	  view: ArrangementViewState,
52	  tracks: readonly TrackModel[],
53	  clips: Record<string, ClipModel>,
54	): HitResult {
55	  // Ruler area
56	  if (y < RULER_HEIGHT) {
57	    return { kind: "ruler", timeSeconds: xToSeconds(x, view) };
58	  }
59	
60	  // Track header area
61	  if (x < view.headerWidth) {
62	    const trackIndex = Math.floor(
63	      (y - RULER_HEIGHT + view.scrollY) / view.trackHeight,
64	    );
65	    const track = tracks[trackIndex];
66	    if (track !== undefined) {
67	      return { kind: "track-header", trackIndex, trackId: track.id };
68	    }
69	    return { kind: "none" };
70	  }
71	
72	  // Timeline area
73	  const trackIndex = Math.floor(
74	    (y - RULER_HEIGHT + view.scrollY) / view.trackHeight,
75	  );
76	  const track = tracks[trackIndex];
77	  if (track === undefined) return { kind: "none" };
78	
79	  const trackY = RULER_HEIGHT + trackIndex * view.trackHeight - view.scrollY;
80	
81	  // Check clips in this track (reverse order for front-to-back priority)
82	  for (let i = track.clipIds.length - 1; i >= 0; i--) {
83	    const clipId = track.clipIds[i];
84	    if (clipId === undefined) continue;
85	    const clip = clips[clipId];
86	    if (clip === undefined) continue;
87	
88	    const clipX =
89	      view.headerWidth + (clip.startTime - view.scrollX) * view.pixelsPerSecond;
90	    const clipW = clip.duration * view.pixelsPerSecond;
91	    const clipY = trackY + CLIP_PADDING;
92	    const clipH = view.trackHeight - CLIP_PADDING * 2;
93	
94	    if (x >= clipX && x <= clipX + clipW && y >= clipY && y <= clipY + clipH) {
95	      // Left trim handle
96	      if (x - clipX < TRIM_HANDLE_PX) {
97	        return { kind: "clip-left-edge", clipId: clip.id, trackId: track.id };
98	      }
99	      // Right trim handle
100	      if (clipX + clipW - x < TRIM_HANDLE_PX) {
101	        return { kind: "clip-right-edge", clipId: clip.id, trackId: track.id };
102	      }
103	      return { kind: "clip-body", clipId: clip.id, trackId: track.id };
104	    }
105	  }
106	
107	  return { kind: "empty-lane", trackIndex, trackId: track.id };
108	}
