34	export class RemoveTrackCommand implements UndoCommand {
35	  readonly type = "remove-track";
36	
37	  private savedTrack: TrackModel | undefined;
38	  private savedClips: readonly ClipModel[] = [];
39	  private savedIndex = -1;
40	
