80	  bpm: 120,
81	  cursorSeconds: 0,
82	  loopEnabled: false,
83	  loopStart: 0,
84	  loopEnd: 0,
85	
86	  // Engine defaults
87	  engineStatus: "uninitialized",
88	
89	  // Mixer defaults
90	  masterVolume: 1,
91	
92	  // Track & clip defaults
93	  tracks: [],
94	  clips: {},
95	  selectedTrackIds: [],
96	  selectedClipIds: [],
97	
98	  // Transport actions
99	  play: () => {
100	    set({ transportState: "playing" });
101	  },
102	  pause: () => {
103	    set({ transportState: "paused" });
104	  },
105	  stop: () => {
106	    set({ transportState: "stopped", cursorSeconds: 0 });
107	  },
108	  setBpm: (bpm: number) => {
109	    const clamped = Math.min(999, Math.max(20, bpm));
110	    if (!Number.isFinite(clamped)) return;
111	    set({ bpm: clamped });
112	  },
113	  setCursor: (seconds: number) => {
114	    set({ cursorSeconds: seconds });
115	  },
116	  setLoop: (enabled: boolean, start?: number, end?: number) => {
117	    set((state) => ({
118	      loopEnabled: enabled,
119	      loopStart: start ?? state.loopStart,
120	      loopEnd: end ?? state.loopEnd,
121	    }));
122	  },
123	
124	  // Engine actions
125	  setEngineStatus: (status: AudioEngineStatus) => {
126	    set({ engineStatus: status });
127	  },
128	
129	  // Mixer actions
130	  setMasterVolume: (volume: number) => {
131	    const clamped = Math.min(2, Math.max(0, volume));
132	    set({ masterVolume: clamped });
133	  },
134	
135	  // Track actions
136	  addTrack: (track: TrackModel, index?: number) => {
137	    set((state) => {
138	      const next = [...state.tracks];
139	      if (index !== undefined) {
140	        next.splice(index, 0, track);
141	      } else {
142	        next.push(track);
143	      }
144	      return { tracks: next };
145	    });
146	  },
147	
148	  removeTrack: (id: string) => {
149	    set((state) => {
150	      const track = state.tracks.find((t) => t.id === id);
151	      if (!track) return state;
152	      const removeSet = new Set(track.clipIds);
153	      const nextClips = Object.fromEntries(
154	        Object.entries(state.clips).filter(([k]) => !removeSet.has(k)),
155	      );
156	      return {
157	        tracks: state.tracks.filter((t) => t.id !== id),
158	        clips: nextClips,
159	      };
160	    });
161	  },
162	
163	  updateTrack: (id: string, patch: Partial<Omit<TrackModel, "id">>) => {
164	    set((state) => ({
165	      tracks: state.tracks.map((t) => (t.id === id ? { ...t, ...patch } : t)),
166	    }));
167	  },
168	
169	  reorderTrack: (id: string, toIndex: number) => {
170	    set((state) => {
171	      const fromIndex = state.tracks.findIndex((t) => t.id === id);
172	      if (fromIndex === -1) return state;
173	      const next = [...state.tracks];
174	      const moved = next.splice(fromIndex, 1)[0];
175	      if (moved === undefined) return state;
176	      next.splice(toIndex, 0, moved);
177	      return { tracks: next };
178	    });
179	  },
180	
181	  // Clip actions
182	  addClip: (clip: ClipModel) => {
183	    set((state) => {
184	      const nextClips = { ...state.clips, [clip.id]: clip };
185	      const tracks = state.tracks.map((t) =>
186	        t.id === clip.trackId ? { ...t, clipIds: [...t.clipIds, clip.id] } : t,
187	      );
188	      return { clips: nextClips, tracks };
189	    });
190	  },
191	
192	  removeClip: (id: string) => {
193	    set((state) => {
194	      const clip = state.clips[id];
195	      if (!clip) return state;
196	      const nextClips = Object.fromEntries(
197	        Object.entries(state.clips).filter(([k]) => k !== id),
198	      );
199	      const tracks = state.tracks.map((t) =>
200	        t.id === clip.trackId
201	          ? { ...t, clipIds: t.clipIds.filter((cid) => cid !== id) }
202	          : t,
203	      );
204	      return { clips: nextClips, tracks };
205	    });
206	  },
207	
208	  moveClip: (id: string, startTime: number, toTrackId?: string) => {
209	    set((state) => {
210	      const clip = state.clips[id];
211	      if (!clip) return state;
212	      const updatedClip = {
213	        ...clip,
214	        startTime,
215	        trackId: toTrackId ?? clip.trackId,
216	      };
217	      const nextClips = { ...state.clips, [id]: updatedClip };
218	
219	      let tracks = state.tracks;
220	      if (toTrackId !== undefined && toTrackId !== clip.trackId) {
221	        tracks = tracks.map((t) => {
222	          if (t.id === clip.trackId) {
223	            return { ...t, clipIds: t.clipIds.filter((cid) => cid !== id) };
224	          }
225	          if (t.id === toTrackId) {
226	            return { ...t, clipIds: [...t.clipIds, id] };
227	          }
228	          return t;
229	        });
230	      }
231	      return { clips: nextClips, tracks };
232	    });
233	  },
234	
235	  splitClip: (
236	    id: string,
237	    atTime: number,
238	    providedId?: string,
239	  ): string | undefined => {
240	    const state = get();
241	    const clip = state.clips[id];
242	    if (!clip) return undefined;
243	
244	    const clipEnd = clip.startTime + clip.duration;
245	    if (atTime <= clip.startTime || atTime >= clipEnd) return undefined;
246	
247	    const leftDuration = atTime - clip.startTime;
248	    const rightDuration = clip.duration - leftDuration;
249	    const rightSourceOffset = clip.sourceOffset + leftDuration;
250	
251	    const newId = providedId ?? nextClipId();
252	
253	    const leftClip: ClipModel = { ...clip, duration: leftDuration };
254	    const rightClip: ClipModel = {
255	      ...clip,
256	      id: newId,
257	      startTime: atTime,
258	      sourceOffset: rightSourceOffset,
259	      duration: rightDuration,
260	    };
261	
262	    set((s) => {
263	      const nextClips = { ...s.clips, [id]: leftClip, [newId]: rightClip };
264	      const tracks = s.tracks.map((t) =>
265	        t.id === clip.trackId ? { ...t, clipIds: [...t.clipIds, newId] } : t,
266	      );
267	      return { clips: nextClips, tracks };
268	    });
269	
270	    return newId;
271	  },
272	
273	  trimClip: (id: string, newStart?: number, newEnd?: number) => {
274	    set((state) => {
275	      const clip = state.clips[id];
276	      if (!clip) return state;
277	
278	      let { startTime, sourceOffset, duration } = clip;
279	      const clipEnd = startTime + duration;
280	
281	      if (newStart !== undefined) {
282	        const delta = newStart - startTime;
283	        startTime = newStart;
284	        sourceOffset = sourceOffset + delta;
285	        duration = clipEnd - newStart;
286	      }
287	
288	      if (newEnd !== undefined) {
289	        duration = newEnd - startTime;
290	      }
291	
292	      // Guard against invalid state
293	      if (duration <= 0 || sourceOffset < 0) return state;
294	
295	      return {
296	        clips: {
297	          ...state.clips,
298	          [id]: { ...clip, startTime, sourceOffset, duration },
299	        },
300	      };
301	    });
302	  },
303	
304	  duplicateClip: (id: string, providedId?: string): string | undefined => {
305	    const state = get();
306	    const clip = state.clips[id];
307	    if (!clip) return undefined;
308	
309	    const newId = providedId ?? nextClipId();
310	    const duplicate: ClipModel = {
311	      ...clip,
312	      id: newId,
313	      startTime: clip.startTime + clip.duration,
314	    };
315	
316	    set((s) => {
317	      const nextClips = { ...s.clips, [newId]: duplicate };
318	      const tracks = s.tracks.map((t) =>
319	        t.id === clip.trackId ? { ...t, clipIds: [...t.clipIds, newId] } : t,
320	      );
321	      return { clips: nextClips, tracks };
322	    });
323	
324	    return newId;
325	  },
326	
327	  // Selection
328	  setSelectedTrackIds: (ids: readonly string[]) => {
329	    set({ selectedTrackIds: ids });
330	  },
331	  setSelectedClipIds: (ids: readonly string[]) => {
332	    set({ selectedClipIds: ids });
333	  },
334	
335	  // Query
336	  queryClipsAtTime: (time: number): readonly ClipModel[] => {
337	    const state = get();
338	    const hasSolo = state.tracks.some((t) => t.solo);
339	    const activeTracks = new Set(
340	      state.tracks
341	        .filter((t) => {
342	          if (t.muted) return false;
343	          if (hasSolo && !t.solo && !t.soloIsolate) return false;
344	          return true;
345	        })
346	        .map((t) => t.id),
347	    );
348	
349	    return Object.values(state.clips).filter((clip) => {
350	      if (!activeTracks.has(clip.trackId)) return false;
351	      const clipEnd = clip.startTime + clip.duration;
352	      return time >= clip.startTime && time < clipEnd;
353	    });
354	  },
355	}));
