34	export class RemoveTrackCommand implements UndoCommand {
35	  readonly type = "remove-track";
36	
37	  private savedTrack: TrackModel | undefined;
38	  private savedClips: readonly ClipModel[] = [];
39	  private savedIndex = -1;
40	
41	  constructor(private readonly trackId: string) {}
42	
43	  execute(): void {
44	    const state = getStore();
45	    this.savedIndex = state.tracks.findIndex((t) => t.id === this.trackId);
46	    this.savedTrack = state.tracks.find((t) => t.id === this.trackId);
47	
48	    if (this.savedTrack) {
49	      this.savedClips = this.savedTrack.clipIds
50	        .map((cid) => state.clips[cid])
51	        .filter((c): c is ClipModel => c !== undefined);
52	    }
53	
54	    state.removeTrack(this.trackId);
55	  }
56	
57	  undo(): void {
58	    if (this.savedTrack === undefined) return;
59	
60	    // Re-add the track at its original position (without clips first)
61	    const trackWithoutClips: TrackModel = { ...this.savedTrack, clipIds: [] };
62	    getStore().addTrack(trackWithoutClips, this.savedIndex);
63	
64	    // Re-add all clips (addClip also wires up clipIds)
65	    for (const clip of this.savedClips) {
66	      getStore().addClip(clip);
67	    }
68	  }
69	
70	  serialize(): Record<string, unknown> {
71	    return { trackId: this.trackId };
72	  }
73	}
