1	import type { UndoCommand } from "./undo-command";
2	
3	const DEFAULT_MAX_SIZE = 200;
4	
5	export type UndoManager = {
6	  push(command: UndoCommand): void;
7	  undo(): boolean;
8	  redo(): boolean;
9	  clear(): void;
10	  readonly canUndo: boolean;
11	  readonly canRedo: boolean;
12	  readonly undoStack: readonly UndoCommand[];
13	  readonly redoStack: readonly UndoCommand[];
14	  readonly size: number;
15	};
16	
17	export function createUndoManager(
18	  maxSize: number = DEFAULT_MAX_SIZE,
19	): UndoManager {
20	  const undoStack: UndoCommand[] = [];
21	  const redoStack: UndoCommand[] = [];
22	
23	  return {
24	    push(command: UndoCommand): void {
25	      undoStack.push(command);
26	      redoStack.length = 0;
27	      while (undoStack.length > maxSize) {
28	        undoStack.shift();
29	      }
30	    },
31	
32	    undo(): boolean {
33	      const cmd = undoStack.pop();
34	      if (cmd === undefined) return false;
35	      cmd.undo();
36	      redoStack.push(cmd);
37	      return true;
38	    },
39	
40	    redo(): boolean {
41	      const cmd = redoStack.pop();
42	      if (cmd === undefined) return false;
43	      cmd.execute();
44	      undoStack.push(cmd);
45	      return true;
46	    },
47	
48	    clear(): void {
49	      undoStack.length = 0;
50	      redoStack.length = 0;
51	    },
52	
53	    get canUndo(): boolean {
54	      return undoStack.length > 0;
55	    },
56	
57	    get canRedo(): boolean {
58	      return redoStack.length > 0;
59	    },
60	
61	    get undoStack(): readonly UndoCommand[] {
62	      return undoStack;
63	    },
64	
65	    get redoStack(): readonly UndoCommand[] {
66	      return redoStack;
67	    },
68	
69	    get size(): number {
70	      return undoStack.length;
71	    },
72	  };
73	}
