1	/**
2	 * Pointer interaction handlers for the arrangement canvas.
3	 * Manages drag operations for clip move, trim, split, and selection.
4	 * Pushes undo commands on drag completion.
5	 */
6	import { useCallback, useRef, useState } from "react";
7	import { useDawStore } from "@state/store";
8	import type { ClipModel } from "@state/track/types";
9	import type { UndoCommand } from "@state/undo";
10	import { sharedUndoManager } from "@state/undo";
11	import { SplitClipCommand } from "@state/track/track-commands";
12	import type { ArrangementViewState } from "./arrangement-renderer";
13	import { hitTest, xToSeconds, snapToGrid, type GridSnap } from "./hit-test";
14	import { RULER_HEIGHT } from "./constants";
15	
16	type DragState =
17	  | { kind: "idle" }
18	  | {
19	      kind: "move-clip";
20	      clipId: string;
21	      originTrackId: string;
22	      startX: number;
23	      startTime: number;
24	      beforeClip: ClipModel;
25	    }
26	  | {
27	      kind: "trim-left";
28	      clipId: string;
29	      startX: number;
30	      originalStart: number;
31	      originalSourceOffset: number;
32	      originalDuration: number;
33	      beforeClip: ClipModel;
34	    }
35	  | {
36	      kind: "trim-right";
37	      clipId: string;
38	      startX: number;
39	      originalEnd: number;
40	      originalStart: number;
41	      beforeClip: ClipModel;
42	    }
43	  | {
44	      kind: "rubber-band";
45	      startX: number;
46	      startY: number;
47	    };
48	
49	export type ArrangementInteractions = {
50	  onPointerDown: (e: React.PointerEvent<HTMLCanvasElement>) => void;
51	  onPointerMove: (e: React.PointerEvent<HTMLCanvasElement>) => void;
52	  onPointerUp: (e: React.PointerEvent<HTMLCanvasElement>) => void;
53	  onDoubleClick: (e: React.MouseEvent<HTMLCanvasElement>) => void;
54	  cursor: string;
55	};
56	
57	export function useArrangementInteractions(
58	  view: ArrangementViewState,
59	  gridSnap: GridSnap,
60	): ArrangementInteractions {
61	  const dragRef = useRef<DragState>({ kind: "idle" });
62	  const [cursor, setCursor] = useState("default");
63	
64	  const getCanvasPos = useCallback(
65	    (e: React.MouseEvent<HTMLCanvasElement>): { x: number; y: number } => {
66	      const rect = e.currentTarget.getBoundingClientRect();
67	      return { x: e.clientX - rect.left, y: e.clientY - rect.top };
68	    },
69	    [],
70	  );
71	
72	  const onPointerDown = useCallback(
73	    (e: React.PointerEvent<HTMLCanvasElement>): void => {
74	      const { x, y } = getCanvasPos(e);
75	      const state = useDawStore.getState();
76	      const hit = hitTest(x, y, view, state.tracks, state.clips);
77	
78	      switch (hit.kind) {
79	        case "clip-body": {
80	          const clip = state.clips[hit.clipId];
81	          if (clip === undefined) break;
82	
83	          if (e.shiftKey) {
84	            const current = [...state.selectedClipIds];
85	            const idx = current.indexOf(hit.clipId);
86	            if (idx >= 0) {
87	              current.splice(idx, 1);
88	            } else {
89	              current.push(hit.clipId);
90	            }
91	            state.setSelectedClipIds(current);
92	          } else if (!state.selectedClipIds.includes(hit.clipId)) {
93	            state.setSelectedClipIds([hit.clipId]);
94	          }
95	
96	          e.currentTarget.setPointerCapture(e.pointerId);
97	          dragRef.current = {
98	            kind: "move-clip",
99	            clipId: hit.clipId,
100	            originTrackId: clip.trackId,
101	            startX: x,
102	            startTime: clip.startTime,
103	            beforeClip: { ...clip },
104	          };
105	          break;
106	        }
107	        case "clip-left-edge": {
108	          const clip = state.clips[hit.clipId];
109	          if (clip === undefined) break;
110	          state.setSelectedClipIds([hit.clipId]);
111	          e.currentTarget.setPointerCapture(e.pointerId);
112	          dragRef.current = {
113	            kind: "trim-left",
114	            clipId: hit.clipId,
115	            startX: x,
116	            originalStart: clip.startTime,
117	            originalSourceOffset: clip.sourceOffset,
118	            originalDuration: clip.duration,
119	            beforeClip: { ...clip },
120	          };
121	          break;
122	        }
123	        case "clip-right-edge": {
124	          const clip = state.clips[hit.clipId];
125	          if (clip === undefined) break;
126	          state.setSelectedClipIds([hit.clipId]);
127	          e.currentTarget.setPointerCapture(e.pointerId);
128	          dragRef.current = {
129	            kind: "trim-right",
130	            clipId: hit.clipId,
131	            startX: x,
132	            originalEnd: clip.startTime + clip.duration,
133	            originalStart: clip.startTime,
134	            beforeClip: { ...clip },
135	          };
136	          break;
137	        }
138	        case "ruler": {
139	          state.setCursor(Math.max(0, hit.timeSeconds));
140	          break;
141	        }
142	        case "empty-lane": {
143	          if (!e.shiftKey) {
144	            state.setSelectedClipIds([]);
145	          }
146	          e.currentTarget.setPointerCapture(e.pointerId);
147	          dragRef.current = { kind: "rubber-band", startX: x, startY: y };
148	          break;
149	        }
150	        case "track-header": {

150	        case "track-header": {
151	          if (e.shiftKey) {
152	            const current = [...state.selectedTrackIds];
153	            const idx = current.indexOf(hit.trackId);
154	            if (idx >= 0) {
155	              current.splice(idx, 1);
156	            } else {
157	              current.push(hit.trackId);
158	            }
159	            state.setSelectedTrackIds(current);
160	          } else {
161	            state.setSelectedTrackIds([hit.trackId]);
162	          }
163	          break;
164	        }
165	        case "none":
166	          break;
167	      }
168	    },
169	    [view, getCanvasPos],
170	  );
171	
172	  const onPointerMove = useCallback(
173	    (e: React.PointerEvent<HTMLCanvasElement>): void => {
174	      const { x, y } = getCanvasPos(e);
175	      const drag = dragRef.current;
176	      const state = useDawStore.getState();
177	
178	      if (drag.kind === "idle") {
179	        const hit = hitTest(x, y, view, state.tracks, state.clips);
180	        switch (hit.kind) {
181	          case "clip-left-edge":
182	          case "clip-right-edge":
183	            setCursor("ew-resize");
184	            break;
185	          case "clip-body":
186	            setCursor("grab");
187	            break;
188	          default:
189	            setCursor("default");
190	            break;
191	        }
192	        return;
193	      }
194	
195	      switch (drag.kind) {
196	        case "move-clip": {
197	          setCursor("grabbing");
198	          const deltaPx = x - drag.startX;
199	          const deltaSec = deltaPx / view.pixelsPerSecond;
200	          const newTime = snapToGrid(
201	            Math.max(0, drag.startTime + deltaSec),
202	            state.bpm,
203	            gridSnap,
204	          );
205	
206	          const trackIndex = Math.floor(
207	            (y - RULER_HEIGHT + view.scrollY) / view.trackHeight,
208	          );
209	          const targetTrack = state.tracks[trackIndex];
210	          const targetTrackId =
211	            targetTrack !== undefined ? targetTrack.id : drag.originTrackId;
212	
213	          state.moveClip(drag.clipId, newTime, targetTrackId);
214	          break;
215	        }
216	        case "trim-left": {
217	          setCursor("ew-resize");
218	          const deltaPx = x - drag.startX;
219	          const deltaSec = deltaPx / view.pixelsPerSecond;
220	          const newStart = snapToGrid(
221	            Math.max(0, drag.originalStart + deltaSec),
222	            state.bpm,
223	            gridSnap,
224	          );
225	          const maxStart = drag.originalStart + drag.originalDuration - 0.01;
226	          const clampedStart = Math.min(newStart, maxStart);
227	          state.trimClip(drag.clipId, clampedStart, undefined);
228	          break;
229	        }
230	        case "trim-right": {
231	          setCursor("ew-resize");
232	          const deltaPx = x - drag.startX;
233	          const deltaSec = deltaPx / view.pixelsPerSecond;
234	          const rawEnd = snapToGrid(
235	            Math.max(0.01, drag.originalEnd + deltaSec),
236	            state.bpm,
237	            gridSnap,
238	          );
239	          // Clamp so the end never crosses the clip's start
240	          const newEnd = Math.max(drag.originalStart + 0.01, rawEnd);
241	          state.trimClip(drag.clipId, undefined, newEnd);
242	          break;
243	        }
244	        case "rubber-band": {
245	          const left = Math.min(drag.startX, x);
246	          const right = Math.max(drag.startX, x);
247	          const top = Math.min(drag.startY, y);
248	          const bottom = Math.max(drag.startY, y);
249	
250	          const selected: string[] = [];
251	          for (let ti = 0; ti < state.tracks.length; ti++) {
252	            const track = state.tracks[ti];
253	            if (track === undefined) continue;
