46	
47	  // Track actions
48	  addTrack: (track: TrackModel, index?: number) => void;
49	  removeTrack: (id: string) => void;
50	  updateTrack: (id: string, patch: Partial<Omit<TrackModel, "id">>) => void;
51	  reorderTrack: (id: string, toIndex: number) => void;
52	
53	  // Clip actions
54	  addClip: (clip: ClipModel) => void;
55	  removeClip: (id: string) => void;
56	  moveClip: (id: string, startTime: number, toTrackId?: string) => void;
57	  splitClip: (
58	    id: string,
59	    atTime: number,
60	    providedId?: string,
61	  ) => string | undefined;
62	  trimClip: (id: string, newStart?: number, newEnd?: number) => void;
63	  duplicateClip: (id: string, providedId?: string) => string | undefined;
64	
65	  // Selection actions
66	  setSelectedTrackIds: (ids: readonly string[]) => void;
67	  setSelectedClipIds: (ids: readonly string[]) => void;
68	
69	  // Query
70	  queryClipsAtTime: (time: number) => readonly ClipModel[];
71	};
72	
73	function nextClipId(): string {
74	  return "clip-" + crypto.randomUUID();
75	}
