79	export class UpdateTrackCommand implements UndoCommand {
80	  readonly type = "update-track";
81	
82	  private oldPatch: Partial<Omit<TrackModel, "id">> | undefined;
83	
84	  constructor(
85	    private readonly trackId: string,
86	    private readonly newPatch: Partial<Omit<TrackModel, "id">>,
87	  ) {}
88	
89	  execute(): void {
90	    const track = getStore().tracks.find((t) => t.id === this.trackId);
91	    if (track === undefined) return;
92	
93	    // Capture old values for only the keys being changed
94	    const old: Record<string, unknown> = {};
95	    for (const key of Object.keys(this.newPatch)) {
96	      old[key] = track[key as keyof TrackModel];
97	    }
98	    this.oldPatch = old as Partial<Omit<TrackModel, "id">>;
99	
100	    getStore().updateTrack(this.trackId, this.newPatch);
101	  }
102	
103	  undo(): void {
104	    if (this.oldPatch === undefined) return;
105	    getStore().updateTrack(this.trackId, this.oldPatch);
106	  }
107	
108	  serialize(): Record<string, unknown> {
109	    return {
110	      trackId: this.trackId,
111	      newPatch: this.newPatch,
112	      oldPatch: this.oldPatch,
113	    };
114	  }
