239	export class SplitClipCommand implements UndoCommand {
240	  readonly type = "split-clip";
241	
242	  private originalClip: ClipModel | undefined;
243	  private generatedRightId: string | undefined;
244	
245	  constructor(
246	    private readonly clipId: string,
247	    private readonly atTime: number,
248	  ) {}
249	
250	  rightClipId(): string | undefined {
251	    return this.generatedRightId;
252	  }
253	
254	  execute(): void {
255	    // Capture full original clip before split
256	    this.originalClip = getStore().clips[this.clipId];
257	    // Pass stored ID on redo to keep clip references deterministic
258	    this.generatedRightId = getStore().splitClip(
259	      this.clipId,
260	      this.atTime,
261	      this.generatedRightId,
262	    );
263	  }
264	
265	  undo(): void {
266	    if (this.originalClip === undefined) return;
267	
268	    // Remove the right clip created by split
269	    if (this.generatedRightId !== undefined) {
270	      getStore().removeClip(this.generatedRightId);
271	    }
272	
273	    // Restore original clip state (splitClip mutated the left clip in-place)
274	    useDawStore.setState((state) => ({
275	      clips: { ...state.clips, [this.clipId]: this.originalClip as ClipModel },
276	    }));
277	  }
278	
279	  serialize(): Record<string, unknown> {
280	    return {
281	      clipId: this.clipId,
282	      atTime: this.atTime,
283	      rightClipId: this.generatedRightId,
284	      originalClip: this.originalClip,
285	    };
286	  }
287	}
