      if (note) { this.oldStartTime = note.startTime; this.oldPitch = note.pitch; }
    }
    getStore().moveNoteEvent(this.clipId, this.noteId, this.newStartTime, this.newPitch);
  }
  undo(): void {
    getStore().moveNoteEvent(this.clipId, this.noteId, this.oldStartTime, this.oldPitch);
  }
  serialize(): Record<string, unknown> {
    return { clipId: this.clipId, noteId: this.noteId, newStartTime: this.newStartTime, newPitch: this.newPitch, oldStartTime: this.oldStartTime, oldPitch: this.oldPitch };
  }
}

export class ResizeNoteCommand implements UndoCommand {
  readonly type = "resize-note";
  private oldDuration = 0;
  constructor(
    private readonly clipId: string,
    private readonly noteId: string,
    private readonly newDuration: number,
  ) {}
  execute(): void {
    const clip = getStore().clips[this.clipId];
    if (clip && isMidiClip(clip)) {
      const note = clip.noteEvents.find((n) => n.id === this.noteId);
      if (note) { this.oldDuration = note.duration; }
    }
    getStore().resizeNoteEvent(this.clipId, this.noteId, this.newDuration);
  }
  undo(): void {
    getStore().resizeNoteEvent(this.clipId, this.noteId, this.oldDuration);
  }
  serialize(): Record<string, unknown> {
    return { clipId: this.clipId, noteId: this.noteId, newDuration: this.newDuration, oldDuration: this.oldDuration };
  }
}

export class BatchNoteCommand implements UndoCommand {
  readonly type = "batch-note";
  constructor(private readonly commands: UndoCommand[]) {}
  execute(): void { for (const cmd of this.commands) cmd.execute(); }
  undo(): void { for (let i = this.commands.length - 1; i >= 0; i--) this.commands[i]!.undo(); }
  serialize(): Record<string, unknown> {
    return { commands: this.commands.map((c) => ({ type: c.type, ...c.serialize() })) };
  }
}
