### 4. Update `src/state/track/track-schema.ts`

Add Zod schemas for MIDI types. The current file uses `zod/v4`:

```typescript
import { z } from "zod/v4";

export const noteEventSchema = z.object({
  id: z.string(),
  pitch: z.number().int().min(0).max(127),
  velocity: z.number().int().min(0).max(127),
  startTime: z.number().min(0),
  duration: z.number().gt(0),
});

export const audioClipSchema = z.object({
  type: z.literal("audio"),
  id: z.string(),
  trackId: z.string(),
  sourceId: z.string(),
  startTime: z.number().min(0),
  sourceOffset: z.number().min(0),
  duration: z.number().min(0),
  gain: z.number().min(0).max(2),
  fadeIn: z.number().min(0),
  fadeOut: z.number().min(0),
  name: z.string(),
});

export const midiClipSchema = z.object({
  type: z.literal("midi"),
  id: z.string(),
  trackId: z.string(),
  startTime: z.number().min(0),
  duration: z.number().min(0),
  noteEvents: z.array(noteEventSchema),
  name: z.string(),
});

// Keep clipSchema as discriminated union
export const clipSchema = z.discriminatedUnion("type", [audioClipSchema, midiClipSchema]);
```

IMPORTANT: The existing `clipSchema` is used in the session schema. By replacing it with a discriminated union, the session schema will automatically accept both types. This is backward compatible because existing audio clips can be migrated by adding `type: "audio"` during deserialization.

