1	import { describe, it, expect, beforeEach } from "vitest";
2	import { useDawStore } from "@state/store";
3	import type { TrackModel, MIDINoteEvent, MidiClipModel } from "./types";
4	import {
5	  AddNoteCommand,
6	  RemoveNoteCommand,
7	  MoveNoteCommand,
8	  ResizeNoteCommand,
9	  BatchNoteCommand,
10	} from "./midi-commands";
11	
12	function makeTrack(overrides: Partial<TrackModel> = {}): TrackModel {
13	  return {
14	    id: "track-1",
15	    name: "Track 1",
16	    type: "instrument",
17	    color: "#ff2d6f",
18	    muted: false,
19	    solo: false,
20	    armed: false,
21	    soloIsolate: false,
22	    volume: 1,
23	    pan: 0,
24	    clipIds: [],
25	    ...overrides,
26	  };
27	}
28	
29	function makeNoteEvent(
30	  overrides: Partial<MIDINoteEvent> = {},
31	): MIDINoteEvent {
32	  return {
33	    id: "note-1",
34	    pitch: 60,
35	    velocity: 100,
36	    startTime: 0,
37	    duration: 0.5,
38	    ...overrides,
39	  };
40	}
41	
42	function makeMidiClip(
43	  overrides: Partial<MidiClipModel> = {},
44	): MidiClipModel {
45	  return {
46	    id: "midi-clip-1",
47	    trackId: "track-1",
48	    type: "midi",
49	    startTime: 0,
50	    duration: 4,
51	    noteEvents: [],
52	    name: "MIDI Clip 1",
53	    ...overrides,
54	  };
55	}
56	
57	function getStore(): ReturnType<typeof useDawStore.getState> {
58	  return useDawStore.getState();
59	}
60	
61	function getClipNotes(clipId: string): readonly MIDINoteEvent[] {
62	  const clip = getStore().clips[clipId] as MidiClipModel | undefined;
63	  expect(clip).toBeDefined();
64	  return clip!.noteEvents;
65	}
66	
67	describe("MIDI note commands", () => {
68	  beforeEach(() => {
69	    useDawStore.setState({
70	      tracks: [],
71	      clips: {},
72	      selectedTrackIds: [],
73	      selectedClipIds: [],
74	      selectedNoteIds: [],
75	    });
76	    getStore().addTrack(makeTrack({ id: "t1" }));
77	    getStore().addMidiClip(makeMidiClip({ id: "mc1", trackId: "t1" }));
78	  });
79	
80	  describe("AddNoteCommand", () => {
81	    it("execute adds a note to the clip", () => {
82	      const note = makeNoteEvent({ id: "n1", pitch: 64 });
83	      const cmd = new AddNoteCommand("mc1", note);
84	      cmd.execute();
85	
86	      const notes = getClipNotes("mc1");
87	      expect(notes).toHaveLength(1);
88	      expect(notes[0]?.pitch).toBe(64);
89	    });
90	
91	    it("undo removes the added note", () => {
92	      const note = makeNoteEvent({ id: "n1" });
93	      const cmd = new AddNoteCommand("mc1", note);
94	      cmd.execute();
95	      cmd.undo();
96	
97	      expect(getClipNotes("mc1")).toHaveLength(0);
98	    });
99	
100	    it("has type add-note", () => {
101	      const cmd = new AddNoteCommand("mc1", makeNoteEvent());
102	      expect(cmd.type).toBe("add-note");
103	    });
104	
105	    it("serializes clipId and note", () => {
106	      const note = makeNoteEvent({ id: "n1" });
107	      const cmd = new AddNoteCommand("mc1", note);
108	      const data = cmd.serialize();
109	      expect(data["clipId"]).toBe("mc1");
110	      expect(data["note"]).toEqual(note);
111	    });
112	  });
113	
114	  describe("RemoveNoteCommand", () => {
115	    it("execute removes a note from the clip", () => {
116	      getStore().addNoteEvent("mc1", makeNoteEvent({ id: "n1" }));
117	      getStore().addNoteEvent("mc1", makeNoteEvent({ id: "n2" }));
118	
119	      const cmd = new RemoveNoteCommand("mc1", "n1");
120	      cmd.execute();
121	
122	      const notes = getClipNotes("mc1");
123	      expect(notes).toHaveLength(1);
124	      expect(notes[0]?.id).toBe("n2");
125	    });
126	
127	    it("undo restores the removed note", () => {
128	      const note = makeNoteEvent({ id: "n1", pitch: 72 });
129	      getStore().addNoteEvent("mc1", note);
130	
131	      const cmd = new RemoveNoteCommand("mc1", "n1");
132	      cmd.execute();
133	      cmd.undo();
134	
135	      const notes = getClipNotes("mc1");
136	      expect(notes).toHaveLength(1);
137	      expect(notes[0]?.pitch).toBe(72);
138	    });
139	
140	    it("has type remove-note", () => {
141	      getStore().addNoteEvent("mc1", makeNoteEvent({ id: "n1" }));
142	      const cmd = new RemoveNoteCommand("mc1", "n1");
143	      expect(cmd.type).toBe("remove-note");
144	    });
145	
146	    it("serializes clipId and noteId", () => {
147	      getStore().addNoteEvent("mc1", makeNoteEvent({ id: "n1" }));
148	      const cmd = new RemoveNoteCommand("mc1", "n1");
149	      const data = cmd.serialize();
150	      expect(data["clipId"]).toBe("mc1");
151	      expect(data["noteId"]).toBe("n1");
152	    });
153	  });
154	
155	  describe("MoveNoteCommand", () => {
156	    it("execute moves a note to new startTime and pitch", () => {
157	      getStore().addNoteEvent(
158	        "mc1",
159	        makeNoteEvent({ id: "n1", startTime: 0, pitch: 60 }),
160	      );
161	
162	      const cmd = new MoveNoteCommand("mc1", "n1", 2.0, 72);
163	      cmd.execute();
164	
165	      const note = getClipNotes("mc1").find((n) => n.id === "n1");
166	      expect(note?.startTime).toBe(2.0);
167	      expect(note?.pitch).toBe(72);
168	    });
169	
170	    it("undo restores original startTime and pitch", () => {
171	      getStore().addNoteEvent(
172	        "mc1",
173	        makeNoteEvent({ id: "n1", startTime: 1.0, pitch: 64 }),
174	      );
175	
176	      const cmd = new MoveNoteCommand("mc1", "n1", 3.0, 80);
177	      cmd.execute();
178	      cmd.undo();
179	
180	      const note = getClipNotes("mc1").find((n) => n.id === "n1");
181	      expect(note?.startTime).toBe(1.0);
182	      expect(note?.pitch).toBe(64);
183	    });
184	
185	    it("preserves velocity and duration after move", () => {
186	      getStore().addNoteEvent(
187	        "mc1",
188	        makeNoteEvent({ id: "n1", velocity: 90, duration: 0.75 }),
189	      );
190	
191	      const cmd = new MoveNoteCommand("mc1", "n1", 1.0, 67);
192	      cmd.execute();
193	
194	      const note = getClipNotes("mc1").find((n) => n.id === "n1");
195	      expect(note?.velocity).toBe(90);
196	      expect(note?.duration).toBe(0.75);
197	    });
198	
199	    it("has type move-note", () => {
200	      getStore().addNoteEvent("mc1", makeNoteEvent({ id: "n1" }));
201	      const cmd = new MoveNoteCommand("mc1", "n1", 1.0, 60);
202	      expect(cmd.type).toBe("move-note");
203	    });
204	
205	    it("serializes all fields", () => {
206	      getStore().addNoteEvent("mc1", makeNoteEvent({ id: "n1" }));
207	      const cmd = new MoveNoteCommand("mc1", "n1", 2.0, 72);
208	      const data = cmd.serialize();
209	      expect(data["clipId"]).toBe("mc1");
210	      expect(data["noteId"]).toBe("n1");
211	      expect(data["newStartTime"]).toBe(2.0);
212	      expect(data["newPitch"]).toBe(72);
213	    });
214	  });
215	
216	  describe("ResizeNoteCommand", () => {
217	    it("execute changes the note duration", () => {
218	      getStore().addNoteEvent(
219	        "mc1",
220	        makeNoteEvent({ id: "n1", duration: 0.5 }),
221	      );
222	
223	      const cmd = new ResizeNoteCommand("mc1", "n1", 2.0);
224	      cmd.execute();
225	
226	      const note = getClipNotes("mc1").find((n) => n.id === "n1");
227	      expect(note?.duration).toBe(2.0);
228	    });
229	
230	    it("undo restores original duration", () => {
231	      getStore().addNoteEvent(
232	        "mc1",
233	        makeNoteEvent({ id: "n1", duration: 0.5 }),
234	      );
235	
236	      const cmd = new ResizeNoteCommand("mc1", "n1", 2.0);
237	      cmd.execute();
238	      cmd.undo();
239	
240	      const note = getClipNotes("mc1").find((n) => n.id === "n1");
241	      expect(note?.duration).toBe(0.5);
242	    });
243	
244	    it("preserves pitch and startTime after resize", () => {
245	      getStore().addNoteEvent(
246	        "mc1",
247	        makeNoteEvent({ id: "n1", pitch: 60, startTime: 1.0 }),
248	      );
249	
250	      const cmd = new ResizeNoteCommand("mc1", "n1", 3.0);
251	      cmd.execute();
252	
253	      const note = getClipNotes("mc1").find((n) => n.id === "n1");
254	      expect(note?.pitch).toBe(60);
255	      expect(note?.startTime).toBe(1.0);
256	    });
257	
258	    it("has type resize-note", () => {
259	      getStore().addNoteEvent("mc1", makeNoteEvent({ id: "n1" }));
260	      const cmd = new ResizeNoteCommand("mc1", "n1", 1.0);
261	      expect(cmd.type).toBe("resize-note");
262	    });
263	
264	    it("serializes clipId, noteId, and newDuration", () => {
265	      getStore().addNoteEvent("mc1", makeNoteEvent({ id: "n1" }));
266	      const cmd = new ResizeNoteCommand("mc1", "n1", 1.5);
267	      const data = cmd.serialize();
