269	      expect(data["noteId"]).toBe("n1");
270	      expect(data["newDuration"]).toBe(1.5);
271	    });
272	  });
273	
274	  describe("BatchNoteCommand", () => {
275	    it("execute runs all sub-commands in order", () => {
276	      getStore().addNoteEvent(
277	        "mc1",
278	        makeNoteEvent({ id: "n1", startTime: 0, pitch: 60 }),
