/**
 * Core types for the track system.
 * Tracks contain clips; clips are non-destructive references to audio sources
 * or containers for MIDI note events.
 */

export type TrackType = "audio" | "instrument";

export type MIDINoteEvent = {
  readonly id: string;
  readonly pitch: number; // 0-127
  readonly velocity: number; // 0-127
  readonly startTime: number; // seconds, relative to clip start
  readonly duration: number; // seconds
};

export type AudioClipModel = {
  readonly type: "audio";
  readonly id: string;
  readonly trackId: string;
  readonly sourceId: string;
  readonly startTime: number; // seconds on timeline
  readonly sourceOffset: number; // seconds into source
  readonly duration: number; // seconds
  readonly gain: number; // 0..2
  readonly fadeIn: number; // seconds
  readonly fadeOut: number; // seconds
  readonly name: string;
};

export type MidiClipModel = {
  readonly type: "midi";
  readonly id: string;
  readonly trackId: string;
  readonly startTime: number; // seconds on timeline
  readonly duration: number; // seconds
  readonly noteEvents: readonly MIDINoteEvent[];
  readonly name: string;
};

export type ClipModel = AudioClipModel | MidiClipModel;

export function isAudioClip(clip: ClipModel): clip is AudioClipModel {
  return clip.type === "audio";
}

export function isMidiClip(clip: ClipModel): clip is MidiClipModel {
  return clip.type === "midi";
}

export type TrackModel = {
  readonly id: string;
  readonly name: string;
  readonly type: TrackType;
  readonly color: string;
  readonly muted: boolean;
  readonly solo: boolean;
  readonly armed: boolean;
  readonly soloIsolate: boolean;
  readonly volume: number; // 0..2
  readonly pan: number; // -1..1
  readonly clipIds: readonly string[];
};

import { z } from "zod/v4";

export const noteEventSchema = z.object({
  id: z.string(),
  pitch: z.number().int().min(0).max(127),
  velocity: z.number().int().min(0).max(127),
  startTime: z.number().min(0),
  duration: z.number().gt(0),
});

export const audioClipSchema = z.object({
  type: z.literal("audio"),
  id: z.string(),
  trackId: z.string(),
  sourceId: z.string(),
  startTime: z.number().min(0),
  sourceOffset: z.number().min(0),
  duration: z.number().min(0),
  gain: z.number().min(0).max(2),
  fadeIn: z.number().min(0),
  fadeOut: z.number().min(0),
  name: z.string(),
});

export const midiClipSchema = z.object({
  type: z.literal("midi"),
  id: z.string(),
  trackId: z.string(),
  startTime: z.number().min(0),
  duration: z.number().min(0),
  noteEvents: z.array(noteEventSchema),
  name: z.string(),
});

export const clipSchema = z.discriminatedUnion("type", [
  audioClipSchema,
  midiClipSchema,
]);

export type ClipSchema = z.infer<typeof clipSchema>;

export const trackSchema = z.object({
  id: z.string(),
  name: z.string(),
  type: z.enum(["audio", "instrument"]),
  color: z.string().regex(/^#[0-9a-fA-F]{6}$/),
  muted: z.boolean(),
  solo: z.boolean(),
  armed: z.boolean(),
  soloIsolate: z.boolean(),
  volume: z.number().min(0).max(2),
  pan: z.number().min(-1).max(1),
  clipIds: z.array(z.string()),
});

export type TrackSchema = z.infer<typeof trackSchema>;

import { create } from "zustand";
import type {
  TrackModel,
  ClipModel,
  MidiClipModel,
  MIDINoteEvent,
} from "./track/types";
import { isAudioClip, isMidiClip } from "./track/types";

export type TransportState = "stopped" | "playing" | "paused";

export type AudioEngineStatus =
  | "uninitialized"
  | "suspended"
  | "running"
  | "error";

export type DawStore = {
  // Transport
  transportState: TransportState;
  bpm: number;
  cursorSeconds: number;
  loopEnabled: boolean;
  loopStart: number;
  loopEnd: number;

  // Audio engine
  engineStatus: AudioEngineStatus;

  // Mixer
  masterVolume: number;

  // Tracks & clips
  tracks: readonly TrackModel[];
  clips: Record<string, ClipModel>;
  selectedTrackIds: readonly string[];
  selectedClipIds: readonly string[];
  selectedNoteIds: readonly string[];

  // Transport actions
  play: () => void;
  pause: () => void;
  stop: () => void;
  setBpm: (bpm: number) => void;
  setCursor: (seconds: number) => void;
  setLoop: (enabled: boolean, start?: number, end?: number) => void;

  // Engine actions
  setEngineStatus: (status: AudioEngineStatus) => void;

  // Mixer actions
  setMasterVolume: (volume: number) => void;

  // Track actions
  addTrack: (track: TrackModel, index?: number) => void;
  removeTrack: (id: string) => void;
  updateTrack: (id: string, patch: Partial<Omit<TrackModel, "id">>) => void;
  reorderTrack: (id: string, toIndex: number) => void;

  // Clip actions
  addClip: (clip: ClipModel) => void;
  removeClip: (id: string) => void;
  moveClip: (id: string, startTime: number, toTrackId?: string) => void;
  splitClip: (
    id: string,
    atTime: number,
    providedId?: string,
  ) => string | undefined;
  trimClip: (id: string, newStart?: number, newEnd?: number) => void;
  duplicateClip: (id: string, providedId?: string) => string | undefined;

  // MIDI clip actions
  addMidiClip: (clip: MidiClipModel) => void;
  removeMidiClip: (id: string) => void;
  addNoteEvent: (clipId: string, note: MIDINoteEvent) => void;
  removeNoteEvent: (clipId: string, noteId: string) => void;
  moveNoteEvent: (
    clipId: string,
    noteId: string,
    newStartTime: number,
    newPitch: number,
  ) => void;
  resizeNoteEvent: (
    clipId: string,
    noteId: string,
    newDuration: number,
  ) => void;
  updateNoteVelocity: (
    clipId: string,
    noteId: string,
    velocity: number,
  ) => void;

  // Selection actions
  setSelectedTrackIds: (ids: readonly string[]) => void;
  setSelectedClipIds: (ids: readonly string[]) => void;
  setSelectedNoteIds: (ids: readonly string[]) => void;

  // Query
  queryClipsAtTime: (time: number) => readonly ClipModel[];
};

function nextClipId(): string {
  return "clip-" + crypto.randomUUID();
}

export const useDawStore = create<DawStore>()((set, get) => ({
  // Transport defaults
  transportState: "stopped",
  bpm: 120,
  cursorSeconds: 0,
  loopEnabled: false,
  loopStart: 0,
  loopEnd: 0,

  // Engine defaults
  engineStatus: "uninitialized",

  // Mixer defaults
  masterVolume: 1,

  // Track & clip defaults
  tracks: [],
  clips: {},
  selectedTrackIds: [],
  selectedClipIds: [],
  selectedNoteIds: [],

  // Transport actions
  play: () => {
    set({ transportState: "playing" });
  },
  pause: () => {
    set({ transportState: "paused" });
  },
  stop: () => {
    set({ transportState: "stopped", cursorSeconds: 0 });
  },
  setBpm: (bpm: number) => {
    const clamped = Math.min(999, Math.max(20, bpm));
    if (!Number.isFinite(clamped)) return;
    set({ bpm: clamped });
  },
  setCursor: (seconds: number) => {
    set({ cursorSeconds: seconds });
  },
  setLoop: (enabled: boolean, start?: number, end?: number) => {
    set((state) => ({
      loopEnabled: enabled,
      loopStart: start ?? state.loopStart,
      loopEnd: end ?? state.loopEnd,
    }));
  },

  // Engine actions
  setEngineStatus: (status: AudioEngineStatus) => {
    set({ engineStatus: status });
  },

  // Mixer actions
  setMasterVolume: (volume: number) => {
    const clamped = Math.min(2, Math.max(0, volume));
    set({ masterVolume: clamped });
  },

  // Track actions
  addTrack: (track: TrackModel, index?: number) => {
    set((state) => {
      const next = [...state.tracks];
      if (index !== undefined) {
        next.splice(index, 0, track);
      } else {
        next.push(track);
      }
      return { tracks: next };
    });
  },

  removeTrack: (id: string) => {
    set((state) => {
      const track = state.tracks.find((t) => t.id === id);
      if (!track) return state;
      const removeSet = new Set(track.clipIds);
      const nextClips = Object.fromEntries(
        Object.entries(state.clips).filter(([k]) => !removeSet.has(k)),
      );
      return {
        tracks: state.tracks.filter((t) => t.id !== id),
        clips: nextClips,
      };
    });
  },

  updateTrack: (id: string, patch: Partial<Omit<TrackModel, "id">>) => {
    set((state) => ({
      tracks: state.tracks.map((t) => (t.id === id ? { ...t, ...patch } : t)),
    }));
  },

  reorderTrack: (id: string, toIndex: number) => {
    set((state) => {
      const fromIndex = state.tracks.findIndex((t) => t.id === id);
      if (fromIndex === -1) return state;
      const next = [...state.tracks];
      const moved = next.splice(fromIndex, 1)[0];
      if (moved === undefined) return state;
      next.splice(toIndex, 0, moved);
      return { tracks: next };
    });
  },

  // Clip actions
  addClip: (clip: ClipModel) => {
    set((state) => {
      const nextClips = { ...state.clips, [clip.id]: clip };
      const tracks = state.tracks.map((t) =>
        t.id === clip.trackId ? { ...t, clipIds: [...t.clipIds, clip.id] } : t,
      );
      return { clips: nextClips, tracks };
    });
  },

  removeClip: (id: string) => {
    set((state) => {
      const clip = state.clips[id];
      if (!clip) return state;
      const nextClips = Object.fromEntries(
        Object.entries(state.clips).filter(([k]) => k !== id),
      );
      const tracks = state.tracks.map((t) =>
        t.id === clip.trackId
          ? { ...t, clipIds: t.clipIds.filter((cid) => cid !== id) }
          : t,
      );
      return { clips: nextClips, tracks };
    });
  },

  moveClip: (id: string, startTime: number, toTrackId?: string) => {
    set((state) => {
      const clip = state.clips[id];
      if (!clip) return state;
      const updatedClip = {
        ...clip,
        startTime,
        trackId: toTrackId ?? clip.trackId,
      };
      const nextClips = { ...state.clips, [id]: updatedClip };

      let tracks = state.tracks;
      if (toTrackId !== undefined && toTrackId !== clip.trackId) {
        tracks = tracks.map((t) => {
          if (t.id === clip.trackId) {
            return { ...t, clipIds: t.clipIds.filter((cid) => cid !== id) };
          }
          if (t.id === toTrackId) {
            return { ...t, clipIds: [...t.clipIds, id] };
          }
          return t;
        });
      }
      return { clips: nextClips, tracks };
    });
  },

  splitClip: (
    id: string,
    atTime: number,
    providedId?: string,
  ): string | undefined => {
    const state = get();
    const clip = state.clips[id];
    if (!clip) return undefined;
    if (!isAudioClip(clip)) return undefined;

    const clipEnd = clip.startTime + clip.duration;
    if (atTime <= clip.startTime || atTime >= clipEnd) return undefined;

    const leftDuration = atTime - clip.startTime;
    const rightDuration = clip.duration - leftDuration;
    const rightSourceOffset = clip.sourceOffset + leftDuration;

    const newId = providedId ?? nextClipId();

    const leftClip: ClipModel = { ...clip, duration: leftDuration };
    const rightClip: ClipModel = {
      ...clip,
      id: newId,
      startTime: atTime,
      sourceOffset: rightSourceOffset,
      duration: rightDuration,
    };

    set((s) => {
      const nextClips = { ...s.clips, [id]: leftClip, [newId]: rightClip };
      const tracks = s.tracks.map((t) =>
        t.id === clip.trackId ? { ...t, clipIds: [...t.clipIds, newId] } : t,
      );
      return { clips: nextClips, tracks };
    });

    return newId;
  },

  trimClip: (id: string, newStart?: number, newEnd?: number) => {
    set((state) => {
      const clip = state.clips[id];
      if (!clip) return state;
      if (!isAudioClip(clip)) return state;

      let { startTime, sourceOffset, duration } = clip;
      const clipEnd = startTime + duration;

      if (newStart !== undefined) {
        const delta = newStart - startTime;
        startTime = newStart;
        sourceOffset = sourceOffset + delta;
        duration = clipEnd - newStart;
      }

      if (newEnd !== undefined) {
        duration = newEnd - startTime;
      }

      // Guard against invalid state
      if (duration <= 0 || sourceOffset < 0) return state;

      return {
        clips: {
          ...state.clips,
          [id]: { ...clip, startTime, sourceOffset, duration },
        },
      };
    });
  },

  duplicateClip: (id: string, providedId?: string): string | undefined => {
    const state = get();
    const clip = state.clips[id];
    if (!clip) return undefined;

    const newId = providedId ?? nextClipId();
    const duplicate: ClipModel = {
      ...clip,
      id: newId,
      startTime: clip.startTime + clip.duration,
    };

    set((s) => {
      const nextClips = { ...s.clips, [newId]: duplicate };
      const tracks = s.tracks.map((t) =>
        t.id === clip.trackId ? { ...t, clipIds: [...t.clipIds, newId] } : t,
      );
      return { clips: nextClips, tracks };
    });

    return newId;
  },

  // MIDI clip actions
  addMidiClip: (clip: MidiClipModel) => {
    set((state) => {
      const nextClips = { ...state.clips, [clip.id]: clip };
      const tracks = state.tracks.map((t) =>
        t.id === clip.trackId ? { ...t, clipIds: [...t.clipIds, clip.id] } : t,
      );
      return { clips: nextClips, tracks };
    });
  },

  removeMidiClip: (id: string) => {
    set((state) => {
      const clip = state.clips[id];
      if (!clip) return state;
      const nextClips = Object.fromEntries(
        Object.entries(state.clips).filter(([k]) => k !== id),
      );
      const tracks = state.tracks.map((t) =>
        t.id === clip.trackId
          ? { ...t, clipIds: t.clipIds.filter((cid) => cid !== id) }
          : t,
      );
      return { clips: nextClips, tracks };
    });
  },

  addNoteEvent: (clipId: string, note: MIDINoteEvent) => {
    set((state) => {
      const clip = state.clips[clipId];
      if (!clip || !isMidiClip(clip)) return state;
      const updated: MidiClipModel = {
        ...clip,
        noteEvents: [...clip.noteEvents, note],
      };
      return { clips: { ...state.clips, [clipId]: updated } };
    });
  },

  removeNoteEvent: (clipId: string, noteId: string) => {
    set((state) => {
      const clip = state.clips[clipId];
      if (!clip || !isMidiClip(clip)) return state;
      const updated: MidiClipModel = {
        ...clip,
        noteEvents: clip.noteEvents.filter((n) => n.id !== noteId),
      };
      return { clips: { ...state.clips, [clipId]: updated } };
    });
  },

  moveNoteEvent: (
    clipId: string,
    noteId: string,
    newStartTime: number,
    newPitch: number,
  ) => {
    set((state) => {
      const clip = state.clips[clipId];
      if (!clip || !isMidiClip(clip)) return state;
      const updated: MidiClipModel = {
        ...clip,
        noteEvents: clip.noteEvents.map((n) =>
          n.id === noteId
            ? { ...n, startTime: newStartTime, pitch: newPitch }
            : n,
        ),
      };
      return { clips: { ...state.clips, [clipId]: updated } };
    });
  },

  resizeNoteEvent: (clipId: string, noteId: string, newDuration: number) => {
    set((state) => {
      const clip = state.clips[clipId];
      if (!clip || !isMidiClip(clip)) return state;
      const updated: MidiClipModel = {
        ...clip,
        noteEvents: clip.noteEvents.map((n) =>
          n.id === noteId ? { ...n, duration: newDuration } : n,
        ),
      };
      return { clips: { ...state.clips, [clipId]: updated } };
    });
  },

  updateNoteVelocity: (clipId: string, noteId: string, velocity: number) => {
    set((state) => {
      const clip = state.clips[clipId];
      if (!clip || !isMidiClip(clip)) return state;
      const updated: MidiClipModel = {
        ...clip,
        noteEvents: clip.noteEvents.map((n) =>
          n.id === noteId ? { ...n, velocity } : n,
        ),
      };
      return { clips: { ...state.clips, [clipId]: updated } };
    });
  },

  // Selection
  setSelectedTrackIds: (ids: readonly string[]) => {
    set({ selectedTrackIds: ids });
  },
  setSelectedClipIds: (ids: readonly string[]) => {
    set({ selectedClipIds: ids });
  },
  setSelectedNoteIds: (ids: readonly string[]) => {
    set({ selectedNoteIds: ids });
  },

  // Query
  queryClipsAtTime: (time: number): readonly ClipModel[] => {
    const state = get();
    const hasSolo = state.tracks.some((t) => t.solo);
    const activeTracks = new Set(
      state.tracks
        .filter((t) => {
          if (t.muted) return false;
          if (hasSolo && !t.solo && !t.soloIsolate) return false;
          return true;
        })
        .map((t) => t.id),
    );

    return Object.values(state.clips).filter((clip) => {
      if (!activeTracks.has(clip.trackId)) return false;
      const clipEnd = clip.startTime + clip.duration;
      return time >= clip.startTime && time < clipEnd;
    });
  },
}));

import type { UndoCommand } from "@state/undo/undo-command";
import { useDawStore } from "@state/store";
import type { MIDINoteEvent } from "@state/track/types";
import { isMidiClip } from "@state/track/types";

function getStore(): ReturnType<typeof useDawStore.getState> {
  return useDawStore.getState();
}

export class AddNoteCommand implements UndoCommand {
  readonly type = "add-note";

  constructor(
    private readonly clipId: string,
    private readonly note: MIDINoteEvent,
  ) {}

  execute(): void {
    getStore().addNoteEvent(this.clipId, this.note);
  }

  undo(): void {
    getStore().removeNoteEvent(this.clipId, this.note.id);
  }

  serialize(): Record<string, unknown> {
    return { clipId: this.clipId, note: this.note };
  }
}

export class RemoveNoteCommand implements UndoCommand {
  readonly type = "remove-note";

  private savedNote: MIDINoteEvent | undefined;

  constructor(
    private readonly clipId: string,
    private readonly noteId: string,
  ) {}

  execute(): void {
    const clip = getStore().clips[this.clipId];
    if (clip && isMidiClip(clip)) {
      this.savedNote = clip.noteEvents.find((n) => n.id === this.noteId);
    }
    getStore().removeNoteEvent(this.clipId, this.noteId);
  }

  undo(): void {
    if (this.savedNote) getStore().addNoteEvent(this.clipId, this.savedNote);
  }

  serialize(): Record<string, unknown> {
    return { clipId: this.clipId, noteId: this.noteId };
  }
}

export class MoveNoteCommand implements UndoCommand {
  readonly type = "move-note";

  private oldStartTime = 0;
  private oldPitch = 0;

  constructor(
    private readonly clipId: string,
    private readonly noteId: string,
    private readonly newStartTime: number,
    private readonly newPitch: number,
  ) {}

  execute(): void {
    const clip = getStore().clips[this.clipId];
    if (clip && isMidiClip(clip)) {
      const note = clip.noteEvents.find((n) => n.id === this.noteId);
      if (note) {
        this.oldStartTime = note.startTime;
        this.oldPitch = note.pitch;
      }
    }
    getStore().moveNoteEvent(
      this.clipId,
      this.noteId,
      this.newStartTime,
      this.newPitch,
    );
  }

  undo(): void {
    getStore().moveNoteEvent(
      this.clipId,
      this.noteId,
      this.oldStartTime,
      this.oldPitch,
    );
  }

  serialize(): Record<string, unknown> {
    return {
      clipId: this.clipId,
      noteId: this.noteId,
      newStartTime: this.newStartTime,
      newPitch: this.newPitch,
      oldStartTime: this.oldStartTime,
      oldPitch: this.oldPitch,
    };
  }
}

export class ResizeNoteCommand implements UndoCommand {
  readonly type = "resize-note";

  private oldDuration = 0;

  constructor(
    private readonly clipId: string,
    private readonly noteId: string,
    private readonly newDuration: number,
  ) {}

  execute(): void {
    const clip = getStore().clips[this.clipId];
    if (clip && isMidiClip(clip)) {
      const note = clip.noteEvents.find((n) => n.id === this.noteId);
      if (note) {
        this.oldDuration = note.duration;
      }
    }
    getStore().resizeNoteEvent(this.clipId, this.noteId, this.newDuration);
  }

  undo(): void {
    getStore().resizeNoteEvent(this.clipId, this.noteId, this.oldDuration);
  }

  serialize(): Record<string, unknown> {
    return {
      clipId: this.clipId,
      noteId: this.noteId,
      newDuration: this.newDuration,
      oldDuration: this.oldDuration,
    };
  }
}

export class BatchNoteCommand implements UndoCommand {
  readonly type = "batch-note";

  constructor(private readonly commands: UndoCommand[]) {}

  execute(): void {
    for (const cmd of this.commands) cmd.execute();
  }

  undo(): void {
    for (let i = this.commands.length - 1; i >= 0; i--) this.commands[i]!.undo();
  }

  serialize(): Record<string, unknown> {
    return {
      commands: this.commands.map((c) => ({ type: c.type, ...c.serialize() })),
    };
  }
}

export type {
  TrackType,
  TrackModel,
  ClipModel,
  AudioClipModel,
  MidiClipModel,
  MIDINoteEvent,
} from "./types";
export { isAudioClip, isMidiClip } from "./types";
export {
  trackSchema,
  clipSchema,
  noteEventSchema,
  midiClipSchema,
  audioClipSchema,
} from "./track-schema";
export type { TrackSchema, ClipSchema } from "./track-schema";
export {
  AddTrackCommand,
  RemoveTrackCommand,
  UpdateTrackCommand,
  ReorderTrackCommand,
  AddClipCommand,
  RemoveClipCommand,
  MoveClipCommand,
  SplitClipCommand,
  TrimClipCommand,
  DuplicateClipCommand,
} from "./track-commands";
export {
  AddNoteCommand,
  RemoveNoteCommand,
  MoveNoteCommand,
  ResizeNoteCommand,
  BatchNoteCommand,
} from "./midi-commands";

