1	/**
2	 * Clip playback scheduler.
3	 * Schedules AudioBufferSourceNode instances for clips within the look-ahead window.
4	 * Integrates with the existing LookAheadScheduler pattern.
5	 *
6	 * Time model: clips use arrangement time (seconds on timeline).
7	 * The caller provides a `timeOffset` to convert to AudioContext time:
8	 *   audioContextTime = arrangementTime + timeOffset
9	 */
10	
11	import type { ClipModel } from "@state/track/types";
12	
13	type ScheduledClip = {
14	  source: AudioBufferSourceNode;
15	  gainNode: GainNode;
16	  clipId: string;
17	  /** AudioContext time when this clip's playback ends */
18	  endTime: number;
19	};
20	
21	export type ClipScheduler = {
22	  /**
23	   * Schedule clips that overlap the look-ahead window.
24	   * @param clips - Clips to potentially schedule
25	   * @param windowStart - Start of look-ahead window (AudioContext time)
26	   * @param windowEnd - End of look-ahead window (AudioContext time)
27	   * @param timeOffset - Offset to convert arrangement time to AudioContext time
28	   *                     (audioCtxTime = arrangementTime + timeOffset)
29	   * @param getBuffer - Resolve sourceId to AudioBuffer
30	   * @param destination - Node to connect scheduled clips to
31	   */
32	  scheduleClips(
33	    clips: readonly ClipModel[],
34	    windowStart: number,
35	    windowEnd: number,
36	    timeOffset: number,
37	    getBuffer: (sourceId: string) => AudioBuffer | undefined,
38	    destination: AudioNode,
39	  ): void;
40	
41	  /** Stop all currently scheduled clips */
42	  stopAll(): void;
43	
44	  /** Clean up completed clips from internal tracking */
45	  cleanup(): void;
46	};
47	
48	export function createClipScheduler(ctx: AudioContext): ClipScheduler {
49	  const scheduled = new Map<string, ScheduledClip>();
50	
51	  return {
52	    scheduleClips(
53	      clips: readonly ClipModel[],
54	      windowStart: number,
55	      windowEnd: number,
56	      timeOffset: number,
57	      getBuffer: (sourceId: string) => AudioBuffer | undefined,
58	      destination: AudioNode,
59	    ): void {
60	      for (const clip of clips) {
61	        // Convert arrangement time to AudioContext time
62	        const clipStartCtx = clip.startTime + timeOffset;
63	        const clipEndCtx = clipStartCtx + clip.duration;
64	
65	        // Skip if already scheduled and still playing
66	        if (scheduled.has(clip.id)) continue;
67	
68	        // Check if clip overlaps the look-ahead window
69	        if (clipEndCtx <= windowStart || clipStartCtx >= windowEnd) {
70	          continue;
71	        }
72	
73	        const buffer = getBuffer(clip.sourceId);
74	        if (!buffer) continue;
75	
76	        const source = ctx.createBufferSource();
77	        source.buffer = buffer;
78	
79	        // Compute source offset for mid-clip seeking
80	        const seekOffset =
81	          clipStartCtx < windowStart ? windowStart - clipStartCtx : 0;
82	        const sourceOffset = clip.sourceOffset + seekOffset;
83	        const playDuration = clip.duration - seekOffset;
84	        const playStartCtx = clipStartCtx + seekOffset;
85	
86	        // Create gain node for clip-level gain and fades
87	        const gainNode = ctx.createGain();
88	        gainNode.gain.value = clip.gain;
89	
90	        // Clamp fades to avoid overlap
91	        const maxFadeIn = Math.min(clip.fadeIn, clip.duration);
92	        const maxFadeOut = Math.min(clip.fadeOut, clip.duration - maxFadeIn);
93	
94	        // Apply fade-in (only if we haven't seeked past it)
95	        if (maxFadeIn > 0 && seekOffset < maxFadeIn) {
96	          const fadeInStart = clipStartCtx + seekOffset;
97	          const fadeInRemaining = maxFadeIn - seekOffset;
98	          const startGain =
99	            seekOffset > 0 ? (seekOffset / maxFadeIn) * clip.gain : 0;
100	          gainNode.gain.setValueAtTime(startGain, fadeInStart);
101	          gainNode.gain.linearRampToValueAtTime(
102	            clip.gain,
103	            fadeInStart + fadeInRemaining,
104	          );
105	        }
106	
107	        // Apply fade-out (mirror of fade-in: handle mid-fade seeking)
108	        if (maxFadeOut > 0) {
109	          const fadeOutStartCtx = clipEndCtx - maxFadeOut;
110	          const fadeOutStartInClip = clip.duration - maxFadeOut;
111	
112	          if (seekOffset >= fadeOutStartInClip) {
113	            // Seeking into the fade-out region: compute partial gain
114	            const fadeOutProgress =
115	              (seekOffset - fadeOutStartInClip) / maxFadeOut;
116	            const startGain = clip.gain * (1 - fadeOutProgress);
117	            gainNode.gain.setValueAtTime(startGain, playStartCtx);
118	            gainNode.gain.linearRampToValueAtTime(0, clipEndCtx);
119	          } else {
120	            gainNode.gain.setValueAtTime(clip.gain, fadeOutStartCtx);
121	            gainNode.gain.linearRampToValueAtTime(0, clipEndCtx);
122	          }
123	        }
124	
125	        // Connect: source -> gainNode -> destination
126	        source.connect(gainNode);
127	        gainNode.connect(destination);
128	
129	        // Schedule playback using AudioContext time
130	        source.start(playStartCtx, sourceOffset, playDuration);
131	
132	        const entry: ScheduledClip = {
133	          source,
134	          gainNode,
135	          clipId: clip.id,
136	          endTime: clipEndCtx,
137	        };
138	        scheduled.set(clip.id, entry);
139	
140	        // Auto-cleanup when playback ends
141	        source.addEventListener("ended", () => {
142	          // Only remove if this is still the active entry for this clip
143	          const current = scheduled.get(clip.id);
144	          if (current === entry) {
145	            gainNode.disconnect();
146	            scheduled.delete(clip.id);
147	          }
148	        });
149	      }
150	    },
151	
152	    stopAll(): void {
153	      for (const entry of scheduled.values()) {
154	        try {
155	          entry.source.stop();
156	        } catch {
157	          // Source may have already stopped
158	        }
159	        entry.gainNode.disconnect();
160	      }
161	      scheduled.clear();
162	    },
163	
164	    cleanup(): void {
165	      const now = ctx.currentTime;
166	      for (const [id, entry] of scheduled) {
167	        if (entry.endTime <= now) {
168	          entry.gainNode.disconnect();
169	          scheduled.delete(id);
170	        }
171	      }
172	    },
173	  };
174	}
175

