99	export function useSessionPersistence(
100	  storage: SessionStorage,
101	): SessionPersistenceResult {
102	  const [recoveryWarnings, setRecoveryWarnings] = useState<string[]>([]);
103	  const [saving, setSaving] = useState(false);
104	  const loadedRef = useRef(false);
105	
106	  const saveQueue = useMemo(() => createSaveQueue(storage), [storage]);
107	
108	  const autoSave = useMemo(
109	    () => createAutoSave(() => JSON.stringify(storeToSession()), saveQueue),
110	    [saveQueue],
111	  );
112	
113	  // Load session from storage on mount (draft-first for crash safety)
114	  useEffect(() => {
115	    if (loadedRef.current) return;
116	    loadedRef.current = true;
117	
118	    void (async (): Promise<void> => {
119	      // Check draft first — a crash between putDraft and putCurrent
120	      // means the draft is the most recent write attempt
121	      const draft = await storage.getDraft();
122	      const raw = draft ?? (await storage.getCurrent());
123	      if (raw !== undefined) {
124	        const result = recoverSession(raw);
125	        hydrateStore(result.session);
126	        if (draft !== undefined) {
127	          result.warnings.push(
128	            "Recovered from unsaved draft (possible crash recovery)",
129	          );
130	        }
131	        if (result.warnings.length > 0) {
132	          setRecoveryWarnings(result.warnings);
133	        }
134	      }
135	    })();
136	  }, [storage]);
137	
138	  // Start auto-save and subscribe to store changes
139	  useEffect(() => {
140	    autoSave.start();
141	
142	    const unsubDaw = useDawStore.subscribe(() => {
143	      autoSave.notifyChange();
144	    });
145	    const unsubEffects = useEffectsStore.subscribe(() => {
146	      autoSave.notifyChange();
147	    });
148	
149	    return () => {
150	      autoSave.stop();
151	      unsubDaw();
152	      unsubEffects();
153	    };
154	  }, [autoSave]);
155	
156	  const saveNow = useCallback(async (): Promise<void> => {
157	    setSaving(true);
158	    await autoSave.saveNow();
159	    await saveQueue.flush();
160	    setSaving(false);
161	  }, [autoSave, saveQueue]);
162	
163	  return {
164	    saving,
165	    dirty: autoSave.dirty,
166	    saveNow,
167	    recoveryWarnings,
168	  };
169	}
