};
```

Change it to:
```typescript
export type TrackType = "audio" | "instrument";

export type MIDINoteEvent = {
  readonly id: string;
  readonly pitch: number;    // 0-127
  readonly velocity: number; // 0-127
  readonly startTime: number; // seconds, relative to clip start
  readonly duration: number;  // seconds
};

export type AudioClipModel = {
  readonly type: "audio";
  readonly id: string;
  readonly trackId: string;
  readonly sourceId: string;
  readonly startTime: number;
  readonly sourceOffset: number;
  readonly duration: number;
  readonly gain: number;
  readonly fadeIn: number;
  readonly fadeOut: number;
  readonly name: string;
};

export type MidiClipModel = {
  readonly type: "midi";
  readonly id: string;
  readonly trackId: string;
  readonly startTime: number;
  readonly duration: number;
  readonly noteEvents: readonly MIDINoteEvent[];
  readonly name: string;
};

export type ClipModel = AudioClipModel | MidiClipModel;

export function isAudioClip(clip: ClipModel): clip is AudioClipModel {
  return clip.type === "audio";
}

export function isMidiClip(clip: ClipModel): clip is MidiClipModel {
  return clip.type === "midi";
}

export type TrackModel = {
  readonly id: string;
  readonly name: string;
  readonly type: TrackType;
  readonly color: string;
  readonly muted: boolean;
  readonly solo: boolean;
  readonly armed: boolean;
  readonly soloIsolate: boolean;
  readonly volume: number;
  readonly pan: number;
  readonly clipIds: readonly string[];
};
```

### 2. Update `src/state/store.ts`

Add MIDI-specific state and actions to the DawStore type and implementation:

New state:
- `selectedNoteIds: readonly string[]`

New actions:
- `addMidiClip(clip: MidiClipModel)` - adds MIDI clip, wires clipIds (same pattern as addClip)
- `removeMidiClip(id: string)` - removes MIDI clip (same as removeClip)
- `addNoteEvent(clipId: string, note: MIDINoteEvent)` - adds note to MIDI clip's noteEvents
- `removeNoteEvent(clipId: string, noteId: string)` - removes note from MIDI clip
- `moveNoteEvent(clipId: string, noteId: string, newStartTime: number, newPitch: number)` - updates note position
- `resizeNoteEvent(clipId: string, noteId: string, newDuration: number)` - updates note duration
- `updateNoteVelocity(clipId: string, noteId: string, velocity: number)` - updates velocity
- `setSelectedNoteIds(ids: readonly string[])` - tracks note selection

Import the new types: `import type { TrackModel, ClipModel, MidiClipModel, MIDINoteEvent } from "./track/types";`
Also import: `import { isMidiClip } from "./track/types";`

For addMidiClip, follow the exact same pattern as addClip but typed for MidiClipModel.

For note operations (addNoteEvent, etc.), find the clip, verify it's a MIDI clip using isMidiClip(), then update its noteEvents array immutably:
```typescript
addNoteEvent: (clipId: string, note: MIDINoteEvent) => {
  set((state) => {
    const clip = state.clips[clipId];
    if (!clip || !isMidiClip(clip)) return state;
    const updated: MidiClipModel = {
      ...clip,
      noteEvents: [...clip.noteEvents, note],
    };
