### 3. Create `src/state/track/midi-commands.ts`

Create undo commands following the exact same pattern as track-commands.ts:

```typescript
import type { UndoCommand } from "@state/undo/undo-command";
import { useDawStore } from "@state/store";
import type { MIDINoteEvent, MidiClipModel } from "@state/track/types";
import { isMidiClip } from "@state/track/types";

function getStore() {
  return useDawStore.getState();
}

export class AddNoteCommand implements UndoCommand {
  readonly type = "add-note";
  constructor(
    private readonly clipId: string,
    private readonly note: MIDINoteEvent,
  ) {}
  execute(): void { getStore().addNoteEvent(this.clipId, this.note); }
  undo(): void { getStore().removeNoteEvent(this.clipId, this.note.id); }
  serialize(): Record<string, unknown> { return { clipId: this.clipId, note: this.note }; }
}

export class RemoveNoteCommand implements UndoCommand {
  readonly type = "remove-note";
  private savedNote: MIDINoteEvent | undefined;
  constructor(
    private readonly clipId: string,
    private readonly noteId: string,
  ) {}
  execute(): void {
    const clip = getStore().clips[this.clipId];
    if (clip && isMidiClip(clip)) {
      this.savedNote = clip.noteEvents.find((n) => n.id === this.noteId);
    }
    getStore().removeNoteEvent(this.clipId, this.noteId);
  }
  undo(): void {
    if (this.savedNote) getStore().addNoteEvent(this.clipId, this.savedNote);
  }
  serialize(): Record<string, unknown> { return { clipId: this.clipId, noteId: this.noteId }; }
}

export class MoveNoteCommand implements UndoCommand {
  readonly type = "move-note";
  private oldStartTime = 0;
  private oldPitch = 0;
  constructor(
    private readonly clipId: string,
    private readonly noteId: string,
    private readonly newStartTime: number,
    private readonly newPitch: number,
  ) {}
  execute(): void {
    const clip = getStore().clips[this.clipId];
    if (clip && isMidiClip(clip)) {
      const note = clip.noteEvents.find((n) => n.id === this.noteId);
      if (note) { this.oldStartTime = note.startTime; this.oldPitch = note.pitch; }
    }
    getStore().moveNoteEvent(this.clipId, this.noteId, this.newStartTime, this.newPitch);
  }
  undo(): void {
    getStore().moveNoteEvent(this.clipId, this.noteId, this.oldStartTime, this.oldPitch);
  }
  serialize(): Record<string, unknown> {
    return { clipId: this.clipId, noteId: this.noteId, newStartTime: this.newStartTime, newPitch: this.newPitch, oldStartTime: this.oldStartTime, oldPitch: this.oldPitch };
  }
}

export class ResizeNoteCommand implements UndoCommand {
  readonly type = "resize-note";
  private oldDuration = 0;
  constructor(
    private readonly clipId: string,
    private readonly noteId: string,
    private readonly newDuration: number,
  ) {}
  execute(): void {
    const clip = getStore().clips[this.clipId];
    if (clip && isMidiClip(clip)) {
      const note = clip.noteEvents.find((n) => n.id === this.noteId);
      if (note) { this.oldDuration = note.duration; }
    }
    getStore().resizeNoteEvent(this.clipId, this.noteId, this.newDuration);
  }
  undo(): void {
    getStore().resizeNoteEvent(this.clipId, this.noteId, this.oldDuration);
  }
  serialize(): Record<string, unknown> {
    return { clipId: this.clipId, noteId: this.noteId, newDuration: this.newDuration, oldDuration: this.oldDuration };
  }
}

export class BatchNoteCommand implements UndoCommand {
  readonly type = "batch-note";
  constructor(private readonly commands: UndoCommand[]) {}
  execute(): void { for (const cmd of this.commands) cmd.execute(); }
  undo(): void { for (let i = this.commands.length - 1; i >= 0; i--) this.commands[i]!.undo(); }
  serialize(): Record<string, unknown> {
    return { commands: this.commands.map((c) => ({ type: c.type, ...c.serialize() })) };
  }
}
```

### 4. Update `src/state/track/track-schema.ts`

Add Zod schemas for MIDI types. The current file uses `zod/v4`:

```typescript
import { z } from "zod/v4";

export const noteEventSchema = z.object({
  id: z.string(),
  pitch: z.number().int().min(0).max(127),
  velocity: z.number().int().min(0).max(127),
  startTime: z.number().min(0),
  duration: z.number().gt(0),
});

export const audioClipSchema = z.object({
  type: z.literal("audio"),
  id: z.string(),
  trackId: z.string(),
  sourceId: z.string(),
  startTime: z.number().min(0),
  sourceOffset: z.number().min(0),
  duration: z.number().min(0),
  gain: z.number().min(0).max(2),
  fadeIn: z.number().min(0),
  fadeOut: z.number().min(0),
  name: z.string(),
});

export const midiClipSchema = z.object({
  type: z.literal("midi"),
  id: z.string(),
  trackId: z.string(),
  startTime: z.number().min(0),
  duration: z.number().min(0),
  noteEvents: z.array(noteEventSchema),
  name: z.string(),
});

// Keep clipSchema as discriminated union
export const clipSchema = z.discriminatedUnion("type", [audioClipSchema, midiClipSchema]);
```

IMPORTANT: The existing `clipSchema` is used in the session schema. By replacing it with a discriminated union, the session schema will automatically accept both types. This is backward compatible because existing audio clips can be migrated by adding `type: "audio"` during deserialization.

