import { describe, it, expect, vi } from "vitest";
import type { MIDINoteEvent } from "@state/track/types";
import {
  renderPianoRoll,
  isBlackKey,
  noteName,
  secondsToX,
  pitchToY,
  type PianoRollViewState,
  type PianoRollRenderContext,
} from "./piano-roll-renderer";
import { PR_RULER_HEIGHT, PR_VELOCITY_LANE_HEIGHT } from "./constants";

// -- Helpers ------------------------------------------------------------------

type MockCtx = {
  fillRect: ReturnType<typeof vi.fn>;
  strokeRect: ReturnType<typeof vi.fn>;
  fillText: ReturnType<typeof vi.fn>;
  beginPath: ReturnType<typeof vi.fn>;
  moveTo: ReturnType<typeof vi.fn>;
  lineTo: ReturnType<typeof vi.fn>;
  stroke: ReturnType<typeof vi.fn>;
  save: ReturnType<typeof vi.fn>;
  restore: ReturnType<typeof vi.fn>;
  clearRect: ReturnType<typeof vi.fn>;
  rect: ReturnType<typeof vi.fn>;
  clip: ReturnType<typeof vi.fn>;
  measureText: ReturnType<typeof vi.fn>;
  fillStyle: string;
  strokeStyle: string;
  lineWidth: number;
  font: string;
  textBaseline: CanvasTextBaseline;
  textAlign: CanvasTextAlign;
  globalAlpha: number;
};

function createMockCtx(): MockCtx {
  return {
    fillRect: vi.fn(),
    strokeRect: vi.fn(),
    fillText: vi.fn(),
    beginPath: vi.fn(),
    moveTo: vi.fn(),
    lineTo: vi.fn(),
    stroke: vi.fn(),
    save: vi.fn(),
    restore: vi.fn(),
    clearRect: vi.fn(),
    rect: vi.fn(),
    clip: vi.fn(),
    measureText: vi.fn().mockReturnValue({ width: 40 }),
    fillStyle: "",
    strokeStyle: "",
    lineWidth: 0,
    font: "",
    textBaseline: "alphabetic",
    textAlign: "start",
    globalAlpha: 1,
  };
}

function makeNote(overrides: Partial<MIDINoteEvent> = {}): MIDINoteEvent {
  return {
    id: "note-1",
    pitch: 60,
    velocity: 100,
    startTime: 0,
    duration: 0.5,
    ...overrides,
  };
}

const defaultView: PianoRollViewState = {
  scrollX: 0,
  scrollY: 84,
  pixelsPerSecond: 100,
  noteHeight: 16,
  keyboardWidth: 48,
};

function makeRenderContext(
  overrides: Partial<Omit<PianoRollRenderContext, "ctx">> = {},
): { rc: PianoRollRenderContext; mock: MockCtx } {
  const mock = createMockCtx();
  const rc: PianoRollRenderContext = {
    ctx: mock as unknown as CanvasRenderingContext2D,
    width: 800,
    height: 400,
    view: defaultView,
    notes: [],
    selectedNoteIds: [],
    cursorSeconds: 0,
    bpm: 120,
    clipStartTime: 0,
    clipDuration: 8,
    tool: "select",
    velocityLaneHeight: PR_VELOCITY_LANE_HEIGHT,
    ...overrides,
  };
  return { rc, mock };
}

