describe("piano-roll-renderer", () => {
  describe("isBlackKey", () => {
    it("identifies black keys (C#, D#, F#, G#, A#)", () => {
      // C#=1, D#=3, F#=6, G#=8, A#=10
      expect(isBlackKey(1)).toBe(true); // C#
      expect(isBlackKey(3)).toBe(true); // D#
      expect(isBlackKey(6)).toBe(true); // F#
      expect(isBlackKey(8)).toBe(true); // G#
      expect(isBlackKey(10)).toBe(true); // A#
    });

    it("identifies white keys (C, D, E, F, G, A, B)", () => {
      expect(isBlackKey(0)).toBe(false); // C
      expect(isBlackKey(2)).toBe(false); // D
      expect(isBlackKey(4)).toBe(false); // E
      expect(isBlackKey(5)).toBe(false); // F
      expect(isBlackKey(7)).toBe(false); // G
      expect(isBlackKey(9)).toBe(false); // A
      expect(isBlackKey(11)).toBe(false); // B
    });

    it("works across octaves", () => {
      expect(isBlackKey(13)).toBe(true); // C#1
      expect(isBlackKey(60)).toBe(false); // C4
      expect(isBlackKey(61)).toBe(true); // C#4
      expect(isBlackKey(69)).toBe(false); // A4
      expect(isBlackKey(70)).toBe(true); // A#4
    });
  });

  describe("noteName", () => {
    it("returns correct name for middle C (C4)", () => {
      expect(noteName(60)).toBe("C4");
    });

    it("returns correct name for A4 (concert pitch)", () => {
      expect(noteName(69)).toBe("A4");
    });

    it("returns correct sharps", () => {
      expect(noteName(61)).toBe("C#4");
      expect(noteName(66)).toBe("F#4");
    });

    it("handles low and high notes", () => {
      expect(noteName(0)).toBe("C-1");
      expect(noteName(127)).toBe("G9");
      expect(noteName(12)).toBe("C0");
      expect(noteName(24)).toBe("C1");
    });
  });

  describe("secondsToX", () => {
    it("converts seconds to pixels accounting for keyboard width", () => {
      const view = { ...defaultView, keyboardWidth: 48, pixelsPerSecond: 100 };
      // x = keyboardWidth + (seconds - scrollX) * pps
      // x = 48 + (1 - 0) * 100 = 148
      expect(secondsToX(1, view)).toBe(148);
    });

    it("accounts for scroll offset", () => {
      const view = { ...defaultView, scrollX: 2, pixelsPerSecond: 100 };
      // x = 48 + (3 - 2) * 100 = 148
      expect(secondsToX(3, view)).toBe(148);
    });

    it("returns keyboard width for scrollX origin", () => {
      const view = { ...defaultView, scrollX: 0, pixelsPerSecond: 100 };
      expect(secondsToX(0, view)).toBe(48);
    });
  });

  describe("pitchToY", () => {
    it("places higher pitch at lower Y value (higher on screen)", () => {
      const view = { ...defaultView, scrollY: 84, noteHeight: 16 };
      const height = 400;
      const yHigh = pitchToY(84, view, height, PR_VELOCITY_LANE_HEIGHT);
      const yLow = pitchToY(60, view, height, PR_VELOCITY_LANE_HEIGHT);
      expect(yHigh).toBeLessThan(yLow);
    });

    it("returns ruler height when pitch equals scrollY", () => {
      const view = { ...defaultView, scrollY: 84, noteHeight: 16 };
      const y = pitchToY(84, view, 400, PR_VELOCITY_LANE_HEIGHT);
      expect(y).toBe(PR_RULER_HEIGHT);
    });

    it("each semitone step moves by noteHeight pixels", () => {
      const view = { ...defaultView, scrollY: 84, noteHeight: 16 };
      const y1 = pitchToY(84, view, 400, PR_VELOCITY_LANE_HEIGHT);
      const y2 = pitchToY(83, view, 400, PR_VELOCITY_LANE_HEIGHT);
      expect(y2 - y1).toBe(16);
    });
  });

  describe("renderPianoRoll", () => {
    it("does not crash with no notes", () => {
      const { rc } = makeRenderContext({ notes: [] });
      expect(() => {
        renderPianoRoll(rc);
      }).not.toThrow();
    });

    it("fills background", () => {
      const { rc, mock } = makeRenderContext();
      renderPianoRoll(rc);
      expect(mock.fillRect).toHaveBeenCalledWith(0, 0, 800, 400);
    });

    it("draws notes at correct positions", () => {
      const notes = [
        makeNote({ id: "n1", pitch: 80, startTime: 1, duration: 0.5 }),
      ];
      const { rc, mock } = makeRenderContext({ notes });
      renderPianoRoll(rc);

      // x = keyboardWidth + (startTime - scrollX) * pps = 48 + (1-0)*100 = 148
      // w = duration * pps = 0.5 * 100 = 50
      // y = RULER_HEIGHT + (scrollY - pitch) * noteHeight = 24 + (84-80)*16 = 88
      // h = noteHeight = 16
      const fillCalls = mock.fillRect.mock.calls as number[][];
      const noteCall = fillCalls.find(
        ([x, y, w, h]) => x === 148 && w === 50 && y === 88 && h === 16,
      );
      expect(noteCall).toBeDefined();
    });

    it("highlights selected notes with white border", () => {
      const notes = [makeNote({ id: "n1", pitch: 80, startTime: 1 })];
      const { rc, mock } = makeRenderContext({
        notes,
        selectedNoteIds: ["n1"],
      });
      renderPianoRoll(rc);

      // Selected note should get a strokeRect with white color
      expect(mock.strokeRect).toHaveBeenCalled();
      // Check that strokeStyle was set to white at some point
      const setCalls = (mock as unknown as { strokeStyle: string }).strokeStyle;
      // We need to verify via the mock calls that white was used
      expect(mock.strokeRect.mock.calls.length).toBeGreaterThan(0);
    });

    it("draws velocity bars in the velocity lane", () => {
      const notes = [
        makeNote({
          id: "n1",
          pitch: 80,
          startTime: 1,
          duration: 0.5,
          velocity: 100,
        }),
      ];
      const { rc, mock } = makeRenderContext({ notes });
      renderPianoRoll(rc);

      // Velocity bar x should match note x (148)
      // Velocity lane is at the bottom of the canvas
      const fillCalls = mock.fillRect.mock.calls as number[][];
      const velocityLaneTop = 400 - PR_VELOCITY_LANE_HEIGHT;
      const velocityBar = fillCalls.find(
        ([x, y]) => x === 148 && y >= velocityLaneTop,
      );
      expect(velocityBar).toBeDefined();
    });

    it("draws playhead as a vertical line", () => {
      const { rc, mock } = makeRenderContext({ cursorSeconds: 2 });
      renderPianoRoll(rc);

      // Playhead x = keyboardWidth + (cursorSeconds - scrollX) * pps = 48 + 2*100 = 248
      const moveToX = (mock.moveTo.mock.calls as number[][]).filter(
        ([x]) => x === 248,
      );
      expect(moveToX.length).toBeGreaterThan(0);
    });

    it("draws piano keyboard sidebar", () => {
      const { rc, mock } = makeRenderContext();
      renderPianoRoll(rc);

      // Should draw C note labels in the keyboard
      const texts = mock.fillText.mock.calls.map(
        ([text]: [string]) => text,
      ) as string[];
      const cLabels = texts.filter((t) => /^C\d+$/.test(t));
      expect(cLabels.length).toBeGreaterThan(0);
    });

    it("draws bar numbers in the ruler", () => {
      const { rc, mock } = makeRenderContext({ bpm: 120 });
      renderPianoRoll(rc);

      const texts = mock.fillText.mock.calls.map(
        ([text]: [string]) => text,
      ) as string[];
      expect(texts).toContain("1");
    });
  });
});

import { describe, it, expect } from "vitest";
import {
  clampMidi7Bit,
  clampMidi14Bit,
  validateMidiMessage,
  validateSysEx,
} from "./midi-input-validator";

describe("clampMidi7Bit", () => {
  it("passes through values in range", () => {
    expect(clampMidi7Bit(0)).toBe(0);
    expect(clampMidi7Bit(64)).toBe(64);
    expect(clampMidi7Bit(127)).toBe(127);
  });

  it("clamps negative values to 0", () => {
    expect(clampMidi7Bit(-1)).toBe(0);
    expect(clampMidi7Bit(-100)).toBe(0);
  });

  it("clamps values above 127 to 127", () => {
    expect(clampMidi7Bit(128)).toBe(127);
    expect(clampMidi7Bit(999)).toBe(127);
  });

  it("floors fractional values before clamping", () => {
    expect(clampMidi7Bit(64.9)).toBe(64);
    expect(clampMidi7Bit(127.5)).toBe(127);
  });
});

describe("clampMidi14Bit", () => {
  it("passes through values in range", () => {
    expect(clampMidi14Bit(0)).toBe(0);
    expect(clampMidi14Bit(8192)).toBe(8192);
    expect(clampMidi14Bit(16383)).toBe(16383);
  });

  it("clamps negative values to 0", () => {
    expect(clampMidi14Bit(-1)).toBe(0);
  });

  it("clamps values above 16383 to 16383", () => {
    expect(clampMidi14Bit(16384)).toBe(16383);
    expect(clampMidi14Bit(99999)).toBe(16383);
  });
});

describe("validateMidiMessage", () => {
  it("parses note-on correctly", () => {
    // Note On, channel 0, note 60, velocity 100
    const result = validateMidiMessage(new Uint8Array([0x90, 60, 100]));
    expect(result.valid).toBe(true);
    if (!result.valid) return;
    expect(result.message).toEqual({
      type: "note-on",
      note: 60,
      velocity: 100,
      channel: 0,
    });
  });

  it("parses note-on on channel 5", () => {
    const result = validateMidiMessage(new Uint8Array([0x95, 72, 80]));
    expect(result.valid).toBe(true);
    if (!result.valid) return;
    expect(result.message).toEqual({
      type: "note-on",
      note: 72,
      velocity: 80,
      channel: 5,
    });
  });

  it("converts note-on with velocity 0 to note-off", () => {
    const result = validateMidiMessage(new Uint8Array([0x90, 60, 0]));
    expect(result.valid).toBe(true);
    if (!result.valid) return;
    expect(result.message).toEqual({
      type: "note-off",
      note: 60,
      channel: 0,
    });
  });

  it("parses note-off correctly", () => {
    // Note Off, channel 2, note 48
    const result = validateMidiMessage(new Uint8Array([0x82, 48, 64]));
    expect(result.valid).toBe(true);
    if (!result.valid) return;
    expect(result.message).toEqual({
      type: "note-off",
      note: 48,
      channel: 2,
    });
  });

  it("parses CC correctly", () => {
    // CC, channel 0, controller 1 (mod wheel), value 100
    const result = validateMidiMessage(new Uint8Array([0xb0, 1, 100]));
    expect(result.valid).toBe(true);
    if (!result.valid) return;
    expect(result.message).toEqual({
      type: "cc",
      controller: 1,
      value: 100,
      channel: 0,
    });
  });

  it("parses pitch bend correctly (14-bit reconstruction)", () => {
    // Pitch Bend, channel 0, LSB=0, MSB=64 => value = 64*128 + 0 = 8192 (center)
    const result = validateMidiMessage(new Uint8Array([0xe0, 0, 64]));
    expect(result.valid).toBe(true);
    if (!result.valid) return;
    expect(result.message).toEqual({
      type: "pitch-bend",
      value: 8192,
      channel: 0,
    });
  });

  it("parses pitch bend with both LSB and MSB", () => {
    // LSB=127, MSB=127 => 127*128 + 127 = 16383 (max)
    const result = validateMidiMessage(new Uint8Array([0xe0, 127, 127]));
    expect(result.valid).toBe(true);
    if (!result.valid) return;
    expect(result.message).toEqual({
      type: "pitch-bend",
      value: 16383,
      channel: 0,
    });
  });

  it("clamps out-of-range note values", () => {
    // Note value 200 should be clamped to 127
    const result = validateMidiMessage(new Uint8Array([0x90, 200, 100]));
    expect(result.valid).toBe(true);
    if (!result.valid) return;
    expect(result.message.type).toBe("note-on");
    if (result.message.type !== "note-on") return;
    expect(result.message.note).toBe(127);
  });

  it("clamps out-of-range CC values", () => {
    // CC value 200 should be clamped to 127
    const result = validateMidiMessage(new Uint8Array([0xb0, 200, 200]));
    expect(result.valid).toBe(true);
    if (!result.valid) return;
    expect(result.message.type).toBe("cc");
    if (result.message.type !== "cc") return;
    expect(result.message.controller).toBe(127);
    expect(result.message.value).toBe(127);
  });

  it("rejects empty data", () => {
    const result = validateMidiMessage(new Uint8Array([]));
    expect(result.valid).toBe(false);
    if (result.valid) return;
    expect(result.reason).toBeDefined();
  });

  it("rejects unknown status bytes", () => {
    // 0xF2 = Song Position Pointer -- not handled
    const result = validateMidiMessage(new Uint8Array([0xf2, 0, 0]));
    expect(result.valid).toBe(false);
    if (result.valid) return;
    expect(result.reason).toContain("Unsupported");
  });

  it("rejects messages with insufficient data bytes", () => {
    // Note On needs 3 bytes, only 2 provided
    const result = validateMidiMessage(new Uint8Array([0x90, 60]));
    expect(result.valid).toBe(false);
    if (result.valid) return;
    expect(result.reason).toBeDefined();
  });
});

describe("validateSysEx", () => {
  it("accepts messages under 1KB with proper framing", () => {
    const data = new Uint8Array(100);
    data[0] = 0xf0;
    data[99] = 0xf7;
    expect(validateSysEx(data)).toEqual({ valid: true });
  });

  it("rejects messages over 1KB", () => {
    const data = new Uint8Array(1025);
    data[0] = 0xf0;
    data[1024] = 0xf7;
    const result = validateSysEx(data);
    expect(result.valid).toBe(false);
    expect(result.reason).toBeDefined();
  });

  it("rejects messages without F0 start byte", () => {
    const data = new Uint8Array([0x00, 0x01, 0xf7]);
    const result = validateSysEx(data);
    expect(result.valid).toBe(false);
    expect(result.reason).toBeDefined();
  });

  it("rejects messages without F7 end byte", () => {
    const data = new Uint8Array([0xf0, 0x01, 0x02]);
    const result = validateSysEx(data);
    expect(result.valid).toBe(false);
    expect(result.reason).toBeDefined();
  });
});

import { describe, it, expect, beforeEach } from "vitest";
import { createMidiRecorder } from "./midi-recorder";
import type { MidiRecorder } from "./midi-recorder";
import type { ValidatedMidiMessage } from "./midi-input-validator";

describe("createMidiRecorder", () => {
  let recorder: MidiRecorder;

  beforeEach(() => {
    recorder = createMidiRecorder();
  });

  it("starts in idle state", () => {
    expect(recorder.state).toBe("idle");
  });

  it("arm changes state to armed", () => {
    recorder.arm();
    expect(recorder.state).toBe("armed");
  });

  it("startRecording changes state to recording", () => {
    recorder.arm();
    recorder.startRecording(0);
    expect(recorder.state).toBe("recording");
  });

  it("startRecording does nothing if not armed", () => {
    recorder.startRecording(0);
    expect(recorder.state).toBe("idle");
  });

  it("recordMessage captures note-on and note-off pair as MIDINoteEvent", () => {
    recorder.arm();
    recorder.startRecording(0);

    const noteOn: ValidatedMidiMessage = {
      type: "note-on",
      note: 60,
      velocity: 100,
      channel: 0,
    };
    const noteOff: ValidatedMidiMessage = {
      type: "note-off",
      note: 60,
      channel: 0,
    };

    recorder.recordMessage(noteOn, 1.0);
    recorder.recordMessage(noteOff, 2.0);

    const notes = recorder.stopRecording();
    expect(notes).toHaveLength(1);
    expect(notes[0]!.pitch).toBe(60);
    expect(notes[0]!.velocity).toBe(100);
    expect(notes[0]!.startTime).toBe(1.0);
    expect(notes[0]!.duration).toBe(1.0);
  });

  it("recordMessage computes correct duration from note-on to note-off", () => {
    recorder.arm();
    recorder.startRecording(10.0);

    const noteOn: ValidatedMidiMessage = {
      type: "note-on",
      note: 72,
      velocity: 80,
      channel: 0,
    };
    const noteOff: ValidatedMidiMessage = {
      type: "note-off",
      note: 72,
      channel: 0,
    };

    recorder.recordMessage(noteOn, 12.5);
    recorder.recordMessage(noteOff, 14.0);

    const notes = recorder.stopRecording();
    expect(notes).toHaveLength(1);
    expect(notes[0]!.startTime).toBeCloseTo(2.5, 6); // 12.5 - 10.0
    expect(notes[0]!.duration).toBeCloseTo(1.5, 6); // 14.0 - 12.5
  });

  it("recordMessage handles multiple simultaneous notes", () => {
    recorder.arm();
    recorder.startRecording(0);

    // Two notes overlapping
    recorder.recordMessage(
      { type: "note-on", note: 60, velocity: 100, channel: 0 },
      0.0,
    );
    recorder.recordMessage(
      { type: "note-on", note: 64, velocity: 90, channel: 0 },
      0.5,
    );
    recorder.recordMessage({ type: "note-off", note: 60, channel: 0 }, 1.0);
    recorder.recordMessage({ type: "note-off", note: 64, channel: 0 }, 1.5);

    const notes = recorder.stopRecording();
    expect(notes).toHaveLength(2);

    const note60 = notes.find((n) => n.pitch === 60);
    const note64 = notes.find((n) => n.pitch === 64);
    expect(note60).toBeDefined();
    expect(note64).toBeDefined();
    expect(note60!.duration).toBeCloseTo(1.0, 6);
    expect(note64!.duration).toBeCloseTo(1.0, 6);
  });

  it("stopRecording closes all open notes at stop time", () => {
    recorder.arm();
    recorder.startRecording(0);

    recorder.recordMessage(
      { type: "note-on", note: 60, velocity: 100, channel: 0 },
      1.0,
    );
    // No note-off -- stop at 3.0 should close it

    const notes = recorder.stopRecording();
    expect(notes).toHaveLength(1);
    // The open note started at transport 1.0, stop at the moment stopRecording is called
    // Duration is from 1.0 to whatever the last known time is
    expect(notes[0]!.pitch).toBe(60);
    expect(notes[0]!.startTime).toBe(1.0);
  });

  it("stopRecording returns all captured notes and resets state", () => {
    recorder.arm();
    recorder.startRecording(0);

    recorder.recordMessage(
      { type: "note-on", note: 60, velocity: 100, channel: 0 },
      0.0,
    );
    recorder.recordMessage({ type: "note-off", note: 60, channel: 0 }, 1.0);

    const notes = recorder.stopRecording();
    expect(notes).toHaveLength(1);
    expect(recorder.state).toBe("idle");

    // Second stop should return empty
    const notes2 = recorder.stopRecording();
    expect(notes2).toHaveLength(0);
  });

  it("disarm resets to idle", () => {
    recorder.arm();
    expect(recorder.state).toBe("armed");
    recorder.disarm();
    expect(recorder.state).toBe("idle");
  });

  it("ignores non-note messages during recording", () => {
    recorder.arm();
    recorder.startRecording(0);

    const cc: ValidatedMidiMessage = {
      type: "cc",
      controller: 1,
      value: 64,
      channel: 0,
    };
    recorder.recordMessage(cc, 0.5);

    const notes = recorder.stopRecording();
    expect(notes).toHaveLength(0);
  });

  it("ignores messages when not recording", () => {
    recorder.recordMessage(
      { type: "note-on", note: 60, velocity: 100, channel: 0 },
      0.0,
    );
    recorder.recordMessage({ type: "note-off", note: 60, channel: 0 }, 1.0);
    // Not recording, so nothing captured; calling stop should be safe
    const notes = recorder.stopRecording();
    expect(notes).toHaveLength(0);
  });
});

