/**
 * Pure canvas renderer for the piano roll editor.
 * No DOM access -- only draws to the CanvasRenderingContext2D passed in.
 */
import type { MIDINoteEvent } from "@state/track/types";
import { PR_RULER_HEIGHT } from "./constants";

// -- Design token constants (canvas cannot read CSS vars) ---------------------

const COLOR = {
  black: "#000000",
  white: "#ffffff",
  red: "#ff0000",
  blue: "#0066ff",
  gray900: "#111111",
  gray800: "#1a1a1a",
  gray700: "#333333",
  gray500: "#666666",
  gray400: "#888888",
  whiteKeyRow: "#1c1c1c",
  blackKeyRow: "#141414",
  whiteKey: "#e0e0e0",
  blackKey: "#222222",
} as const;

const FONT_MONO = "'JetBrains Mono', monospace" as const;
const TEXT_XS = 10;
const BORDER_WIDTH = 2;

// -- Public types -------------------------------------------------------------

export type PianoRollViewState = {
  scrollX: number; // seconds
  scrollY: number; // MIDI note number at top (0-127, higher = higher pitch)
  pixelsPerSecond: number; // horizontal zoom
  noteHeight: number; // pixels per semitone
  keyboardWidth: number; // width of piano keyboard sidebar
};

export type PianoRollTool = "pencil" | "select" | "erase";

export type PianoRollRenderContext = {
  ctx: CanvasRenderingContext2D;
  width: number;
  height: number;
  view: PianoRollViewState;
  notes: readonly MIDINoteEvent[];
  selectedNoteIds: readonly string[];
  cursorSeconds: number;
  bpm: number;
  clipStartTime: number; // absolute timeline position of the clip
  clipDuration: number;
  tool: PianoRollTool;
  velocityLaneHeight: number; // height of velocity lane at bottom
};

// -- Helpers ------------------------------------------------------------------

export function secondsToX(
  seconds: number,
  view: PianoRollViewState,
): number {
  return view.keyboardWidth + (seconds - view.scrollX) * view.pixelsPerSecond;
}

export function pitchToY(
  pitch: number,
  view: PianoRollViewState,
  _height: number,
  _velocityLaneHeight: number,
): number {
  return PR_RULER_HEIGHT + (view.scrollY - pitch) * view.noteHeight;
}

export function isBlackKey(pitch: number): boolean {
  const pc = pitch % 12;
  return pc === 1 || pc === 3 || pc === 6 || pc === 8 || pc === 10;
}

export function noteName(pitch: number): string {
  const names = [
    "C",
    "C#",
    "D",
    "D#",
    "E",
    "F",
    "F#",
    "G",
    "G#",
    "A",
    "A#",
    "B",
  ];
  const octave = Math.floor(pitch / 12) - 1;
  return (names[pitch % 12] ?? "") + String(octave);
}

/** Convert a hex color (#rrggbb) to rgba with given alpha (0-1). */
function hexToRgba(hex: string, alpha: number): string {
  if (!/^#[0-9a-fA-F]{6}$/.test(hex)) {
    return `rgba(128,128,128,${String(alpha)})`;
  }
  const r = parseInt(hex.slice(1, 3), 16);
  const g = parseInt(hex.slice(3, 5), 16);
  const b = parseInt(hex.slice(5, 7), 16);
  return `rgba(${String(r)},${String(g)},${String(b)},${String(alpha)})`;
}

// -- Rendering stages ---------------------------------------------------------

function drawBackground(rc: PianoRollRenderContext): void {
  const { ctx, width, height } = rc;
  ctx.fillStyle = COLOR.gray900;
  ctx.fillRect(0, 0, width, height);
}

function drawNoteGrid(rc: PianoRollRenderContext): void {
  const { ctx, width, height, view, velocityLaneHeight } = rc;
  const gridBottom = height - velocityLaneHeight;

  // Determine visible pitch range
  const topPitch = view.scrollY;
  const visibleRows = Math.ceil(
    (gridBottom - PR_RULER_HEIGHT) / view.noteHeight,
  );
  const bottomPitch = topPitch - visibleRows;

  for (let pitch = topPitch; pitch >= bottomPitch; pitch--) {
    const y = pitchToY(pitch, view, height, velocityLaneHeight);
    if (y + view.noteHeight < PR_RULER_HEIGHT || y > gridBottom) continue;

    // Row fill: slightly lighter for white keys
    ctx.fillStyle = isBlackKey(pitch)
      ? COLOR.blackKeyRow
      : COLOR.whiteKeyRow;
    ctx.fillRect(view.keyboardWidth, y, width - view.keyboardWidth, view.noteHeight);

    // Horizontal separator
    ctx.strokeStyle = COLOR.gray700;
    ctx.lineWidth = 1;
    ctx.beginPath();
    ctx.moveTo(view.keyboardWidth, y + view.noteHeight);
    ctx.lineTo(width, y + view.noteHeight);
    ctx.stroke();
  }
}

function drawTimeGrid(rc: PianoRollRenderContext): void {
  const { ctx, width, height, view, bpm, velocityLaneHeight } = rc;
  const secPerBeat = 60 / bpm;
  const secPerBar = secPerBeat * 4;
  const gridBottom = height - velocityLaneHeight;

  const startSec = view.scrollX;
  const endSec =
    view.scrollX + (width - view.keyboardWidth) / view.pixelsPerSecond;

  // Determine grid step -- skip beats when zoomed out too far
  const minPxPerLine = 12;
  let step = secPerBeat;
  while (step * view.pixelsPerSecond < minPxPerLine) {
    step *= 2;
  }

  const firstBeat = Math.floor(startSec / step) * step;

  ctx.save();
  for (let t = firstBeat; t <= endSec; t += step) {
    const x = secondsToX(t, view);
    if (x < view.keyboardWidth || x > width) continue;

    const nearestBar = Math.round(t / secPerBar) * secPerBar;
    const isBar = Math.abs(t - nearestBar) < 0.001;
    ctx.strokeStyle = COLOR.gray700;
    ctx.lineWidth = isBar ? 2 : 1;

    ctx.beginPath();
    ctx.moveTo(x, PR_RULER_HEIGHT);
    ctx.lineTo(x, gridBottom);
    ctx.stroke();
  }
  ctx.restore();
}

function drawNotes(rc: PianoRollRenderContext): void {
  const { ctx, view, height, notes, selectedNoteIds, velocityLaneHeight } = rc;
  const selectedSet = new Set(selectedNoteIds);

  for (const note of notes) {
    const x = secondsToX(note.startTime, view);
    const w = note.duration * view.pixelsPerSecond;
    const y = pitchToY(note.pitch, view, height, velocityLaneHeight);
    const h = view.noteHeight;

    // Skip notes fully out of view
    if (x + w < view.keyboardWidth || x > rc.width) continue;
    if (y + h < PR_RULER_HEIGHT || y > height - velocityLaneHeight) continue;

    // Fill
    ctx.fillStyle = hexToRgba(COLOR.blue, 0.8);
    ctx.fillRect(x, y, w, h);

    // Border
    const isSelected = selectedSet.has(note.id);
    ctx.strokeStyle = isSelected ? COLOR.white : COLOR.blue;
    ctx.lineWidth = BORDER_WIDTH;
    ctx.strokeRect(x, y, w, h);
  }
}

function drawKeyboard(rc: PianoRollRenderContext): void {
  const { ctx, view, height, velocityLaneHeight } = rc;
  const gridBottom = height - velocityLaneHeight;

  // Keyboard background
  ctx.fillStyle = COLOR.black;
  ctx.fillRect(0, PR_RULER_HEIGHT, view.keyboardWidth, gridBottom - PR_RULER_HEIGHT);

  const topPitch = view.scrollY;
  const visibleRows = Math.ceil(
    (gridBottom - PR_RULER_HEIGHT) / view.noteHeight,
  );
  const bottomPitch = topPitch - visibleRows;

  for (let pitch = topPitch; pitch >= bottomPitch; pitch--) {
    const y = pitchToY(pitch, view, height, velocityLaneHeight);
    if (y + view.noteHeight < PR_RULER_HEIGHT || y > gridBottom) continue;

    const black = isBlackKey(pitch);

    // Key fill
    ctx.fillStyle = black ? COLOR.blackKey : COLOR.whiteKey;
    const keyWidth = black ? view.keyboardWidth * 0.6 : view.keyboardWidth - 1;
    ctx.fillRect(0, y, keyWidth, view.noteHeight);

    // Key separator
    ctx.strokeStyle = COLOR.gray700;
    ctx.lineWidth = 1;
    ctx.beginPath();
    ctx.moveTo(0, y + view.noteHeight);
    ctx.lineTo(view.keyboardWidth, y + view.noteHeight);
    ctx.stroke();

    // Label C notes
    if (pitch % 12 === 0) {
      const label = noteName(pitch);
      ctx.font = `${String(TEXT_XS)}px ${FONT_MONO}`;
      ctx.fillStyle = black ? COLOR.white : COLOR.black;
      ctx.textBaseline = "middle";
      ctx.textAlign = "left";
      ctx.fillText(label, 2, y + view.noteHeight / 2);
    }
  }

  // Keyboard right border
  ctx.strokeStyle = COLOR.gray700;
  ctx.lineWidth = BORDER_WIDTH;
  ctx.beginPath();
  ctx.moveTo(view.keyboardWidth, PR_RULER_HEIGHT);
  ctx.lineTo(view.keyboardWidth, gridBottom);
  ctx.stroke();
}

function drawVelocityLane(rc: PianoRollRenderContext): void {
  const { ctx, width, height, view, notes, velocityLaneHeight } = rc;
  const laneTop = height - velocityLaneHeight;

  // Lane background
  ctx.fillStyle = COLOR.black;
  ctx.fillRect(view.keyboardWidth, laneTop, width - view.keyboardWidth, velocityLaneHeight);

  // Separator line
  ctx.strokeStyle = COLOR.gray500;
  ctx.lineWidth = 1;
  ctx.beginPath();
  ctx.moveTo(view.keyboardWidth, laneTop);
  ctx.lineTo(width, laneTop);
  ctx.stroke();

  // Velocity bars
  for (const note of notes) {
    const x = secondsToX(note.startTime, view);
    const w = note.duration * view.pixelsPerSecond;

    if (x + w < view.keyboardWidth || x > width) continue;

    const barHeight = (note.velocity / 127) * (velocityLaneHeight - 4);
    const barY = laneTop + velocityLaneHeight - barHeight;

    ctx.fillStyle = hexToRgba(COLOR.blue, 0.8);
    ctx.fillRect(x, barY, w, barHeight);
  }
}

function drawPlayhead(rc: PianoRollRenderContext): void {
  const { ctx, height, view, cursorSeconds } = rc;
  const x = secondsToX(cursorSeconds, view);

  if (x < view.keyboardWidth || x > rc.width) return;

  ctx.strokeStyle = COLOR.red;
  ctx.lineWidth = 2;
  ctx.beginPath();
  ctx.moveTo(x, 0);
  ctx.lineTo(x, height);
  ctx.stroke();
}

function drawRuler(rc: PianoRollRenderContext): void {
  const { ctx, width, view, bpm } = rc;
  const secPerBeat = 60 / bpm;
  const secPerBar = secPerBeat * 4;

  // Ruler background
  ctx.fillStyle = COLOR.black;
  ctx.fillRect(0, 0, width, PR_RULER_HEIGHT);

  // Bar labels
  ctx.font = `${String(TEXT_XS)}px ${FONT_MONO}`;
  ctx.fillStyle = COLOR.gray500;
  ctx.textBaseline = "middle";
  ctx.textAlign = "center";

  const startBar = Math.max(0, Math.floor(view.scrollX / secPerBar));
  const endSec =
    view.scrollX + (width - view.keyboardWidth) / view.pixelsPerSecond;
  const endBar = Math.ceil(endSec / secPerBar) + 1;

  for (let bar = startBar; bar < endBar; bar++) {
    const x = secondsToX(bar * secPerBar, view);
    if (x >= view.keyboardWidth && x <= width) {
      ctx.fillText(String(bar + 1), x, PR_RULER_HEIGHT / 2);
    }
  }
}

// -- Public API ---------------------------------------------------------------

export function renderPianoRoll(rc: PianoRollRenderContext): void {
  drawBackground(rc);
  drawNoteGrid(rc);
  drawTimeGrid(rc);
  drawNotes(rc);
  drawKeyboard(rc);
  drawVelocityLane(rc);
  drawPlayhead(rc);
  drawRuler(rc);
}

/**
 * MIDI input validation and clamping.
 * NFR-16: All MIDI input values clamped to valid ranges.
 * All external input treated as untrusted.
 */

// -- Validated message types --

export type ValidatedNoteOn = {
  readonly type: "note-on";
  readonly note: number; // 0-127
  readonly velocity: number; // 1-127 (0 is note-off)
  readonly channel: number; // 0-15
};

export type ValidatedNoteOff = {
  readonly type: "note-off";
  readonly note: number; // 0-127
  readonly channel: number; // 0-15
};

export type ValidatedCC = {
  readonly type: "cc";
  readonly controller: number; // 0-127
  readonly value: number; // 0-127
  readonly channel: number; // 0-15
};

export type ValidatedPitchBend = {
  readonly type: "pitch-bend";
  readonly value: number; // 0-16383
  readonly channel: number; // 0-15
};

export type ValidatedMidiMessage =
  | ValidatedNoteOn
  | ValidatedNoteOff
  | ValidatedCC
  | ValidatedPitchBend;

export type MidiValidationResult =
  | { readonly valid: true; readonly message: ValidatedMidiMessage }
  | { readonly valid: false; readonly reason: string };

// -- Constants --

const SYSEX_MAX_BYTES = 1024; // 1 KB
const SYSEX_START = 0xf0;
const SYSEX_END = 0xf7;

// Status byte high nibble ranges
const NOTE_OFF_MIN = 0x80;
const NOTE_OFF_MAX = 0x8f;
const NOTE_ON_MIN = 0x90;
const NOTE_ON_MAX = 0x9f;
const CC_MIN = 0xb0;
const CC_MAX = 0xbf;
const PITCH_BEND_MIN = 0xe0;
const PITCH_BEND_MAX = 0xef;

// -- Clamp functions --

/** Clamp a value to 7-bit MIDI range (0-127). */
export function clampMidi7Bit(value: number): number {
  return Math.min(127, Math.max(0, Math.floor(value)));
}

/** Clamp a value to 14-bit MIDI range (0-16383). */
export function clampMidi14Bit(value: number): number {
  return Math.min(16383, Math.max(0, Math.floor(value)));
}

// -- Validation --

/** Validate raw MIDI bytes (Uint8Array) from Web MIDI API. */
export function validateMidiMessage(data: Uint8Array): MidiValidationResult {
  if (data.length === 0) {
    return { valid: false, reason: "Empty MIDI message" };
  }

  const status = data[0]!;
  const channel = status & 0x0f;

  if (status >= NOTE_OFF_MIN && status <= NOTE_OFF_MAX) {
    if (data.length < 3)
      return { valid: false, reason: "Note Off requires 3 bytes" };
    return {
      valid: true,
      message: {
        type: "note-off",
        note: clampMidi7Bit(data[1]!),
        channel,
      },
    };
  }

  if (status >= NOTE_ON_MIN && status <= NOTE_ON_MAX) {
    if (data.length < 3)
      return { valid: false, reason: "Note On requires 3 bytes" };
    const note = clampMidi7Bit(data[1]!);
    const velocity = clampMidi7Bit(data[2]!);
    // Note-on with velocity 0 is conventionally note-off
    if (velocity === 0) {
      return { valid: true, message: { type: "note-off", note, channel } };
    }
    return {
      valid: true,
      message: { type: "note-on", note, velocity, channel },
    };
  }

  if (status >= CC_MIN && status <= CC_MAX) {
    if (data.length < 3)
      return { valid: false, reason: "CC requires 3 bytes" };
    return {
      valid: true,
      message: {
        type: "cc",
        controller: clampMidi7Bit(data[1]!),
        value: clampMidi7Bit(data[2]!),
        channel,
      },
    };
  }

  if (status >= PITCH_BEND_MIN && status <= PITCH_BEND_MAX) {
    if (data.length < 3)
      return { valid: false, reason: "Pitch Bend requires 3 bytes" };
    const lsb = clampMidi7Bit(data[1]!);
    const msb = clampMidi7Bit(data[2]!);
    return {
      valid: true,
      message: {
        type: "pitch-bend",
        value: clampMidi14Bit(msb * 128 + lsb),
        channel,
      },
    };
  }

  return {
    valid: false,
    reason: `Unsupported MIDI status byte: 0x${status.toString(16)}`,
  };
}

/** Validate SysEx message size (max 1KB) and framing. */
export function validateSysEx(
  data: Uint8Array,
): { valid: boolean; reason?: string } {
  if (data.length === 0) {
    return { valid: false, reason: "Empty SysEx message" };
  }
  if (data[0] !== SYSEX_START) {
    return { valid: false, reason: "SysEx must start with 0xF0" };
  }
  if (data[data.length - 1] !== SYSEX_END) {
    return { valid: false, reason: "SysEx must end with 0xF7" };
  }
  if (data.length > SYSEX_MAX_BYTES) {
    return {
      valid: false,
      reason: `SysEx exceeds max size: ${data.length} > ${SYSEX_MAX_BYTES} bytes`,
    };
  }
  return { valid: true };
}

/**
 * Live MIDI recording -- captures validated MIDI messages into MIDINoteEvents.
 * Uses an open-note map to pair note-on/note-off events.
 */

import type { MIDINoteEvent } from "@state/track/types";
import type { ValidatedMidiMessage } from "./midi-input-validator";

export type MidiRecorderState = "idle" | "armed" | "recording";

export type MidiRecorder = {
  readonly state: MidiRecorderState;
  arm(): void;
  startRecording(transportTimeSeconds: number): void;
  recordMessage(
    message: ValidatedMidiMessage,
    transportTimeSeconds: number,
  ): void;
  stopRecording(): readonly MIDINoteEvent[];
  disarm(): void;
};

type OpenNote = {
  readonly id: string;
  readonly pitch: number;
  readonly velocity: number;
  readonly startTime: number; // relative to recording start
  readonly startAbsolute: number; // absolute transport time
};

let nextNoteId = 0;
function generateNoteId(): string {
  return `rec-${Date.now()}-${nextNoteId++}`;
}

export function createMidiRecorder(): MidiRecorder {
  let currentState: MidiRecorderState = "idle";
  let recordingStartTime = 0;
  let lastMessageTime = 0;
  const openNotes = new Map<number, OpenNote>(); // keyed by pitch
  const completedNotes: MIDINoteEvent[] = [];

  function reset(): void {
    openNotes.clear();
    completedNotes.length = 0;
    recordingStartTime = 0;
    lastMessageTime = 0;
  }

  return {
    get state(): MidiRecorderState {
      return currentState;
    },

    arm(): void {
      currentState = "armed";
    },

    startRecording(transportTimeSeconds: number): void {
      if (currentState !== "armed") return;
      currentState = "recording";
      recordingStartTime = transportTimeSeconds;
      lastMessageTime = transportTimeSeconds;
      reset();
      // Keep state as recording after reset
      // (reset clears notes/times but not state)
    },

    recordMessage(
      message: ValidatedMidiMessage,
      transportTimeSeconds: number,
    ): void {
      if (currentState !== "recording") return;
      lastMessageTime = transportTimeSeconds;

      if (message.type === "note-on") {
        openNotes.set(message.note, {
          id: generateNoteId(),
          pitch: message.note,
          velocity: message.velocity,
          startTime: transportTimeSeconds - recordingStartTime,
          startAbsolute: transportTimeSeconds,
        });
      } else if (message.type === "note-off") {
        const open = openNotes.get(message.note);
        if (open) {
          completedNotes.push({
            id: open.id,
            pitch: open.pitch,
            velocity: open.velocity,
            startTime: open.startTime,
            duration: transportTimeSeconds - open.startAbsolute,
          });
          openNotes.delete(message.note);
        }
      }
      // CC and pitch-bend are ignored for note recording
    },

    stopRecording(): readonly MIDINoteEvent[] {
      if (currentState !== "recording") return [];

      // Close any open notes at the last known message time
      for (const open of openNotes.values()) {
        completedNotes.push({
          id: open.id,
          pitch: open.pitch,
          velocity: open.velocity,
          startTime: open.startTime,
          duration: lastMessageTime - open.startAbsolute,
        });
      }
      openNotes.clear();

      const result = [...completedNotes];
      completedNotes.length = 0;
      currentState = "idle";
      return result;
    },

    disarm(): void {
      currentState = "idle";
      reset();
    },
  };
}

/**
 * Web MIDI API device manager.
 * R-OPT-01: Accept MIDI note and CC messages from connected input devices.
 */

import {
  validateMidiMessage,
  type ValidatedMidiMessage,
} from "./midi-input-validator";

export type MidiDeviceInfo = {
  readonly id: string;
  readonly name: string;
  readonly manufacturer: string;
  readonly state: "connected" | "disconnected";
};

export type MidiDeviceCallback = (message: ValidatedMidiMessage) => void;

export type MidiDeviceManager = {
  initialize(): Promise<boolean>;
  getInputDevices(): readonly MidiDeviceInfo[];
  onMessage(callback: MidiDeviceCallback): () => void;
  connectDevice(deviceId: string): boolean;
  disconnect(): void;
  dispose(): void;
};

export function createMidiDeviceManager(): MidiDeviceManager {
  let midiAccess: MIDIAccess | null = null;
  let connectedInput: MIDIInput | null = null;
  const listeners = new Set<MidiDeviceCallback>();

  function handleMidiMessage(event: MIDIMessageEvent): void {
    if (!event.data) return;
    const result = validateMidiMessage(event.data);
    if (!result.valid) return;
    for (const cb of listeners) {
      cb(result.message);
    }
  }

  function handleStateChange(): void {
    // Re-check connection state; if connected device is disconnected, clean up
    if (connectedInput && connectedInput.state === "disconnected") {
      connectedInput.onmidimessage = null;
      connectedInput = null;
    }
  }

  return {
    async initialize(): Promise<boolean> {
      if (typeof navigator === "undefined" || !navigator.requestMIDIAccess) {
        return false;
      }
      try {
        midiAccess = await navigator.requestMIDIAccess();
        midiAccess.onstatechange = handleStateChange;
        return true;
      } catch {
        return false;
      }
    },

    getInputDevices(): readonly MidiDeviceInfo[] {
      if (!midiAccess) return [];
      const devices: MidiDeviceInfo[] = [];
      for (const input of midiAccess.inputs.values()) {
        devices.push({
          id: input.id,
          name: input.name ?? "Unknown",
          manufacturer: input.manufacturer ?? "Unknown",
          state: input.state,
        });
      }
      return devices;
    },

    onMessage(callback: MidiDeviceCallback): () => void {
      listeners.add(callback);
      return () => {
        listeners.delete(callback);
      };
    },

    connectDevice(deviceId: string): boolean {
      if (!midiAccess) return false;
      const input = midiAccess.inputs.get(deviceId);
      if (!input) return false;

      // Disconnect previous
      if (connectedInput) {
        connectedInput.onmidimessage = null;
      }

      connectedInput = input;
      connectedInput.onmidimessage = handleMidiMessage;
      return true;
    },

    disconnect(): void {
      if (connectedInput) {
        connectedInput.onmidimessage = null;
        connectedInput = null;
      }
    },

    dispose(): void {
      if (connectedInput) {
        connectedInput.onmidimessage = null;
        connectedInput = null;
      }
      listeners.clear();
      if (midiAccess) {
        midiAccess.onstatechange = null;
        midiAccess = null;
      }
    },
  };
}

export {
  validateMidiMessage,
  validateSysEx,
  clampMidi7Bit,
  clampMidi14Bit,
} from "./midi-input-validator";
export type {
  ValidatedNoteOn,
  ValidatedNoteOff,
  ValidatedCC,
  ValidatedPitchBend,
  ValidatedMidiMessage,
  MidiValidationResult,
} from "./midi-input-validator";
export { createMidiDeviceManager } from "./midi-device-manager";
export type {
  MidiDeviceInfo,
  MidiDeviceCallback,
  MidiDeviceManager,
} from "./midi-device-manager";
export { createMidiRecorder } from "./midi-recorder";
export type { MidiRecorderState, MidiRecorder } from "./midi-recorder";

