For canvas tests, create a mock CanvasRenderingContext2D that records calls:
```typescript
function createMockContext() {
  const calls: Array<{ method: string; args: unknown[] }> = [];
  const handler: ProxyHandler<Record<string, unknown>> = {
    get(target, prop) {
      if (prop === "__calls") return calls;
      if (typeof prop === "string") {
        if (!(prop in target)) {
          target[prop] = (...args: unknown[]) => {
            calls.push({ method: prop, args });
          };
        }
        return target[prop];
      }
      return undefined;
    },
    set(target, prop, value) {
      calls.push({ method: `set:${String(prop)}`, args: [value] });
      target[prop as string] = value;
      return true;
    },
  };
  return new Proxy({} as Record<string, unknown>, handler) as unknown as CanvasRenderingContext2D & { __calls: typeof calls };
}
```

