76	export function validateMidiMessage(data: Uint8Array): MidiValidationResult {
77	  if (data.length === 0) {
78	    return { valid: false, reason: "Empty MIDI message" };
79	  }
80	
81	  const status = data[0]!;
82	  const channel = status & 0x0f;
83	
84	  if (status >= NOTE_OFF_MIN && status <= NOTE_OFF_MAX) {
85	    if (data.length < 3)
86	      return { valid: false, reason: "Note Off requires 3 bytes" };
87	    return {
88	      valid: true,
89	      message: {
90	        type: "note-off",
91	        note: clampMidi7Bit(data[1]!),
92	        channel,
93	      },
94	    };
95	  }
96	
97	  if (status >= NOTE_ON_MIN && status <= NOTE_ON_MAX) {
98	    if (data.length < 3)
99	      return { valid: false, reason: "Note On requires 3 bytes" };
100	    const note = clampMidi7Bit(data[1]!);
101	    const velocity = clampMidi7Bit(data[2]!);
102	    // Note-on with velocity 0 is conventionally note-off
103	    if (velocity === 0) {
104	      return { valid: true, message: { type: "note-off", note, channel } };
105	    }
106	    return {
107	      valid: true,
108	      message: { type: "note-on", note, velocity, channel },
109	    };
110	  }
111	
112	  if (status >= CC_MIN && status <= CC_MAX) {
113	    if (data.length < 3) return { valid: false, reason: "CC requires 3 bytes" };
114	    return {
115	      valid: true,
116	      message: {
117	        type: "cc",
118	        controller: clampMidi7Bit(data[1]!),
119	        value: clampMidi7Bit(data[2]!),
120	        channel,
121	      },
122	    };
123	  }
124	
125	  if (status >= PITCH_BEND_MIN && status <= PITCH_BEND_MAX) {
126	    if (data.length < 3)
