128	    const lsb = clampMidi7Bit(data[1]!);
129	    const msb = clampMidi7Bit(data[2]!);
130	    return {
131	      valid: true,
132	      message: {
133	        type: "pitch-bend",
134	        value: clampMidi14Bit(msb * 128 + lsb),
135	        channel,
136	      },
137	    };
138	  }
139	
