149	function drawTimeGrid(rc: PianoRollRenderContext): void {
150	  const { ctx, width, height, view, bpm, velocityLaneHeight } = rc;
151	  const secPerBeat = 60 / bpm;
152	  const secPerBar = secPerBeat * 4;
153	  const gridBottom = height - velocityLaneHeight;
154	
155	  const startSec = view.scrollX;
156	  const endSec =
157	    view.scrollX + (width - view.keyboardWidth) / view.pixelsPerSecond;
158	
159	  // Determine grid step -- skip beats when zoomed out too far
160	  const minPxPerLine = 12;
161	  let step = secPerBeat;
162	  while (step * view.pixelsPerSecond < minPxPerLine) {
163	    step *= 2;
164	  }
165	
166	  const firstBeat = Math.floor(startSec / step) * step;
167	
168	  ctx.save();
169	  for (let t = firstBeat; t <= endSec; t += step) {
170	    const x = secondsToX(t, view);
171	    if (x < view.keyboardWidth || x > width) continue;
172	
173	    const nearestBar = Math.round(t / secPerBar) * secPerBar;
174	    const isBar = Math.abs(t - nearestBar) < 0.001;
175	    ctx.strokeStyle = COLOR.gray700;
176	    ctx.lineWidth = isBar ? 2 : 1;
177	
178	    ctx.beginPath();
179	    ctx.moveTo(x, PR_RULER_HEIGHT);
180	    ctx.lineTo(x, gridBottom);
181	    ctx.stroke();
182	  }
183	  ctx.restore();
184	}
