Hit testing for the piano roll canvas:

```typescript
import type { MIDINoteEvent } from "@state/track/types";
import type { PianoRollViewState } from "./piano-roll-renderer";
import { PR_RULER_HEIGHT } from "./constants";

// Reuse GridSnap from arrangement or define piano-roll specific one with triplets
export type PianoRollGridSnap = "1/4" | "1/8" | "1/16" | "1/8T" | "1/16T";

export type PianoRollHitResult =
  | { kind: "none" }
  | { kind: "note-body"; noteId: string }
  | { kind: "note-left-edge"; noteId: string }
  | { kind: "note-right-edge"; noteId: string }
  | { kind: "velocity-bar"; noteId: string }
  | { kind: "keyboard-key"; pitch: number }
  | { kind: "ruler"; timeSeconds: number }
  | { kind: "empty-grid"; pitch: number; timeSeconds: number };

// Trim handle detection threshold
const EDGE_HANDLE_PX = 6;

export function xToSeconds(x: number, view: PianoRollViewState): number {
  return view.scrollX + (x - view.keyboardWidth) / view.pixelsPerSecond;
}

export function yToPitch(y: number, view: PianoRollViewState): number {
  return Math.round(view.scrollY - (y - PR_RULER_HEIGHT) / view.noteHeight);
}

export function pianoRollSnapToGrid(seconds: number, bpm: number, snap: PianoRollGridSnap): number {
  const secPerBeat = 60 / bpm;
  let gridSize: number;
  switch (snap) {
    case "1/4": gridSize = secPerBeat; break;
    case "1/8": gridSize = secPerBeat / 2; break;
    case "1/16": gridSize = secPerBeat / 4; break;
    case "1/8T": gridSize = secPerBeat / 3; break;      // triplet eighth
    case "1/16T": gridSize = secPerBeat / 6; break;      // triplet sixteenth
  }
  return Math.round(seconds / gridSize) * gridSize;
}

export function pianoRollHitTest(
  x: number,
  y: number,
  view: PianoRollViewState,
  notes: readonly MIDINoteEvent[],
  canvasHeight: number,
  velocityLaneHeight: number,
): PianoRollHitResult {
  // Ruler area
  if (y < PR_RULER_HEIGHT) {
    return { kind: "ruler", timeSeconds: xToSeconds(x, view) };
  }

  // Keyboard area
  if (x < view.keyboardWidth) {
    const pitch = yToPitch(y, view);
    return { kind: "keyboard-key", pitch };
  }

  // Velocity lane area
  const velocityLaneTop = canvasHeight - velocityLaneHeight;
  if (y >= velocityLaneTop) {
    // Check if clicking on a velocity bar
    for (let i = notes.length - 1; i >= 0; i--) {
      const note = notes[i];
      if (!note) continue;
      const noteX = secondsToX(note.startTime, view);  // import from renderer
      const noteW = note.duration * view.pixelsPerSecond;
      if (x >= noteX && x <= noteX + noteW) {
        return { kind: "velocity-bar", noteId: note.id };
      }
    }
    return { kind: "none" };
  }

  // Note grid area - check notes in reverse for z-order
  for (let i = notes.length - 1; i >= 0; i--) {
    const note = notes[i];
    if (!note) continue;
    const noteX = secondsToX(note.startTime, view);
    const noteW = note.duration * view.pixelsPerSecond;
    const noteY = PR_RULER_HEIGHT + (view.scrollY - note.pitch) * view.noteHeight;
    const noteH = view.noteHeight;

    if (x >= noteX && x <= noteX + noteW && y >= noteY && y <= noteY + noteH) {
      // Left edge handle
      if (x - noteX < EDGE_HANDLE_PX) {
        return { kind: "note-left-edge", noteId: note.id };
      }
      // Right edge handle
      if (noteX + noteW - x < EDGE_HANDLE_PX) {
        return { kind: "note-right-edge", noteId: note.id };
      }
      return { kind: "note-body", noteId: note.id };
    }
  }

  // Empty grid - calculate pitch and time at click point
  const pitch = yToPitch(y, view);
  const timeSeconds = xToSeconds(x, view);
  return { kind: "empty-grid", pitch, timeSeconds };
}

// Rubber-band lasso selection: returns IDs of notes within the rectangle
export function lassoSelectNotes(
  startX: number, startY: number, endX: number, endY: number,
  view: PianoRollViewState,
  notes: readonly MIDINoteEvent[],
): readonly string[] {
  const left = Math.min(startX, endX);
  const right = Math.max(startX, endX);
  const top = Math.min(startY, endY);
  const bottom = Math.max(startY, endY);

  return notes.filter((note) => {
    const noteX = secondsToX(note.startTime, view);
    const noteW = note.duration * view.pixelsPerSecond;
    const noteY = PR_RULER_HEIGHT + (view.scrollY - note.pitch) * view.noteHeight;
    const noteH = view.noteHeight;

    // Note must overlap the lasso rectangle
    return noteX + noteW > left && noteX < right && noteY + noteH > top && noteY < bottom;
  }).map((n) => n.id);
}
```

Import `secondsToX` from the renderer: `import { secondsToX } from "./piano-roll-renderer";`

### 2. `src/ui/piano-roll/piano-roll-hit-test.test.ts`

Write comprehensive tests FIRST:

```
- xToSeconds() converts pixel to seconds correctly
- yToPitch() converts pixel to pitch correctly (higher Y = lower pitch)
- pianoRollSnapToGrid() snaps to 1/4 note
- pianoRollSnapToGrid() snaps to 1/8 note
- pianoRollSnapToGrid() snaps to 1/16 note
- pianoRollSnapToGrid() snaps to 1/8 triplet
- pianoRollSnapToGrid() snaps to 1/16 triplet
- pianoRollHitTest() returns "ruler" for clicks above PR_RULER_HEIGHT
- pianoRollHitTest() returns "keyboard-key" for clicks in keyboard area
- pianoRollHitTest() returns "note-body" for clicks on a note
- pianoRollHitTest() returns "note-left-edge" for clicks near left edge of note
- pianoRollHitTest() returns "note-right-edge" for clicks near right edge of note
- pianoRollHitTest() returns "velocity-bar" for clicks in velocity lane on a note's x range
- pianoRollHitTest() returns "empty-grid" with correct pitch and time for clicks on empty area
- pianoRollHitTest() returns "none" for clicks in velocity lane outside any note
- pianoRollHitTest() prioritizes later notes (reverse z-order)
- lassoSelectNotes() selects notes within rectangle
- lassoSelectNotes() returns empty for rectangle with no notes
- lassoSelectNotes() handles inverted rectangle (start > end)
```

