1	/** Shared layout constants for the piano roll view. */
2	export const PR_RULER_HEIGHT = 24;
3	export const PR_KEYBOARD_WIDTH = 48;
4	export const PR_DEFAULT_NOTE_HEIGHT = 16;
5	export const PR_VELOCITY_LANE_HEIGHT = 60;
6	export const PR_NOTE_PADDING = 1;
7	export const PR_DEFAULT_PPS = 100; // pixels per second
8	export const PR_DEFAULT_SCROLL_Y = 84; // Start at C5 area
9	export const PR_MIN_NOTE = 0;
10	export const PR_MAX_NOTE = 127;
