1	import { useCallback, useEffect, useRef, useState } from "react";
2	import { useDawStore } from "@state/store";
3	import {
4	  renderArrangement,
5	  type ArrangementViewState,
6	} from "./arrangement-renderer";
7	import { useArrangementInteractions } from "./use-arrangement-interactions";
8	import type { GridSnap } from "./hit-test";
9	import styles from "./ArrangementPanel.module.css";
10	
11	const DEFAULT_VIEW: ArrangementViewState = {
12	  scrollX: 0,
13	  scrollY: 0,
14	  pixelsPerSecond: 100,
15	  trackHeight: 64,
16	  headerWidth: 160,
17	};
18	
19	const MIN_PPS = 10;
20	const MAX_PPS = 500;
21	const ZOOM_FACTOR = 1.1;
22	
23	export function ArrangementPanel(): React.JSX.Element {
24	  const canvasRef = useRef<HTMLCanvasElement>(null);
25	  const rafRef = useRef(0);
26	  const [view, setView] = useState(DEFAULT_VIEW);
27	  const [gridSnap] = useState<GridSnap>("1/4");
28	  const interactions = useArrangementInteractions(view, gridSnap);
29	
30	  const tracks = useDawStore((s) => s.tracks);
31	  const clips = useDawStore((s) => s.clips);
32	  const selectedClipIds = useDawStore((s) => s.selectedClipIds);
33	  const cursorSeconds = useDawStore((s) => s.cursorSeconds);
34	  const bpm = useDawStore((s) => s.bpm);
35	  const transportState = useDawStore((s) => s.transportState);
36	
37	  // Render loop
38	  const render = useCallback((): void => {
39	    const canvas = canvasRef.current;
40	    if (canvas === null) return;
41	    const ctx = canvas.getContext("2d");
42	    if (ctx === null) return;
43	
44	    const rect = canvas.getBoundingClientRect();
45	    renderArrangement({
46	      ctx,
47	      width: rect.width,
48	      height: rect.height,
49	      view,
50	      tracks,
51	      clips,
52	      selectedClipIds,
53	      cursorSeconds,
54	      bpm,
55	    });
56	  }, [view, tracks, clips, selectedClipIds, cursorSeconds, bpm]);
57	
58	  // Schedule re-render when state changes or during playback
59	  useEffect(() => {
60	    const tick = (): void => {
61	      render();
62	      if (transportState === "playing") {
63	        rafRef.current = requestAnimationFrame(tick);
64	      }
65	    };
66	
67	    rafRef.current = requestAnimationFrame(tick);
68	    return (): void => {
69	      cancelAnimationFrame(rafRef.current);
70	    };
71	  }, [render, transportState]);
72	
73	  // Handle canvas sizing with ResizeObserver
74	  useEffect(() => {
75	    const canvas = canvasRef.current;
76	    if (canvas === null) return;
77	    const parent = canvas.parentElement;
78	    if (parent === null) return;
79	
80	    const resizeCanvas = (): void => {
81	      const dpr = window.devicePixelRatio;
82	      const rect = parent.getBoundingClientRect();
83	      canvas.width = rect.width * dpr;
84	      canvas.height = rect.height * dpr;
85	      canvas.style.width = `${String(rect.width)}px`;
86	      canvas.style.height = `${String(rect.height)}px`;
87	
88	      const ctx = canvas.getContext("2d");
89	      if (ctx !== null) {
90	        ctx.scale(dpr, dpr);
91	      }
92	    };
93	
94	    if (typeof ResizeObserver === "undefined") return;
95	
96	    const observer = new ResizeObserver(resizeCanvas);
97	    observer.observe(parent);
98	    resizeCanvas();
99	
100	    return (): void => {
101	      observer.disconnect();
102	    };
103	  }, []);
104	
105	  // Wheel: ctrl+wheel for zoom, plain wheel for scroll
106	  const handleWheel = useCallback(
107	    (e: React.WheelEvent<HTMLCanvasElement>): void => {
108	      e.preventDefault();
109	
110	      if (e.ctrlKey || e.metaKey) {
111	        // Zoom
112	        const factor = e.deltaY < 0 ? ZOOM_FACTOR : 1 / ZOOM_FACTOR;
113	        setView((prev) => ({
114	          ...prev,
115	          pixelsPerSecond: Math.min(
116	            MAX_PPS,
117	            Math.max(MIN_PPS, prev.pixelsPerSecond * factor),
118	          ),
119	        }));
120	      } else if (e.shiftKey) {
121	        // Horizontal scroll
122	        setView((prev) => ({
123	          ...prev,
124	          scrollX: Math.max(0, prev.scrollX + e.deltaY / prev.pixelsPerSecond),
125	        }));
126	      } else {
127	        // Vertical scroll
128	        setView((prev) => ({
129	          ...prev,
130	          scrollX: Math.max(0, prev.scrollX + e.deltaX / prev.pixelsPerSecond),
131	          scrollY: Math.max(0, prev.scrollY + e.deltaY),
132	        }));
133	      }
134	    },
135	    [],
136	  );
137	
138	  return (
139	    <section data-testid="arrangement-panel" className={styles["container"]}>
140	      <canvas
141	        ref={canvasRef}
142	        className={styles["canvas"]}
143	        style={{ cursor: interactions.cursor }}
144	        onWheel={handleWheel}
145	        onPointerDown={interactions.onPointerDown}
146	        onPointerMove={interactions.onPointerMove}
147	        onPointerUp={interactions.onPointerUp}
148	        onDoubleClick={interactions.onDoubleClick}
149	      />
150	    </section>
151	  );
152	}
