1	/**
2	 * Pointer interaction handlers for the arrangement canvas.
3	 * Manages drag operations for clip move, trim, split, and selection.
4	 * Pushes undo commands on drag completion.
5	 */
6	import { useCallback, useRef, useState } from "react";
7	import { useDawStore } from "@state/store";
8	import type { ClipModel } from "@state/track/types";
9	import { isAudioClip } from "@state/track/types";
10	import type { UndoCommand } from "@state/undo";
11	import { sharedUndoManager } from "@state/undo";
12	import { SplitClipCommand } from "@state/track/track-commands";
13	import type { ArrangementViewState } from "./arrangement-renderer";
14	import { hitTest, xToSeconds, snapToGrid, type GridSnap } from "./hit-test";
15	import { RULER_HEIGHT } from "./constants";
16	
17	type DragState =
18	  | { kind: "idle" }
19	  | {
20	      kind: "move-clip";
21	      clipId: string;
22	      originTrackId: string;
23	      startX: number;
24	      startTime: number;
25	      beforeClip: ClipModel;
26	    }
27	  | {
28	      kind: "trim-left";
29	      clipId: string;
30	      startX: number;
31	      originalStart: number;
32	      originalSourceOffset: number;
33	      originalDuration: number;
34	      beforeClip: ClipModel;
35	    }
36	  | {
37	      kind: "trim-right";
38	      clipId: string;
39	      startX: number;
40	      originalEnd: number;
41	      originalStart: number;
42	      beforeClip: ClipModel;
43	    }
44	  | {
45	      kind: "rubber-band";
46	      startX: number;
47	      startY: number;
48	    };
49	
50	export type ArrangementInteractions = {
51	  onPointerDown: (e: React.PointerEvent<HTMLCanvasElement>) => void;
52	  onPointerMove: (e: React.PointerEvent<HTMLCanvasElement>) => void;
53	  onPointerUp: (e: React.PointerEvent<HTMLCanvasElement>) => void;
54	  onDoubleClick: (e: React.MouseEvent<HTMLCanvasElement>) => void;
55	  cursor: string;
56	};
57	
58	export function useArrangementInteractions(
59	  view: ArrangementViewState,
60	  gridSnap: GridSnap,
61	): ArrangementInteractions {
62	  const dragRef = useRef<DragState>({ kind: "idle" });
63	  const [cursor, setCursor] = useState("default");
64	
65	  const getCanvasPos = useCallback(
66	    (e: React.MouseEvent<HTMLCanvasElement>): { x: number; y: number } => {
67	      const rect = e.currentTarget.getBoundingClientRect();
68	      return { x: e.clientX - rect.left, y: e.clientY - rect.top };
69	    },
70	    [],
71	  );
72	
73	  const onPointerDown = useCallback(
74	    (e: React.PointerEvent<HTMLCanvasElement>): void => {
75	      const { x, y } = getCanvasPos(e);
76	      const state = useDawStore.getState();
77	      const hit = hitTest(x, y, view, state.tracks, state.clips);
78	
79	      switch (hit.kind) {
80	        case "clip-body": {
81	          const clip = state.clips[hit.clipId];
82	          if (clip === undefined) break;
83	
84	          if (e.shiftKey) {
85	            const current = [...state.selectedClipIds];
86	            const idx = current.indexOf(hit.clipId);
87	            if (idx >= 0) {
88	              current.splice(idx, 1);
89	            } else {
90	              current.push(hit.clipId);
91	            }
92	            state.setSelectedClipIds(current);
93	          } else if (!state.selectedClipIds.includes(hit.clipId)) {
94	            state.setSelectedClipIds([hit.clipId]);
95	          }
96	
97	          e.currentTarget.setPointerCapture(e.pointerId);
98	          dragRef.current = {
99	            kind: "move-clip",
100	            clipId: hit.clipId,
101	            originTrackId: clip.trackId,
102	            startX: x,
103	            startTime: clip.startTime,
104	            beforeClip: { ...clip },
105	          };
106	          break;
107	        }
108	        case "clip-left-edge": {
109	          const clip = state.clips[hit.clipId];
110	          if (clip === undefined) break;
111	          state.setSelectedClipIds([hit.clipId]);
112	          e.currentTarget.setPointerCapture(e.pointerId);
113	          dragRef.current = {
114	            kind: "trim-left",
115	            clipId: hit.clipId,
116	            startX: x,
117	            originalStart: clip.startTime,
118	            originalSourceOffset: isAudioClip(clip) ? clip.sourceOffset : 0,
119	            originalDuration: clip.duration,
120	            beforeClip: { ...clip },
121	          };
122	          break;
123	        }
124	        case "clip-right-edge": {
125	          const clip = state.clips[hit.clipId];
126	          if (clip === undefined) break;
127	          state.setSelectedClipIds([hit.clipId]);
128	          e.currentTarget.setPointerCapture(e.pointerId);
129	          dragRef.current = {
130	            kind: "trim-right",
131	            clipId: hit.clipId,
132	            startX: x,
133	            originalEnd: clip.startTime + clip.duration,
134	            originalStart: clip.startTime,
135	            beforeClip: { ...clip },
136	          };
137	          break;
138	        }
139	        case "ruler": {
140	          state.setCursor(Math.max(0, hit.timeSeconds));
141	          break;
142	        }
143	        case "empty-lane": {
144	          if (!e.shiftKey) {
145	            state.setSelectedClipIds([]);
146	          }
147	          e.currentTarget.setPointerCapture(e.pointerId);
148	          dragRef.current = { kind: "rubber-band", startX: x, startY: y };
149	          break;
150	        }
151	        case "track-header": {
152	          if (e.shiftKey) {
153	            const current = [...state.selectedTrackIds];
154	            const idx = current.indexOf(hit.trackId);
155	            if (idx >= 0) {
156	              current.splice(idx, 1);
157	            } else {
158	              current.push(hit.trackId);
159	            }
160	            state.setSelectedTrackIds(current);
161	          } else {
162	            state.setSelectedTrackIds([hit.trackId]);
163	          }
164	          break;
165	        }
166	        case "none":
167	          break;
168	      }
169	    },
170	    [view, getCanvasPos],
171	  );
172	
173	  const onPointerMove = useCallback(
174	    (e: React.PointerEvent<HTMLCanvasElement>): void => {
175	      const { x, y } = getCanvasPos(e);
176	      const drag = dragRef.current;
177	      const state = useDawStore.getState();
178	
179	      if (drag.kind === "idle") {
180	        const hit = hitTest(x, y, view, state.tracks, state.clips);
181	        switch (hit.kind) {
182	          case "clip-left-edge":
183	          case "clip-right-edge":
184	            setCursor("ew-resize");
185	            break;
186	          case "clip-body":
187	            setCursor("grab");
188	            break;
189	          default:
190	            setCursor("default");
191	            break;
192	        }
193	        return;
194	      }
195	
196	      switch (drag.kind) {
197	        case "move-clip": {
198	          setCursor("grabbing");
199	          const deltaPx = x - drag.startX;
200	          const deltaSec = deltaPx / view.pixelsPerSecond;
201	          const newTime = snapToGrid(
202	            Math.max(0, drag.startTime + deltaSec),
203	            state.bpm,
204	            gridSnap,
205	          );
206	
207	          const trackIndex = Math.floor(
208	            (y - RULER_HEIGHT + view.scrollY) / view.trackHeight,
209	          );
210	          const targetTrack = state.tracks[trackIndex];
211	          const targetTrackId =
212	            targetTrack !== undefined ? targetTrack.id : drag.originTrackId;
213	
214	          state.moveClip(drag.clipId, newTime, targetTrackId);
215	          break;
216	        }
217	        case "trim-left": {
218	          setCursor("ew-resize");
219	          const deltaPx = x - drag.startX;
220	          const deltaSec = deltaPx / view.pixelsPerSecond;
221	          const newStart = snapToGrid(
222	            Math.max(0, drag.originalStart + deltaSec),
223	            state.bpm,
224	            gridSnap,
225	          );
226	          const maxStart = drag.originalStart + drag.originalDuration - 0.01;
227	          const clampedStart = Math.min(newStart, maxStart);
228	          state.trimClip(drag.clipId, clampedStart, undefined);
229	          break;
230	        }
231	        case "trim-right": {
232	          setCursor("ew-resize");
233	          const deltaPx = x - drag.startX;
234	          const deltaSec = deltaPx / view.pixelsPerSecond;
235	          const rawEnd = snapToGrid(
236	            Math.max(0.01, drag.originalEnd + deltaSec),
237	            state.bpm,
238	            gridSnap,
239	          );
240	          // Clamp so the end never crosses the clip's start
241	          const newEnd = Math.max(drag.originalStart + 0.01, rawEnd);
242	          state.trimClip(drag.clipId, undefined, newEnd);
243	          break;
244	        }
245	        case "rubber-band": {
246	          const left = Math.min(drag.startX, x);
247	          const right = Math.max(drag.startX, x);
248	          const top = Math.min(drag.startY, y);
249	          const bottom = Math.max(drag.startY, y);
250	
251	          const selected: string[] = [];
252	          for (let ti = 0; ti < state.tracks.length; ti++) {
253	            const track = state.tracks[ti];
254	            if (track === undefined) continue;
255	            const trackTop =
256	              RULER_HEIGHT + ti * view.trackHeight - view.scrollY;
257	            const trackBottom = trackTop + view.trackHeight;
258	            if (trackBottom < top || trackTop > bottom) continue;
259	
260	            for (const clipId of track.clipIds) {
261	              const clip = state.clips[clipId];
262	              if (clip === undefined) continue;
263	              const clipLeft =
264	                view.headerWidth +
265	                (clip.startTime - view.scrollX) * view.pixelsPerSecond;
266	              const clipRight = clipLeft + clip.duration * view.pixelsPerSecond;
267	              if (clipRight >= left && clipLeft <= right) {
268	                selected.push(clip.id);
269	              }
270	            }
271	          }
272	          state.setSelectedClipIds(selected);
273	          break;
274	        }
275	      }
276	    },
277	    [view, gridSnap, getCanvasPos],
278	  );
279	
280	  const onPointerUp = useCallback(
281	    (e: React.PointerEvent<HTMLCanvasElement>): void => {
282	      const drag = dragRef.current;
283	
284	      // Push undo commands for clip-mutating drags
285	      if (
286	        drag.kind === "move-clip" ||
287	        drag.kind === "trim-left" ||
288	        drag.kind === "trim-right"
289	      ) {
290	        const afterClip = useDawStore.getState().clips[drag.clipId];
291	        const before = drag.beforeClip;
292	
293	        if (
294	          afterClip !== undefined &&
295	          (before.startTime !== afterClip.startTime ||
296	            before.trackId !== afterClip.trackId ||
297	            before.duration !== afterClip.duration ||
298	            (isAudioClip(before) &&
299	              isAudioClip(afterClip) &&
300	              before.sourceOffset !== afterClip.sourceOffset))
301	        ) {
302	          const clipId = drag.clipId;
303	          const cmd: UndoCommand =
304	            drag.kind === "move-clip"
305	              ? {
306	                  type: "move-clip-drag",
307	                  execute() {
308	                    useDawStore
309	                      .getState()
310	                      .moveClip(clipId, afterClip.startTime, afterClip.trackId);
311	                  },
312	                  undo() {
313	                    useDawStore
314	                      .getState()
315	                      .moveClip(clipId, before.startTime, before.trackId);
316	                  },
317	                  serialize() {
318	                    return { clipId, before, after: afterClip };
319	                  },
320	                }
321	              : {
322	                  type: "trim-clip-drag",
323	                  execute() {
324	                    useDawStore.setState((s) => ({
325	                      clips: { ...s.clips, [clipId]: afterClip },
326	                    }));
327	                  },
328	                  undo() {
329	                    useDawStore.setState((s) => ({
330	                      clips: { ...s.clips, [clipId]: before },
331	                    }));
332	                  },
333	                  serialize() {
334	                    return { clipId, before, after: afterClip };
335	                  },
336	                };
337	          sharedUndoManager.push(cmd);
338	        }
339	      }
340	
341	      if (drag.kind !== "idle") {
342	        e.currentTarget.releasePointerCapture(e.pointerId);
343	      }
344	      dragRef.current = { kind: "idle" };
345	      setCursor("default");
346	    },
347	    [],
348	  );
349	
350	  const onDoubleClick = useCallback(
351	    (e: React.MouseEvent<HTMLCanvasElement>): void => {
352	      const { x, y } = getCanvasPos(e);
353	      const state = useDawStore.getState();
354	      const hit = hitTest(x, y, view, state.tracks, state.clips);
355	
356	      if (hit.kind === "clip-body") {
357	        const timeSec = xToSeconds(x, view);
358	        const cmd = new SplitClipCommand(hit.clipId, timeSec);
359	        cmd.execute();
360	        sharedUndoManager.push(cmd);
361	      }
362	    },
363	    [view, getCanvasPos],
364	  );
365	
366	  return {
367	    onPointerDown,
368	    onPointerMove,
369	    onPointerUp,
370	    onDoubleClick,
371	    cursor,
372	  };
373	}
