/**
 * Pointer interaction handlers for the piano roll canvas.
 * Manages draw, select, move, resize, erase, and lasso operations.
 * Pushes undo commands on completion.
 */
import { useCallback, useRef, useState } from "react";
import { useDawStore } from "@state/store";
import type { MIDINoteEvent } from "@state/track/types";
import { isMidiClip } from "@state/track/types";
import { sharedUndoManager } from "@state/undo";
import {
  AddNoteCommand,
  RemoveNoteCommand,
  MoveNoteCommand,
  ResizeNoteCommand,
  BatchNoteCommand,
} from "@state/track/midi-commands";
import type { PianoRollViewState, PianoRollTool } from "./piano-roll-renderer";
import {
  pianoRollHitTest,
  xToSeconds,
  yToPitch,
  pianoRollSnapToGrid,
  lassoSelectNotes,
  type PianoRollGridSnap,
} from "./piano-roll-hit-test";
import { PR_VELOCITY_LANE_HEIGHT } from "./constants";

type DragState =
  | { kind: "idle" }
  | {
      kind: "move-note";
      noteId: string;
      clipId: string;
      startX: number;
      startY: number;
      origStartTime: number;
      origPitch: number;
    }
  | {
      kind: "resize-note";
      noteId: string;
      clipId: string;
      startX: number;
      origDuration: number;
    }
  | {
      kind: "draw-note";
      clipId: string;
      noteId: string;
      startTime: number;
      pitch: number;
    }
  | { kind: "rubber-band"; startX: number; startY: number };

export type PianoRollInteractions = {
  cursor: string;
  onPointerDown: (e: React.PointerEvent<HTMLCanvasElement>) => void;
  onPointerMove: (e: React.PointerEvent<HTMLCanvasElement>) => void;
  onPointerUp: (e: React.PointerEvent<HTMLCanvasElement>) => void;
  deleteSelectedNotes: () => void;
};

let noteCounter = 0;
function generateNoteId(): string {
  noteCounter += 1;
  return `note-${String(Date.now())}-${String(noteCounter)}`;
}

function gridDuration(
  bpm: number,
  snap: PianoRollGridSnap,
): number {
  const secPerBeat = 60 / bpm;
  switch (snap) {
    case "1/4":
      return secPerBeat;
    case "1/8":
      return secPerBeat / 2;
    case "1/16":
      return secPerBeat / 4;
    case "1/8T":
      return secPerBeat / 3;
    case "1/16T":
      return secPerBeat / 6;
  }
}

export function usePianoRollInteractions(
  clipId: string | null,
  view: PianoRollViewState,
  tool: PianoRollTool,
  gridSnap: PianoRollGridSnap,
): PianoRollInteractions {
  const dragRef = useRef<DragState>({ kind: "idle" });
  const [cursor, setCursor] = useState(
    tool === "pencil" ? "crosshair" : "default",
  );

  const getCanvasPos = useCallback(
    (e: React.MouseEvent<HTMLCanvasElement>): { x: number; y: number } => {
      const rect = e.currentTarget.getBoundingClientRect();
      return { x: e.clientX - rect.left, y: e.clientY - rect.top };
    },
    [],
  );

  const getNotes = useCallback((): readonly MIDINoteEvent[] => {
    if (clipId === null) return [];
    const clip = useDawStore.getState().clips[clipId];
    if (clip === undefined || !isMidiClip(clip)) return [];
    return clip.noteEvents;
  }, [clipId]);

  const onPointerDown = useCallback(
    (e: React.PointerEvent<HTMLCanvasElement>): void => {
      if (clipId === null) return;

      const { x, y } = getCanvasPos(e);
      const state = useDawStore.getState();
      const notes = getNotes();
      const canvasHeight =
        e.currentTarget.getBoundingClientRect().height;
      const hit = pianoRollHitTest(
        x,
        y,
        view,
        notes,
        canvasHeight,
        PR_VELOCITY_LANE_HEIGHT,
      );

      switch (tool) {
        case "pencil": {
          if (hit.kind === "empty-grid") {
            const snappedTime = pianoRollSnapToGrid(
              hit.timeSeconds,
              state.bpm,
              gridSnap,
            );
            const dur = gridDuration(state.bpm, gridSnap);
            const noteId = generateNoteId();
            const note: MIDINoteEvent = {
              id: noteId,
              pitch: hit.pitch,
              velocity: 100,
              startTime: Math.max(0, snappedTime),
              duration: dur,
            };
            const cmd = new AddNoteCommand(clipId, note);
            cmd.execute();
            sharedUndoManager.push(cmd);

            e.currentTarget.setPointerCapture(e.pointerId);
            dragRef.current = {
              kind: "draw-note",
              clipId,
              noteId,
              startTime: note.startTime,
              pitch: note.pitch,
            };
          }
          break;
        }
        case "select": {
          if (hit.kind === "note-body") {
            if (e.shiftKey) {
              const current = [...state.selectedNoteIds];
              const idx = current.indexOf(hit.noteId);
              if (idx >= 0) {
                current.splice(idx, 1);
              } else {
                current.push(hit.noteId);
              }
              state.setSelectedNoteIds(current);
            } else {
              if (!state.selectedNoteIds.includes(hit.noteId)) {
                state.setSelectedNoteIds([hit.noteId]);
              }
            }

            // Find note for drag
            const note = notes.find((n) => n.id === hit.noteId);
            if (note !== undefined) {
              e.currentTarget.setPointerCapture(e.pointerId);
              dragRef.current = {
                kind: "move-note",
                noteId: hit.noteId,
                clipId,
                startX: x,
                startY: y,
                origStartTime: note.startTime,
                origPitch: note.pitch,
              };
            }
          } else if (
            hit.kind === "note-left-edge" ||
            hit.kind === "note-right-edge"
          ) {
            state.setSelectedNoteIds([hit.noteId]);
            const note = notes.find((n) => n.id === hit.noteId);
            if (note !== undefined) {
              e.currentTarget.setPointerCapture(e.pointerId);
              dragRef.current = {
                kind: "resize-note",
                noteId: hit.noteId,
                clipId,
                startX: x,
                origDuration: note.duration,
              };
            }
          } else if (hit.kind === "empty-grid") {
            if (!e.shiftKey) {
              state.setSelectedNoteIds([]);
            }
            e.currentTarget.setPointerCapture(e.pointerId);
            dragRef.current = { kind: "rubber-band", startX: x, startY: y };
          }
          break;
        }
        case "erase": {
          if (
            hit.kind === "note-body" ||
            hit.kind === "note-left-edge" ||
            hit.kind === "note-right-edge"
          ) {
            const cmd = new RemoveNoteCommand(clipId, hit.noteId);
            cmd.execute();
            sharedUndoManager.push(cmd);
          }
          break;
        }
      }
    },
    [clipId, view, tool, gridSnap, getCanvasPos, getNotes],
  );

  const onPointerMove = useCallback(
    (e: React.PointerEvent<HTMLCanvasElement>): void => {
      const { x, y } = getCanvasPos(e);
      const drag = dragRef.current;
      const state = useDawStore.getState();

      if (drag.kind === "idle") {
        // Update cursor based on hover
        if (clipId === null) {
          setCursor("default");
          return;
        }

        const notes = getNotes();
        const canvasHeight =
          e.currentTarget.getBoundingClientRect().height;
        const hit = pianoRollHitTest(
          x,
          y,
          view,
          notes,
          canvasHeight,
          PR_VELOCITY_LANE_HEIGHT,
        );

        if (tool === "pencil") {
          setCursor("crosshair");
        } else if (tool === "select") {
          switch (hit.kind) {
            case "note-body":
              setCursor("pointer");
              break;
            case "note-left-edge":
            case "note-right-edge":
              setCursor("ew-resize");
              break;
            default:
              setCursor("default");
              break;
          }
        } else {
          setCursor("default");
        }
        return;
      }

      switch (drag.kind) {
        case "move-note": {
          setCursor("grabbing");
          const deltaPx = x - drag.startX;
          const deltaSec = deltaPx / view.pixelsPerSecond;
          const newTime = pianoRollSnapToGrid(
            Math.max(0, drag.origStartTime + deltaSec),
            state.bpm,
            gridSnap,
          );
          const newPitch = yToPitch(y, view);
          state.moveNoteEvent(drag.clipId, drag.noteId, newTime, newPitch);
          break;
        }
        case "resize-note": {
          setCursor("ew-resize");
          const deltaPx = x - drag.startX;
          const deltaSec = deltaPx / view.pixelsPerSecond;
          const newDuration = Math.max(0.01, drag.origDuration + deltaSec);
          state.resizeNoteEvent(drag.clipId, drag.noteId, newDuration);
          break;
        }
        case "draw-note": {
          // Extend note duration as user drags
          const currentTime = xToSeconds(x, view);
          const snappedEnd = pianoRollSnapToGrid(
            currentTime,
            state.bpm,
            gridSnap,
          );
          const newDuration = Math.max(
            gridDuration(state.bpm, gridSnap),
            snappedEnd - drag.startTime,
          );
          state.resizeNoteEvent(drag.clipId, drag.noteId, newDuration);
          break;
        }
        case "rubber-band": {
          if (clipId === null) break;
          const notes = getNotes();
          const selected = lassoSelectNotes(
            drag.startX,
            drag.startY,
            x,
            y,
            view,
            notes,
          );
          state.setSelectedNoteIds([...selected]);
          break;
        }
      }
    },
    [clipId, view, tool, gridSnap, getCanvasPos, getNotes],
  );

  const onPointerUp = useCallback(
    (e: React.PointerEvent<HTMLCanvasElement>): void => {
      const drag = dragRef.current;

      if (drag.kind === "move-note") {
        const notes = getNotes();
        const note = notes.find((n) => n.id === drag.noteId);
        if (
          note !== undefined &&
          (note.startTime !== drag.origStartTime ||
            note.pitch !== drag.origPitch)
        ) {
          const cmd = new MoveNoteCommand(
            drag.clipId,
            drag.noteId,
            note.startTime,
            note.pitch,
          );
          // Already moved in store -- record for undo
          cmd.execute = (): void => {
            useDawStore
              .getState()
              .moveNoteEvent(
                drag.clipId,
                drag.noteId,
                note.startTime,
                note.pitch,
              );
          };
          sharedUndoManager.push(cmd);
        }
      } else if (drag.kind === "resize-note") {
        const notes = getNotes();
        const note = notes.find((n) => n.id === drag.noteId);
        if (
          note !== undefined &&
          note.duration !== drag.origDuration
        ) {
          const cmd = new ResizeNoteCommand(
            drag.clipId,
            drag.noteId,
            note.duration,
          );
          cmd.execute = (): void => {
            useDawStore
              .getState()
              .resizeNoteEvent(drag.clipId, drag.noteId, note.duration);
          };
          sharedUndoManager.push(cmd);
        }
      }

      if (drag.kind !== "idle") {
        e.currentTarget.releasePointerCapture(e.pointerId);
      }
      dragRef.current = { kind: "idle" };

      // Restore tool-appropriate cursor
      if (tool === "pencil") {
        setCursor("crosshair");
      } else {
        setCursor("default");
      }
    },
    [tool, getNotes],
  );

  const deleteSelectedNotes = useCallback((): void => {
    if (clipId === null) return;
    const state = useDawStore.getState();
    const selected = state.selectedNoteIds;
    if (selected.length === 0) return;

    const commands = selected.map(
      (noteId) => new RemoveNoteCommand(clipId, noteId),
    );
    const batch = new BatchNoteCommand(commands);
    batch.execute();
    sharedUndoManager.push(batch);
    state.setSelectedNoteIds([]);
  }, [clipId]);

  return {
    cursor,
    onPointerDown,
    onPointerMove,
    onPointerUp,
    deleteSelectedNotes,
  };
}

import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import { useDawStore } from "@state/store";
import { isMidiClip } from "@state/track/types";
import { CommandRegistry } from "@ui/keyboard/command-registry";
import { ShortcutMap } from "@ui/keyboard/shortcut-map";
import { useKeyboardShortcuts } from "@ui/keyboard/useKeyboardShortcuts";
import {
  renderPianoRoll,
  type PianoRollViewState,
  type PianoRollTool,
} from "./piano-roll-renderer";
import type { PianoRollGridSnap } from "./piano-roll-hit-test";
import { usePianoRollInteractions } from "./use-piano-roll-interactions";
import {
  PR_DEFAULT_NOTE_HEIGHT,
  PR_KEYBOARD_WIDTH,
  PR_DEFAULT_PPS,
  PR_DEFAULT_SCROLL_Y,
  PR_VELOCITY_LANE_HEIGHT,
} from "./constants";
import styles from "./PianoRollEditor.module.css";

const DEFAULT_VIEW: PianoRollViewState = {
  scrollX: 0,
  scrollY: PR_DEFAULT_SCROLL_Y,
  pixelsPerSecond: PR_DEFAULT_PPS,
  noteHeight: PR_DEFAULT_NOTE_HEIGHT,
  keyboardWidth: PR_KEYBOARD_WIDTH,
};

const MIN_PPS = 20;
const MAX_PPS = 500;
const ZOOM_FACTOR = 1.1;

const SNAP_OPTIONS: readonly PianoRollGridSnap[] = [
  "1/4",
  "1/8",
  "1/16",
  "1/8T",
  "1/16T",
];

type PianoRollEditorProps = {
  clipId: string | null;
  onNotePreview?: (note: number, velocity: number) => void;
  onNotePreviewEnd?: (note: number) => void;
};

export function PianoRollEditor({
  clipId,
  onNotePreview: _onNotePreview,
  onNotePreviewEnd: _onNotePreviewEnd,
}: PianoRollEditorProps): React.JSX.Element {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const rafRef = useRef(0);
  const [tool, setTool] = useState<PianoRollTool>("pencil");
  const [gridSnap, setGridSnap] = useState<PianoRollGridSnap>("1/8");
  const [view, setView] = useState<PianoRollViewState>(DEFAULT_VIEW);

  const interactions = usePianoRollInteractions(clipId, view, tool, gridSnap);

  // Store selectors
  const clips = useDawStore((s) => s.clips);
  const selectedNoteIds = useDawStore((s) => s.selectedNoteIds);
  const cursorSeconds = useDawStore((s) => s.cursorSeconds);
  const bpm = useDawStore((s) => s.bpm);
  const transportState = useDawStore((s) => s.transportState);

  // Derive clip data
  const clip = clipId !== null ? clips[clipId] : undefined;
  const notes =
    clip !== undefined && isMidiClip(clip) ? clip.noteEvents : [];
  const clipStartTime =
    clip !== undefined ? clip.startTime : 0;
  const clipDuration = clip !== undefined ? clip.duration : 4;

  // Keyboard commands
  const registry = useMemo(() => {
    const reg = new CommandRegistry();
    reg.register({
      id: "piano-roll.tool.pencil",
      label: "Pencil Tool",
      execute: () => setTool("pencil"),
    });
    reg.register({
      id: "piano-roll.tool.select",
      label: "Select Tool",
      execute: () => setTool("select"),
    });
    reg.register({
      id: "piano-roll.tool.erase",
      label: "Erase Tool",
      execute: () => setTool("erase"),
    });
    reg.register({
      id: "piano-roll.delete-selected",
      label: "Delete Selected Notes",
      execute: () => interactions.deleteSelectedNotes(),
    });
    return reg;
  }, [interactions]);

  const shortcuts = useMemo(() => {
    const map = new ShortcutMap();
    map.bind({ key: "p", commandId: "piano-roll.tool.pencil" });
    map.bind({ key: "s", commandId: "piano-roll.tool.select" });
    map.bind({ key: "e", commandId: "piano-roll.tool.erase" });
    map.bind({ key: "Delete", commandId: "piano-roll.delete-selected" });
    map.bind({ key: "Backspace", commandId: "piano-roll.delete-selected" });
    return map;
  }, []);

  useKeyboardShortcuts(registry, shortcuts);

  // Render loop
  const render = useCallback((): void => {
    const canvas = canvasRef.current;
    if (canvas === null) return;
    const ctx = canvas.getContext("2d");
    if (ctx === null) return;

    const rect = canvas.getBoundingClientRect();
    renderPianoRoll({
      ctx,
      width: rect.width,
      height: rect.height,
      view,
      notes,
      selectedNoteIds: [...selectedNoteIds],
      cursorSeconds,
      bpm,
      clipStartTime,
      clipDuration,
      tool,
      velocityLaneHeight: PR_VELOCITY_LANE_HEIGHT,
    });
  }, [
    view,
    notes,
    selectedNoteIds,
    cursorSeconds,
    bpm,
    clipStartTime,
    clipDuration,
    tool,
  ]);

  // RAF scheduling
  useEffect(() => {
    const tick = (): void => {
      render();
      if (transportState === "playing") {
        rafRef.current = requestAnimationFrame(tick);
      }
    };

    rafRef.current = requestAnimationFrame(tick);
    return (): void => {
      cancelAnimationFrame(rafRef.current);
    };
  }, [render, transportState]);

  // Canvas sizing with ResizeObserver
  useEffect(() => {
    const canvas = canvasRef.current;
    if (canvas === null) return;
    const parent = canvas.parentElement;
    if (parent === null) return;

    const resizeCanvas = (): void => {
      const dpr = window.devicePixelRatio;
      const rect = parent.getBoundingClientRect();
      canvas.width = rect.width * dpr;
      canvas.height = rect.height * dpr;
      canvas.style.width = `${String(rect.width)}px`;
      canvas.style.height = `${String(rect.height)}px`;

      const ctx = canvas.getContext("2d");
      if (ctx !== null) {
        ctx.scale(dpr, dpr);
      }
    };

    if (typeof ResizeObserver === "undefined") return;

    const observer = new ResizeObserver(resizeCanvas);
    observer.observe(parent);
    resizeCanvas();

    return (): void => {
      observer.disconnect();
    };
  }, []);

  // Wheel: ctrl+wheel for zoom, plain wheel for scroll
  const handleWheel = useCallback(
    (e: React.WheelEvent<HTMLCanvasElement>): void => {
      e.preventDefault();

      if (e.ctrlKey || e.metaKey) {
        const factor = e.deltaY < 0 ? ZOOM_FACTOR : 1 / ZOOM_FACTOR;
        setView((prev) => ({
          ...prev,
          pixelsPerSecond: Math.min(
            MAX_PPS,
            Math.max(MIN_PPS, prev.pixelsPerSecond * factor),
          ),
        }));
      } else if (e.shiftKey) {
        setView((prev) => ({
          ...prev,
          scrollX: Math.max(0, prev.scrollX + e.deltaY / prev.pixelsPerSecond),
        }));
      } else {
        setView((prev) => ({
          ...prev,
          scrollX: Math.max(0, prev.scrollX + e.deltaX / prev.pixelsPerSecond),
          scrollY: prev.scrollY - e.deltaY / prev.noteHeight,
        }));
      }
    },
    [],
  );

  return (
    <section data-testid="piano-roll-editor" className={styles["container"]}>
      <div className={styles["toolbar"]}>
        <button
          data-testid="tool-pencil"
          className={styles["toolButton"]}
          data-active={String(tool === "pencil")}
          onClick={() => setTool("pencil")}
        >
          Pencil
        </button>
        <button
          data-testid="tool-select"
          className={styles["toolButton"]}
          data-active={String(tool === "select")}
          onClick={() => setTool("select")}
        >
          Select
        </button>
        <button
          data-testid="tool-erase"
          className={styles["toolButton"]}
          data-active={String(tool === "erase")}
          onClick={() => setTool("erase")}
        >
          Erase
        </button>
        <select
          data-testid="snap-select"
          className={styles["snapSelect"]}
          value={gridSnap}
          onChange={(e) =>
            setGridSnap(e.target.value as PianoRollGridSnap)
          }
        >
          {SNAP_OPTIONS.map((opt) => (
            <option key={opt} value={opt}>
              {opt}
            </option>
          ))}
        </select>
      </div>
      <div className={styles["canvasWrapper"]}>
        <canvas
          ref={canvasRef}
          className={styles["canvas"]}
          style={{ cursor: interactions.cursor }}
          onWheel={handleWheel}
          onPointerDown={interactions.onPointerDown}
          onPointerMove={interactions.onPointerMove}
          onPointerUp={interactions.onPointerUp}
        />
      </div>
    </section>
  );
}

export { PianoRollEditor } from "./PianoRollEditor";
export type { PianoRollViewState, PianoRollTool } from "./piano-roll-renderer";
export { renderPianoRoll, isBlackKey, noteName } from "./piano-roll-renderer";
export type {
