1	import { useCallback, useEffect, useMemo, useRef, useState } from "react";
2	import { useDawStore } from "@state/store";
3	import { isMidiClip } from "@state/track/types";
4	import { CommandRegistry } from "@ui/keyboard/command-registry";
5	import { ShortcutMap } from "@ui/keyboard/shortcut-map";
6	import { useKeyboardShortcuts } from "@ui/keyboard/useKeyboardShortcuts";
7	import {
8	  renderPianoRoll,
9	  type PianoRollViewState,
10	  type PianoRollTool,
11	} from "./piano-roll-renderer";
12	import type { PianoRollGridSnap } from "./piano-roll-hit-test";
13	import { usePianoRollInteractions } from "./use-piano-roll-interactions";
14	import {
15	  PR_DEFAULT_NOTE_HEIGHT,
16	  PR_KEYBOARD_WIDTH,
17	  PR_DEFAULT_PPS,
18	  PR_DEFAULT_SCROLL_Y,
19	  PR_VELOCITY_LANE_HEIGHT,
20	} from "./constants";
21	import styles from "./PianoRollEditor.module.css";
22	
23	const DEFAULT_VIEW: PianoRollViewState = {
24	  scrollX: 0,
25	  scrollY: PR_DEFAULT_SCROLL_Y,
26	  pixelsPerSecond: PR_DEFAULT_PPS,
27	  noteHeight: PR_DEFAULT_NOTE_HEIGHT,
28	  keyboardWidth: PR_KEYBOARD_WIDTH,
29	};
30	
31	const MIN_PPS = 20;
32	const MAX_PPS = 500;
33	const ZOOM_FACTOR = 1.1;
34	
35	const SNAP_OPTIONS: readonly PianoRollGridSnap[] = [
36	  "1/4",
37	  "1/8",
38	  "1/16",
39	  "1/8T",
40	  "1/16T",
41	];
42	
43	type PianoRollEditorProps = {
44	  clipId: string | null;
45	  onNotePreview?: (note: number, velocity: number) => void;
46	  onNotePreviewEnd?: (note: number) => void;
47	};
48	
49	export function PianoRollEditor({
50	  clipId,
51	  onNotePreview: _onNotePreview,
52	  onNotePreviewEnd: _onNotePreviewEnd,
53	}: PianoRollEditorProps): React.JSX.Element {
54	  const canvasRef = useRef<HTMLCanvasElement>(null);
55	  const rafRef = useRef(0);
56	  const [tool, setTool] = useState<PianoRollTool>("pencil");
57	  const [gridSnap, setGridSnap] = useState<PianoRollGridSnap>("1/8");
58	  const [view, setView] = useState<PianoRollViewState>(DEFAULT_VIEW);
59	
60	  const interactions = usePianoRollInteractions(clipId, view, tool, gridSnap);
61	
62	  // Store selectors
63	  const clips = useDawStore((s) => s.clips);
64	  const selectedNoteIds = useDawStore((s) => s.selectedNoteIds);
65	  const cursorSeconds = useDawStore((s) => s.cursorSeconds);
66	  const bpm = useDawStore((s) => s.bpm);
67	  const transportState = useDawStore((s) => s.transportState);
68	
69	  // Derive clip data
70	  const clip = clipId !== null ? clips[clipId] : undefined;
71	  const notes =
72	    clip !== undefined && isMidiClip(clip) ? clip.noteEvents : [];
73	  const clipStartTime =
74	    clip !== undefined ? clip.startTime : 0;
75	  const clipDuration = clip !== undefined ? clip.duration : 4;
76	
77	  // Keyboard commands
78	  const registry = useMemo(() => {
79	    const reg = new CommandRegistry();
80	    reg.register({
81	      id: "piano-roll.tool.pencil",
82	      label: "Pencil Tool",
83	      execute: () => setTool("pencil"),
84	    });
85	    reg.register({
86	      id: "piano-roll.tool.select",
87	      label: "Select Tool",
88	      execute: () => setTool("select"),
89	    });
90	    reg.register({
91	      id: "piano-roll.tool.erase",
92	      label: "Erase Tool",
93	      execute: () => setTool("erase"),
94	    });
95	    reg.register({
96	      id: "piano-roll.delete-selected",
97	      label: "Delete Selected Notes",
98	      execute: () => interactions.deleteSelectedNotes(),
99	    });
100	    return reg;
101	  }, [interactions]);
102	
103	  const shortcuts = useMemo(() => {
104	    const map = new ShortcutMap();
105	    map.bind({ key: "p", commandId: "piano-roll.tool.pencil" });
106	    map.bind({ key: "s", commandId: "piano-roll.tool.select" });
107	    map.bind({ key: "e", commandId: "piano-roll.tool.erase" });
108	    map.bind({ key: "Delete", commandId: "piano-roll.delete-selected" });
109	    map.bind({ key: "Backspace", commandId: "piano-roll.delete-selected" });
110	    return map;
111	  }, []);
112	
113	  useKeyboardShortcuts(registry, shortcuts);
114	
115	  // Render loop
116	  const render = useCallback((): void => {
117	    const canvas = canvasRef.current;
118	    if (canvas === null) return;
119	    const ctx = canvas.getContext("2d");
120	    if (ctx === null) return;
121	
122	    const rect = canvas.getBoundingClientRect();
123	    renderPianoRoll({
124	      ctx,
125	      width: rect.width,
126	      height: rect.height,
127	      view,
128	      notes,
129	      selectedNoteIds: [...selectedNoteIds],
130	      cursorSeconds,
131	      bpm,
132	      clipStartTime,
133	      clipDuration,
134	      tool,
135	      velocityLaneHeight: PR_VELOCITY_LANE_HEIGHT,
136	    });
137	  }, [
138	    view,
139	    notes,
140	    selectedNoteIds,
141	    cursorSeconds,
142	    bpm,
143	    clipStartTime,
144	    clipDuration,
145	    tool,
146	  ]);
147	
148	  // RAF scheduling
149	  useEffect(() => {
150	    const tick = (): void => {
151	      render();
152	      if (transportState === "playing") {
153	        rafRef.current = requestAnimationFrame(tick);
154	      }
155	    };
156	
157	    rafRef.current = requestAnimationFrame(tick);
158	    return (): void => {
159	      cancelAnimationFrame(rafRef.current);
160	    };
161	  }, [render, transportState]);
162	
163	  // Canvas sizing with ResizeObserver
164	  useEffect(() => {
165	    const canvas = canvasRef.current;
166	    if (canvas === null) return;
167	    const parent = canvas.parentElement;
168	    if (parent === null) return;
169	
170	    const resizeCanvas = (): void => {
171	      const dpr = window.devicePixelRatio;
172	      const rect = parent.getBoundingClientRect();
173	      canvas.width = rect.width * dpr;
174	      canvas.height = rect.height * dpr;
175	      canvas.style.width = `${String(rect.width)}px`;
176	      canvas.style.height = `${String(rect.height)}px`;
177	
178	      const ctx = canvas.getContext("2d");
179	      if (ctx !== null) {
180	        ctx.scale(dpr, dpr);
181	      }
182	    };
183	
184	    if (typeof ResizeObserver === "undefined") return;
185	
186	    const observer = new ResizeObserver(resizeCanvas);
187	    observer.observe(parent);
188	    resizeCanvas();
189	
190	    return (): void => {
191	      observer.disconnect();
192	    };
193	  }, []);
194	
195	  // Wheel: ctrl+wheel for zoom, plain wheel for scroll
196	  const handleWheel = useCallback(
197	    (e: React.WheelEvent<HTMLCanvasElement>): void => {
198	      e.preventDefault();
199	
200	      if (e.ctrlKey || e.metaKey) {
201	        const factor = e.deltaY < 0 ? ZOOM_FACTOR : 1 / ZOOM_FACTOR;
202	        setView((prev) => ({
203	          ...prev,
204	          pixelsPerSecond: Math.min(
205	            MAX_PPS,
206	            Math.max(MIN_PPS, prev.pixelsPerSecond * factor),
207	          ),
208	        }));
209	      } else if (e.shiftKey) {
210	        setView((prev) => ({
211	          ...prev,
212	          scrollX: Math.max(0, prev.scrollX + e.deltaY / prev.pixelsPerSecond),
213	        }));
214	      } else {
215	        setView((prev) => ({
216	          ...prev,
217	          scrollX: Math.max(0, prev.scrollX + e.deltaX / prev.pixelsPerSecond),
218	          scrollY: prev.scrollY - e.deltaY / prev.noteHeight,
219	        }));
220	      }
221	    },
222	    [],
223	  );
224	
225	  return (
226	    <section data-testid="piano-roll-editor" className={styles["container"]}>
227	      <div className={styles["toolbar"]}>
228	        <button
229	          data-testid="tool-pencil"
230	          className={styles["toolButton"]}
231	          data-active={String(tool === "pencil")}
232	          onClick={() => setTool("pencil")}
233	        >
234	          Pencil
235	        </button>
236	        <button
237	          data-testid="tool-select"
238	          className={styles["toolButton"]}
239	          data-active={String(tool === "select")}
240	          onClick={() => setTool("select")}
241	        >
242	          Select
243	        </button>
244	        <button
245	          data-testid="tool-erase"
246	          className={styles["toolButton"]}
247	          data-active={String(tool === "erase")}
248	          onClick={() => setTool("erase")}
249	        >
250	          Erase
251	        </button>
252	        <select
253	          data-testid="snap-select"
254	          className={styles["snapSelect"]}
255	          value={gridSnap}
256	          onChange={(e) =>
257	            setGridSnap(e.target.value as PianoRollGridSnap)
258	          }
259	        >
260	          {SNAP_OPTIONS.map((opt) => (
261	            <option key={opt} value={opt}>
262	              {opt}
263	            </option>
264	          ))}
265	        </select>
266	      </div>
267	      <div className={styles["canvasWrapper"]}>
268	        <canvas
269	          ref={canvasRef}
270	          className={styles["canvas"]}
271	          style={{ cursor: interactions.cursor }}
272	          onWheel={handleWheel}
273	          onPointerDown={interactions.onPointerDown}
274	          onPointerMove={interactions.onPointerMove}
275	          onPointerUp={interactions.onPointerUp}
276	        />
277	      </div>
278	    </section>
279	  );
280	}
281

