1	/**
2	 * MIDI input validation and clamping.
3	 * NFR-16: All MIDI input values clamped to valid ranges.
4	 * All external input treated as untrusted.
5	 */
6	
7	// -- Validated message types --
8	
9	export type ValidatedNoteOn = {
10	  readonly type: "note-on";
11	  readonly note: number; // 0-127
12	  readonly velocity: number; // 1-127 (0 is note-off)
13	  readonly channel: number; // 0-15
14	};
15	
16	export type ValidatedNoteOff = {
17	  readonly type: "note-off";
18	  readonly note: number; // 0-127
19	  readonly channel: number; // 0-15
20	};
21	
22	export type ValidatedCC = {
23	  readonly type: "cc";
24	  readonly controller: number; // 0-127
25	  readonly value: number; // 0-127
26	  readonly channel: number; // 0-15
27	};
28	
29	export type ValidatedPitchBend = {
30	  readonly type: "pitch-bend";
31	  readonly value: number; // 0-16383
32	  readonly channel: number; // 0-15
33	};
34	
35	export type ValidatedMidiMessage =
36	  | ValidatedNoteOn
37	  | ValidatedNoteOff
38	  | ValidatedCC
39	  | ValidatedPitchBend;
40	
41	export type MidiValidationResult =
42	  | { readonly valid: true; readonly message: ValidatedMidiMessage }
43	  | { readonly valid: false; readonly reason: string };
44	
45	// -- Constants --
46	
47	const SYSEX_MAX_BYTES = 1024; // 1 KB
48	const SYSEX_START = 0xf0;
49	const SYSEX_END = 0xf7;
50	
51	// Status byte high nibble ranges
52	const NOTE_OFF_MIN = 0x80;
53	const NOTE_OFF_MAX = 0x8f;
54	const NOTE_ON_MIN = 0x90;
55	const NOTE_ON_MAX = 0x9f;
56	const CC_MIN = 0xb0;
57	const CC_MAX = 0xbf;
58	const PITCH_BEND_MIN = 0xe0;
59	const PITCH_BEND_MAX = 0xef;
60	
61	// -- Clamp functions --
62	
63	/** Clamp a value to 7-bit MIDI range (0-127). */
64	export function clampMidi7Bit(value: number): number {
65	  return Math.min(127, Math.max(0, Math.floor(value)));
66	}
67	
68	/** Clamp a value to 14-bit MIDI range (0-16383). */
69	export function clampMidi14Bit(value: number): number {
70	  return Math.min(16383, Math.max(0, Math.floor(value)));
71	}
72	
73	// -- Validation --
74	
75	/** Safe byte read -- returns 0 for out-of-bounds indices. */
76	function byte(data: Uint8Array, index: number): number {
77	  return data[index] ?? 0;
78	}
79	
80	/** Validate raw MIDI bytes (Uint8Array) from Web MIDI API. */
81	export function validateMidiMessage(data: Uint8Array): MidiValidationResult {
82	  if (data.length === 0) {
83	    return { valid: false, reason: "Empty MIDI message" };
84	  }
85	
86	  const status = byte(data, 0);
87	  const channel = status & 0x0f;
88	
89	  if (status >= NOTE_OFF_MIN && status <= NOTE_OFF_MAX) {
90	    if (data.length < 3)
91	      return { valid: false, reason: "Note Off requires 3 bytes" };
92	    return {
93	      valid: true,
94	      message: {
95	        type: "note-off",
96	        note: clampMidi7Bit(byte(data, 1)),
97	        channel,
98	      },
99	    };
100	  }
101	
102	  if (status >= NOTE_ON_MIN && status <= NOTE_ON_MAX) {
103	    if (data.length < 3)
104	      return { valid: false, reason: "Note On requires 3 bytes" };
105	    const note = clampMidi7Bit(byte(data, 1));
106	    const velocity = clampMidi7Bit(byte(data, 2));
107	    // Note-on with velocity 0 is conventionally note-off
108	    if (velocity === 0) {
109	      return { valid: true, message: { type: "note-off", note, channel } };
110	    }
111	    return {
112	      valid: true,
113	      message: { type: "note-on", note, velocity, channel },
114	    };
115	  }
116	
117	  if (status >= CC_MIN && status <= CC_MAX) {
118	    if (data.length < 3) return { valid: false, reason: "CC requires 3 bytes" };
119	    return {
120	      valid: true,
121	      message: {
122	        type: "cc",
123	        controller: clampMidi7Bit(byte(data, 1)),
124	        value: clampMidi7Bit(byte(data, 2)),
125	        channel,
126	      },
127	    };
128	  }
129	
130	  if (status >= PITCH_BEND_MIN && status <= PITCH_BEND_MAX) {
131	    if (data.length < 3)
132	      return { valid: false, reason: "Pitch Bend requires 3 bytes" };
133	    const lsb = clampMidi7Bit(byte(data, 1));
134	    const msb = clampMidi7Bit(byte(data, 2));
135	    return {
136	      valid: true,
137	      message: {
138	        type: "pitch-bend",
139	        value: clampMidi14Bit(msb * 128 + lsb),
140	        channel,
141	      },
142	    };
143	  }
144	
145	  return {
146	    valid: false,
147	    reason: `Unsupported MIDI status byte: 0x${status.toString(16)}`,
148	  };
149	}
150	
151	/** Validate SysEx message size (max 1KB) and framing. */
152	export function validateSysEx(data: Uint8Array): {
153	  valid: boolean;
154	  reason?: string;
155	} {
156	  if (data.length === 0) {
157	    return { valid: false, reason: "Empty SysEx message" };
158	  }
159	  if (byte(data, 0) !== SYSEX_START) {
160	    return { valid: false, reason: "SysEx must start with 0xF0" };
161	  }
162	  if (byte(data, data.length - 1) !== SYSEX_END) {
163	    return { valid: false, reason: "SysEx must end with 0xF7" };
164	  }
165	  if (data.length > SYSEX_MAX_BYTES) {
166	    return {
167	      valid: false,
168	      reason: `SysEx exceeds max size: ${String(data.length)} > ${String(SYSEX_MAX_BYTES)} bytes`,
169	    };
170	  }
171	  return { valid: true };
172	}
