1	import type { UndoCommand } from "@state/undo/undo-command";
2	import { useDawStore } from "@state/store";
3	import type { MIDINoteEvent } from "@state/track/types";
4	import { isMidiClip } from "@state/track/types";
5	
6	function getStore(): ReturnType<typeof useDawStore.getState> {
7	  return useDawStore.getState();
8	}
9	
10	export class AddNoteCommand implements UndoCommand {
11	  readonly type = "add-note";
12	
13	  constructor(
14	    private readonly clipId: string,
15	    private readonly note: MIDINoteEvent,
16	  ) {}
17	
18	  execute(): void {
19	    getStore().addNoteEvent(this.clipId, this.note);
20	  }
21	
22	  undo(): void {
23	    getStore().removeNoteEvent(this.clipId, this.note.id);
24	  }
25	
26	  serialize(): Record<string, unknown> {
27	    return { clipId: this.clipId, note: this.note };
28	  }
29	}
