31	export class RemoveNoteCommand implements UndoCommand {
32	  readonly type = "remove-note";
33	
34	  private savedNote: MIDINoteEvent | undefined;
35	
36	  constructor(
37	    private readonly clipId: string,
38	    private readonly noteId: string,
39	  ) {}
40	
41	  execute(): void {
42	    const clip = getStore().clips[this.clipId];
43	    if (clip && isMidiClip(clip)) {
44	      this.savedNote = clip.noteEvents.find((n) => n.id === this.noteId);
45	    }
46	    getStore().removeNoteEvent(this.clipId, this.noteId);
47	  }
48	
49	  undo(): void {
50	    if (this.savedNote) getStore().addNoteEvent(this.clipId, this.savedNote);
51	  }
52	
53	  serialize(): Record<string, unknown> {
54	    return { clipId: this.clipId, noteId: this.noteId };
55	  }
56	}
