58	export class MoveNoteCommand implements UndoCommand {
59	  readonly type = "move-note";
60	
61	  private oldStartTime = 0;
62	  private oldPitch = 0;
63	
64	  constructor(
65	    private readonly clipId: string,
66	    private readonly noteId: string,
67	    private readonly newStartTime: number,
68	    private readonly newPitch: number,
69	  ) {}
70	
71	  execute(): void {
72	    const clip = getStore().clips[this.clipId];
73	    if (clip && isMidiClip(clip)) {
74	      const note = clip.noteEvents.find((n) => n.id === this.noteId);
75	      if (note) {
76	        this.oldStartTime = note.startTime;
77	        this.oldPitch = note.pitch;
78	      }
79	    }
80	    getStore().moveNoteEvent(
81	      this.clipId,
82	      this.noteId,
83	      this.newStartTime,
84	      this.newPitch,
85	    );
86	  }
87	
88	  undo(): void {
89	    getStore().moveNoteEvent(
90	      this.clipId,
91	      this.noteId,
92	      this.oldStartTime,
93	      this.oldPitch,
94	    );
95	  }
96	
97	  serialize(): Record<string, unknown> {
98	    return {
99	      clipId: this.clipId,
100	      noteId: this.noteId,
101	      newStartTime: this.newStartTime,
102	      newPitch: this.newPitch,
103	      oldStartTime: this.oldStartTime,
104	      oldPitch: this.oldPitch,
105	    };
106	  }
107	}
108	
109	export class ResizeNoteCommand implements UndoCommand {
110	  readonly type = "resize-note";
111	
112	  private oldDuration = 0;
113	
114	  constructor(
115	    private readonly clipId: string,
116	    private readonly noteId: string,
117	    private readonly newDuration: number,
118	  ) {}
119	
120	  execute(): void {
121	    const clip = getStore().clips[this.clipId];
122	    if (clip && isMidiClip(clip)) {
123	      const note = clip.noteEvents.find((n) => n.id === this.noteId);
124	      if (note) {
125	        this.oldDuration = note.duration;
126	      }
127	    }
128	    getStore().resizeNoteEvent(this.clipId, this.noteId, this.newDuration);
129	  }
130	
131	  undo(): void {
132	    getStore().resizeNoteEvent(this.clipId, this.noteId, this.oldDuration);
133	  }
134	
135	  serialize(): Record<string, unknown> {
136	    return {
137	      clipId: this.clipId,
138	      noteId: this.noteId,
139	      newDuration: this.newDuration,
140	      oldDuration: this.oldDuration,
141	    };
142	  }
143	}
144	
145	export class BatchNoteCommand implements UndoCommand {
146	  readonly type = "batch-note";
147	
148	  constructor(private readonly commands: UndoCommand[]) {}
149	
150	  execute(): void {
151	    for (const cmd of this.commands) cmd.execute();
152	  }
153	
154	  undo(): void {
155	    for (let i = this.commands.length - 1; i >= 0; i--) {
156	      const cmd = this.commands[i];
157	      if (cmd) cmd.undo();
158	    }
159	  }
160	
161	  serialize(): Record<string, unknown> {
162	    return {
163	      commands: this.commands.map((c) => ({ type: c.type, ...c.serialize() })),
164	    };
165	  }
166	}
