1	/**
2	 * Web MIDI API device manager.
3	 * R-OPT-01: Accept MIDI note and CC messages from connected input devices.
4	 */
5	
6	import {
7	  validateMidiMessage,
8	  type ValidatedMidiMessage,
9	} from "./midi-input-validator";
10	
11	export type MidiDeviceInfo = {
12	  readonly id: string;
13	  readonly name: string;
14	  readonly manufacturer: string;
15	  readonly state: "connected" | "disconnected";
16	};
17	
18	export type MidiDeviceCallback = (message: ValidatedMidiMessage) => void;
19	
20	export type MidiDeviceManager = {
21	  initialize(): Promise<boolean>;
22	  getInputDevices(): readonly MidiDeviceInfo[];
23	  onMessage(callback: MidiDeviceCallback): () => void;
24	  connectDevice(deviceId: string): boolean;
25	  disconnect(): void;
26	  dispose(): void;
27	};
28	
29	export function createMidiDeviceManager(): MidiDeviceManager {
30	  let midiAccess: MIDIAccess | null = null;
31	  let connectedInput: MIDIInput | null = null;
32	  const listeners = new Set<MidiDeviceCallback>();
33	
34	  function handleMidiMessage(event: MIDIMessageEvent): void {
35	    if (!event.data) return;
36	    const result = validateMidiMessage(event.data);
37	    if (!result.valid) return;
38	    for (const cb of listeners) {
39	      cb(result.message);
40	    }
41	  }
42	
43	  function handleStateChange(): void {
44	    // Re-check connection state; if connected device is disconnected, clean up
45	    if (connectedInput && connectedInput.state === "disconnected") {
46	      connectedInput.onmidimessage = null;
47	      connectedInput = null;
48	    }
49	  }
50	
51	  return {
52	    async initialize(): Promise<boolean> {
53	      if (
54	        typeof navigator === "undefined" ||
55	        !("requestMIDIAccess" in navigator)
56	      ) {
57	        return false;
58	      }
59	      try {
60	        midiAccess = await navigator.requestMIDIAccess();
61	        midiAccess.onstatechange = handleStateChange;
62	        return true;
63	      } catch {
64	        return false;
65	      }
66	    },
67	
68	    getInputDevices(): readonly MidiDeviceInfo[] {
69	      if (!midiAccess) return [];
70	      const devices: MidiDeviceInfo[] = [];
71	      for (const input of midiAccess.inputs.values()) {
72	        devices.push({
73	          id: input.id,
74	          name: input.name ?? "Unknown",
75	          manufacturer: input.manufacturer ?? "Unknown",
76	          state: input.state,
77	        });
78	      }
79	      return devices;
80	    },
81	
82	    onMessage(callback: MidiDeviceCallback): () => void {
83	      listeners.add(callback);
84	      return () => {
85	        listeners.delete(callback);
86	      };
87	    },
88	
89	    connectDevice(deviceId: string): boolean {
90	      if (!midiAccess) return false;
91	      const input = midiAccess.inputs.get(deviceId);
92	      if (!input) return false;
93	
94	      // Disconnect previous
95	      if (connectedInput) {
96	        connectedInput.onmidimessage = null;
97	      }
98	
99	      connectedInput = input;
100	      connectedInput.onmidimessage = handleMidiMessage;
101	      return true;
102	    },
103	
104	    disconnect(): void {
105	      if (connectedInput) {
106	        connectedInput.onmidimessage = null;
107	        connectedInput = null;
108	      }
109	    },
110	
111	    dispose(): void {
112	      if (connectedInput) {
113	        connectedInput.onmidimessage = null;
114	        connectedInput = null;
115	      }
116	      listeners.clear();
117	      if (midiAccess) {
118	        midiAccess.onstatechange = null;
119	        midiAccess = null;
120	      }
121	    },
122	  };
123	}
