1	/**
2	 * Hit-testing utilities for the piano roll canvas.
3	 * Converts pixel coordinates to note/region references.
4	 */
5	import type { MIDINoteEvent } from "@state/track/types";
6	import type { PianoRollViewState } from "./piano-roll-renderer";
7	import { secondsToX } from "./piano-roll-renderer";
8	import { PR_RULER_HEIGHT } from "./constants";
9	
10	// -- Types --------------------------------------------------------------------
11	
12	export type PianoRollGridSnap = "1/4" | "1/8" | "1/16" | "1/8T" | "1/16T";
13	
14	export type PianoRollHitResult =
15	  | { kind: "none" }
16	  | { kind: "note-body"; noteId: string }
17	  | { kind: "note-left-edge"; noteId: string }
18	  | { kind: "note-right-edge"; noteId: string }
19	  | { kind: "velocity-bar"; noteId: string }
20	  | { kind: "keyboard-key"; pitch: number }
21	  | { kind: "ruler"; timeSeconds: number }
22	  | { kind: "empty-grid"; pitch: number; timeSeconds: number };
23	
24	// -- Constants ----------------------------------------------------------------
25	
26	const EDGE_HANDLE_PX = 6;
27	
28	// -- Coordinate transforms ----------------------------------------------------
29	
30	export function xToSeconds(x: number, view: PianoRollViewState): number {
31	  return view.scrollX + (x - view.keyboardWidth) / view.pixelsPerSecond;
32	}
33	
34	export function yToPitch(y: number, view: PianoRollViewState): number {
35	  return Math.round(view.scrollY - (y - PR_RULER_HEIGHT) / view.noteHeight);
36	}
37	
38	// -- Grid snapping ------------------------------------------------------------
39	
40	export function pianoRollSnapToGrid(
41	  seconds: number,
42	  bpm: number,
43	  snap: PianoRollGridSnap,
44	): number {
45	  const secPerBeat = 60 / bpm;
46	  let gridSize: number;
47	  switch (snap) {
48	    case "1/4":
49	      gridSize = secPerBeat;
50	      break;
51	    case "1/8":
52	      gridSize = secPerBeat / 2;
53	      break;
54	    case "1/16":
55	      gridSize = secPerBeat / 4;
56	      break;
57	    case "1/8T":
58	      gridSize = secPerBeat / 3;
59	      break;
60	    case "1/16T":
61	      gridSize = secPerBeat / 6;
62	      break;
63	  }
64	  return Math.round(seconds / gridSize) * gridSize;
65	}
66	
67	// -- Hit testing --------------------------------------------------------------
68	
69	export function pianoRollHitTest(
70	  x: number,
71	  y: number,
72	  view: PianoRollViewState,
73	  notes: readonly MIDINoteEvent[],
74	  canvasHeight: number,
75	  velocityLaneHeight: number,
76	): PianoRollHitResult {
77	  // Ruler area
78	  if (y < PR_RULER_HEIGHT) {
79	    return { kind: "ruler", timeSeconds: xToSeconds(x, view) };
80	  }
81	
82	  // Keyboard area
83	  if (x < view.keyboardWidth) {
84	    return { kind: "keyboard-key", pitch: yToPitch(y, view) };
85	  }
86	
87	  // Velocity lane area
88	  const velocityLaneTop = canvasHeight - velocityLaneHeight;
89	  if (y >= velocityLaneTop) {
90	    for (let i = notes.length - 1; i >= 0; i--) {
91	      const note = notes[i];
92	      if (!note) continue;
93	      const noteX = secondsToX(note.startTime, view);
94	      const noteW = note.duration * view.pixelsPerSecond;
95	      if (x >= noteX && x <= noteX + noteW) {
96	        return { kind: "velocity-bar", noteId: note.id };
97	      }
98	    }
99	    return { kind: "none" };
100	  }
101	
102	  // Note grid area -- check notes in reverse for z-order priority
103	  for (let i = notes.length - 1; i >= 0; i--) {
104	    const note = notes[i];
105	    if (!note) continue;
106	    const noteX = secondsToX(note.startTime, view);
107	    const noteW = note.duration * view.pixelsPerSecond;
108	    const noteY =
109	      PR_RULER_HEIGHT + (view.scrollY - note.pitch) * view.noteHeight;
110	    const noteH = view.noteHeight;
111	
112	    if (x >= noteX && x <= noteX + noteW && y >= noteY && y <= noteY + noteH) {
113	      if (x - noteX < EDGE_HANDLE_PX) {
114	        return { kind: "note-left-edge", noteId: note.id };
115	      }
116	      if (noteX + noteW - x < EDGE_HANDLE_PX) {
117	        return { kind: "note-right-edge", noteId: note.id };
118	      }
119	      return { kind: "note-body", noteId: note.id };
120	    }
121	  }
122	
123	  // Empty grid
124	  return {
125	    kind: "empty-grid",
126	    pitch: yToPitch(y, view),
127	    timeSeconds: xToSeconds(x, view),
128	  };
129	}
130	
131	// -- Lasso selection ----------------------------------------------------------
132	
133	export function lassoSelectNotes(
134	  startX: number,
135	  startY: number,
136	  endX: number,
137	  endY: number,
138	  view: PianoRollViewState,
139	  notes: readonly MIDINoteEvent[],
140	): readonly string[] {
141	  const left = Math.min(startX, endX);
142	  const right = Math.max(startX, endX);
143	  const top = Math.min(startY, endY);
144	  const bottom = Math.max(startY, endY);
145	
146	  return notes
147	    .filter((note) => {
148	      const noteX = secondsToX(note.startTime, view);
149	      const noteW = note.duration * view.pixelsPerSecond;
150	      const noteY =
151	        PR_RULER_HEIGHT + (view.scrollY - note.pitch) * view.noteHeight;
152	      const noteH = view.noteHeight;
153	
154	      return (
155	        noteX + noteW > left &&
156	        noteX < right &&
157	        noteY + noteH > top &&
158	        noteY < bottom
159	      );
160	    })
161	    .map((n) => n.id);
162	}
