1	/**
2	 * Pointer interaction handlers for the piano roll canvas.
3	 * Manages draw, select, move, resize, erase, and lasso operations.
4	 * Pushes undo commands on completion.
5	 */
6	import { useCallback, useRef, useState } from "react";
7	import { useDawStore } from "@state/store";
8	import type { MIDINoteEvent } from "@state/track/types";
9	import { isMidiClip } from "@state/track/types";
10	import { sharedUndoManager } from "@state/undo";
11	import {
12	  AddNoteCommand,
13	  RemoveNoteCommand,
14	  MoveNoteCommand,
15	  ResizeNoteCommand,
16	  BatchNoteCommand,
17	} from "@state/track/midi-commands";
18	import type { PianoRollViewState, PianoRollTool } from "./piano-roll-renderer";
19	import {
20	  pianoRollHitTest,
21	  xToSeconds,
22	  yToPitch,
23	  pianoRollSnapToGrid,
24	  lassoSelectNotes,
25	  type PianoRollGridSnap,
26	} from "./piano-roll-hit-test";
27	import { PR_VELOCITY_LANE_HEIGHT } from "./constants";
28	
29	type DragState =
30	  | { kind: "idle" }
31	  | {
32	      kind: "move-note";
33	      noteId: string;
34	      clipId: string;
35	      startX: number;
36	      startY: number;
37	      origStartTime: number;
38	      origPitch: number;
39	    }
40	  | {
41	      kind: "resize-note";
42	      noteId: string;
43	      clipId: string;
44	      startX: number;
45	      origDuration: number;
46	    }
47	  | {
48	      kind: "draw-note";
49	      clipId: string;
50	      noteId: string;
51	      startTime: number;
52	      pitch: number;
53	    }
54	  | { kind: "rubber-band"; startX: number; startY: number };
55	
56	export type PianoRollInteractions = {
57	  cursor: string;
58	  onPointerDown: (e: React.PointerEvent<HTMLCanvasElement>) => void;
59	  onPointerMove: (e: React.PointerEvent<HTMLCanvasElement>) => void;
60	  onPointerUp: (e: React.PointerEvent<HTMLCanvasElement>) => void;
61	  deleteSelectedNotes: () => void;
62	};
63	
64	let noteCounter = 0;
65	function generateNoteId(): string {
66	  noteCounter += 1;
67	  return `note-${String(Date.now())}-${String(noteCounter)}`;
68	}
69	
70	function gridDuration(bpm: number, snap: PianoRollGridSnap): number {
71	  const secPerBeat = 60 / bpm;
72	  switch (snap) {
73	    case "1/4":
74	      return secPerBeat;
75	    case "1/8":
76	      return secPerBeat / 2;
77	    case "1/16":
78	      return secPerBeat / 4;
79	    case "1/8T":
80	      return secPerBeat / 3;
81	    case "1/16T":
82	      return secPerBeat / 6;
83	  }
84	}
85	
86	export function usePianoRollInteractions(
87	  clipId: string | null,
88	  view: PianoRollViewState,
89	  tool: PianoRollTool,
90	  gridSnap: PianoRollGridSnap,
91	): PianoRollInteractions {
92	  const dragRef = useRef<DragState>({ kind: "idle" });
93	  const [cursor, setCursor] = useState(
94	    clipId !== null && tool === "pencil" ? "crosshair" : "default",
95	  );
96	
97	  const getCanvasPos = useCallback(
98	    (e: React.MouseEvent<HTMLCanvasElement>): { x: number; y: number } => {
99	      const rect = e.currentTarget.getBoundingClientRect();
100	      return { x: e.clientX - rect.left, y: e.clientY - rect.top };
101	    },
102	    [],
103	  );
104	
105	  const getNotes = useCallback((): readonly MIDINoteEvent[] => {
106	    if (clipId === null) return [];
107	    const clip = useDawStore.getState().clips[clipId];
108	    if (clip === undefined || !isMidiClip(clip)) return [];
109	    return clip.noteEvents;
110	  }, [clipId]);
111	
112	  const onPointerDown = useCallback(
113	    (e: React.PointerEvent<HTMLCanvasElement>): void => {
114	      if (clipId === null) return;
115	
116	      const { x, y } = getCanvasPos(e);
117	      const state = useDawStore.getState();
118	      const notes = getNotes();
119	      const canvasHeight = e.currentTarget.getBoundingClientRect().height;
120	      const hit = pianoRollHitTest(
121	        x,
122	        y,
123	        view,
124	        notes,
125	        canvasHeight,
126	        PR_VELOCITY_LANE_HEIGHT,
127	      );
128	
129	      switch (tool) {
130	        case "pencil": {
131	          if (hit.kind === "empty-grid") {
132	            const snappedTime = pianoRollSnapToGrid(
133	              hit.timeSeconds,
134	              state.bpm,
135	              gridSnap,
136	            );
137	            const dur = gridDuration(state.bpm, gridSnap);
138	            const noteId = generateNoteId();
139	            const note: MIDINoteEvent = {
140	              id: noteId,
141	              pitch: hit.pitch,
142	              velocity: 100,
143	              startTime: Math.max(0, snappedTime),
144	              duration: dur,
145	            };
146	            const cmd = new AddNoteCommand(clipId, note);
147	            cmd.execute();
148	            sharedUndoManager.push(cmd);
149	
150	            e.currentTarget.setPointerCapture(e.pointerId);
151	            dragRef.current = {
152	              kind: "draw-note",
153	              clipId,
154	              noteId,
155	              startTime: note.startTime,
156	              pitch: note.pitch,
157	            };
158	          }
159	          break;
160	        }
161	        case "select": {
162	          if (hit.kind === "note-body") {
163	            if (e.shiftKey) {
164	              const current = [...state.selectedNoteIds];
165	              const idx = current.indexOf(hit.noteId);
166	              if (idx >= 0) {
167	                current.splice(idx, 1);
168	              } else {
169	                current.push(hit.noteId);
170	              }
171	              state.setSelectedNoteIds(current);
172	            } else {
173	              if (!state.selectedNoteIds.includes(hit.noteId)) {
174	                state.setSelectedNoteIds([hit.noteId]);
175	              }
176	            }
177	
178	            // Find note for drag
179	            const note = notes.find((n) => n.id === hit.noteId);
180	            if (note !== undefined) {
181	              e.currentTarget.setPointerCapture(e.pointerId);
182	              dragRef.current = {
183	                kind: "move-note",
184	                noteId: hit.noteId,
185	                clipId,
186	                startX: x,
187	                startY: y,
188	                origStartTime: note.startTime,
189	                origPitch: note.pitch,
190	              };
191	            }
192	          } else if (
193	            hit.kind === "note-left-edge" ||
194	            hit.kind === "note-right-edge"
195	          ) {
196	            state.setSelectedNoteIds([hit.noteId]);
197	            const note = notes.find((n) => n.id === hit.noteId);
198	            if (note !== undefined) {
199	              e.currentTarget.setPointerCapture(e.pointerId);
200	              dragRef.current = {
201	                kind: "resize-note",
202	                noteId: hit.noteId,
203	                clipId,
204	                startX: x,
205	                origDuration: note.duration,
206	              };
207	            }
208	          } else if (hit.kind === "empty-grid") {
209	            if (!e.shiftKey) {
210	              state.setSelectedNoteIds([]);
211	            }
212	            e.currentTarget.setPointerCapture(e.pointerId);
213	            dragRef.current = { kind: "rubber-band", startX: x, startY: y };
214	          }
215	          break;
216	        }
217	        case "erase": {
218	          if (
219	            hit.kind === "note-body" ||
220	            hit.kind === "note-left-edge" ||
221	            hit.kind === "note-right-edge"
222	          ) {
223	            const cmd = new RemoveNoteCommand(clipId, hit.noteId);
224	            cmd.execute();
225	            sharedUndoManager.push(cmd);
226	          }
227	          break;
228	        }
229	      }
230	    },
231	    [clipId, view, tool, gridSnap, getCanvasPos, getNotes],
232	  );
233	
234	  const onPointerMove = useCallback(
235	    (e: React.PointerEvent<HTMLCanvasElement>): void => {
236	      const { x, y } = getCanvasPos(e);
237	      const drag = dragRef.current;
238	      const state = useDawStore.getState();
239	
240	      if (drag.kind === "idle") {
241	        // Update cursor based on hover
242	        if (clipId === null) {
243	          setCursor("default");
244	          return;
245	        }
246	
247	        const notes = getNotes();
248	        const canvasHeight = e.currentTarget.getBoundingClientRect().height;
249	        const hit = pianoRollHitTest(
250	          x,
251	          y,
252	          view,
253	          notes,
254	          canvasHeight,
255	          PR_VELOCITY_LANE_HEIGHT,
256	        );
257	
258	        if (tool === "pencil") {
259	          setCursor("crosshair");
260	        } else if (tool === "select") {
261	          switch (hit.kind) {
262	            case "note-body":
263	              setCursor("pointer");
264	              break;
265	            case "note-left-edge":
266	            case "note-right-edge":
267	              setCursor("ew-resize");
268	              break;
269	            default:
270	              setCursor("default");
271	              break;
272	          }
273	        } else {
274	          setCursor("default");
275	        }
276	        return;
277	      }
278	
279	      switch (drag.kind) {
280	        case "move-note": {
281	          setCursor("grabbing");
282	          const deltaPx = x - drag.startX;
283	          const deltaSec = deltaPx / view.pixelsPerSecond;
284	          const newTime = pianoRollSnapToGrid(
285	            Math.max(0, drag.origStartTime + deltaSec),
286	            state.bpm,
287	            gridSnap,
288	          );
289	          const newPitch = yToPitch(y, view);
290	          state.moveNoteEvent(drag.clipId, drag.noteId, newTime, newPitch);
291	          break;
292	        }
293	        case "resize-note": {
294	          setCursor("ew-resize");
295	          const deltaPx = x - drag.startX;
296	          const deltaSec = deltaPx / view.pixelsPerSecond;
297	          const newDuration = Math.max(0.01, drag.origDuration + deltaSec);
298	          state.resizeNoteEvent(drag.clipId, drag.noteId, newDuration);
299	          break;
300	        }
301	        case "draw-note": {
302	          // Extend note duration as user drags
303	          const currentTime = xToSeconds(x, view);
304	          const snappedEnd = pianoRollSnapToGrid(
305	            currentTime,
306	            state.bpm,
307	            gridSnap,
308	          );
309	          const newDuration = Math.max(
310	            gridDuration(state.bpm, gridSnap),
311	            snappedEnd - drag.startTime,
312	          );
313	          state.resizeNoteEvent(drag.clipId, drag.noteId, newDuration);
314	          break;
315	        }
316	        case "rubber-band": {
317	          if (clipId === null) break;
318	          const notes = getNotes();
319	          const selected = lassoSelectNotes(
320	            drag.startX,
321	            drag.startY,
322	            x,
323	            y,
324	            view,
325	            notes,
326	          );
327	          state.setSelectedNoteIds([...selected]);
328	          break;
329	        }
330	      }
331	    },
332	    [clipId, view, tool, gridSnap, getCanvasPos, getNotes],
333	  );
334	
335	  const onPointerUp = useCallback(
336	    (e: React.PointerEvent<HTMLCanvasElement>): void => {
337	      const drag = dragRef.current;
338	
339	      if (drag.kind === "move-note") {
340	        const notes = getNotes();
341	        const note = notes.find((n) => n.id === drag.noteId);
342	        if (
343	          note !== undefined &&
344	          (note.startTime !== drag.origStartTime ||
345	            note.pitch !== drag.origPitch)
346	        ) {
347	          const cmd = new MoveNoteCommand(
348	            drag.clipId,
349	            drag.noteId,
350	            note.startTime,
351	            note.pitch,
352	          );
353	          // Already moved in store -- record for undo
354	          cmd.execute = (): void => {
355	            useDawStore
356	              .getState()
357	              .moveNoteEvent(
358	                drag.clipId,
359	                drag.noteId,
360	                note.startTime,
361	                note.pitch,
362	              );
363	          };
364	          sharedUndoManager.push(cmd);
365	        }
366	      } else if (drag.kind === "resize-note") {
367	        const notes = getNotes();
368	        const note = notes.find((n) => n.id === drag.noteId);
369	        if (note !== undefined && note.duration !== drag.origDuration) {
370	          const cmd = new ResizeNoteCommand(
371	            drag.clipId,
372	            drag.noteId,
373	            note.duration,
374	          );
375	          cmd.execute = (): void => {
376	            useDawStore
377	              .getState()
378	              .resizeNoteEvent(drag.clipId, drag.noteId, note.duration);
379	          };
380	          sharedUndoManager.push(cmd);
381	        }
382	      }
383	
384	      if (drag.kind !== "idle") {
385	        e.currentTarget.releasePointerCapture(e.pointerId);
386	      }
387	      dragRef.current = { kind: "idle" };
388	
389	      // Restore tool-appropriate cursor
390	      if (tool === "pencil") {
391	        setCursor("crosshair");
392	      } else {
393	        setCursor("default");
394	      }
395	    },
396	    [tool, getNotes],
397	  );
398	
399	  const deleteSelectedNotes = useCallback((): void => {
400	    if (clipId === null) return;
401	    const state = useDawStore.getState();
402	    const selected = state.selectedNoteIds;
403	    if (selected.length === 0) return;
404	
405	    const commands = selected.map(
406	      (noteId) => new RemoveNoteCommand(clipId, noteId),
407	    );
408	    const batch = new BatchNoteCommand(commands);
409	    batch.execute();
410	    sharedUndoManager.push(batch);
411	    state.setSelectedNoteIds([]);
412	  }, [clipId]);
413	
414	  return {
415	    cursor,
416	    onPointerDown,
417	    onPointerMove,
418	    onPointerUp,
419	    deleteSelectedNotes,
420	  };
421	}
