1	/**
2	 * Pure canvas renderer for the piano roll editor.
3	 * No DOM access -- only draws to the CanvasRenderingContext2D passed in.
4	 */
5	import type { MIDINoteEvent } from "@state/track/types";
6	import { PR_RULER_HEIGHT } from "./constants";
7	
8	// -- Design token constants (canvas cannot read CSS vars) ---------------------
9	
10	const COLOR = {
11	  black: "#000000",
12	  white: "#ffffff",
13	  red: "#ff0000",
14	  blue: "#0066ff",
15	  gray900: "#111111",
16	  gray800: "#1a1a1a",
17	  gray700: "#333333",
18	  gray500: "#666666",
19	  gray400: "#888888",
20	  whiteKeyRow: "#1c1c1c",
21	  blackKeyRow: "#141414",
22	  whiteKey: "#e0e0e0",
23	  blackKey: "#222222",
24	} as const;
25	
26	const FONT_MONO = "'JetBrains Mono', monospace" as const;
27	const TEXT_XS = 10;
28	const BORDER_WIDTH = 2;
29	
30	// -- Public types -------------------------------------------------------------
31	
32	export type PianoRollViewState = {
33	  scrollX: number; // seconds
34	  scrollY: number; // MIDI note number at top (0-127, higher = higher pitch)
35	  pixelsPerSecond: number; // horizontal zoom
36	  noteHeight: number; // pixels per semitone
37	  keyboardWidth: number; // width of piano keyboard sidebar
38	};
39	
40	export type PianoRollTool = "pencil" | "select" | "erase";
41	
42	export type PianoRollRenderContext = {
43	  ctx: CanvasRenderingContext2D;
44	  width: number;
45	  height: number;
46	  view: PianoRollViewState;
47	  notes: readonly MIDINoteEvent[];
48	  selectedNoteIds: readonly string[];
49	  cursorSeconds: number;
50	  bpm: number;
51	  clipStartTime: number; // absolute timeline position of the clip
52	  clipDuration: number;
53	  tool: PianoRollTool;
54	  velocityLaneHeight: number; // height of velocity lane at bottom
55	};
56	
57	// -- Helpers ------------------------------------------------------------------
58	
59	export function secondsToX(seconds: number, view: PianoRollViewState): number {
60	  return view.keyboardWidth + (seconds - view.scrollX) * view.pixelsPerSecond;
61	}
62	
63	export function pitchToY(
64	  pitch: number,
65	  view: PianoRollViewState,
66	  _height: number,
67	  _velocityLaneHeight: number,
68	): number {
69	  return PR_RULER_HEIGHT + (view.scrollY - pitch) * view.noteHeight;
70	}
71	
72	export function isBlackKey(pitch: number): boolean {
73	  const pc = pitch % 12;
74	  return pc === 1 || pc === 3 || pc === 6 || pc === 8 || pc === 10;
75	}
76	
77	export function noteName(pitch: number): string {
78	  const names = [
79	    "C",
80	    "C#",
81	    "D",
82	    "D#",
83	    "E",
84	    "F",
85	    "F#",
86	    "G",
87	    "G#",
88	    "A",
89	    "A#",
90	    "B",
91	  ];
92	  const octave = Math.floor(pitch / 12) - 1;
93	  return (names[pitch % 12] ?? "") + String(octave);
94	}
95	
96	/** Convert a hex color (#rrggbb) to rgba with given alpha (0-1). */
97	function hexToRgba(hex: string, alpha: number): string {
98	  if (!/^#[0-9a-fA-F]{6}$/.test(hex)) {
99	    return `rgba(128,128,128,${String(alpha)})`;
100	  }
101	  const r = parseInt(hex.slice(1, 3), 16);
102	  const g = parseInt(hex.slice(3, 5), 16);
103	  const b = parseInt(hex.slice(5, 7), 16);
104	  return `rgba(${String(r)},${String(g)},${String(b)},${String(alpha)})`;
105	}
106	
107	// -- Rendering stages ---------------------------------------------------------
108	
109	function drawBackground(rc: PianoRollRenderContext): void {
110	  const { ctx, width, height } = rc;
111	  ctx.fillStyle = COLOR.gray900;
112	  ctx.fillRect(0, 0, width, height);
113	}
114	
115	function drawNoteGrid(rc: PianoRollRenderContext): void {
116	  const { ctx, width, height, view, velocityLaneHeight } = rc;
117	  const gridBottom = height - velocityLaneHeight;
118	
119	  // Determine visible pitch range
120	  const topPitch = view.scrollY;
121	  const visibleRows = Math.ceil(
122	    (gridBottom - PR_RULER_HEIGHT) / view.noteHeight,
123	  );
124	  const bottomPitch = topPitch - visibleRows;
125	
126	  for (let pitch = topPitch; pitch >= bottomPitch; pitch--) {
127	    const y = pitchToY(pitch, view, height, velocityLaneHeight);
128	    if (y + view.noteHeight < PR_RULER_HEIGHT || y > gridBottom) continue;
129	
130	    // Row fill: slightly lighter for white keys
131	    ctx.fillStyle = isBlackKey(pitch) ? COLOR.blackKeyRow : COLOR.whiteKeyRow;
132	    ctx.fillRect(
133	      view.keyboardWidth,
134	      y,
135	      width - view.keyboardWidth,
136	      view.noteHeight,
137	    );
138	
139	    // Horizontal separator
140	    ctx.strokeStyle = COLOR.gray700;
141	    ctx.lineWidth = 1;
142	    ctx.beginPath();
143	    ctx.moveTo(view.keyboardWidth, y + view.noteHeight);
144	    ctx.lineTo(width, y + view.noteHeight);
145	    ctx.stroke();
146	  }
147	}
148	
149	function drawTimeGrid(rc: PianoRollRenderContext): void {
150	  const { ctx, width, height, view, bpm, velocityLaneHeight } = rc;
151	  const secPerBeat = 60 / bpm;
152	  const secPerBar = secPerBeat * 4;
153	  const gridBottom = height - velocityLaneHeight;
154	
155	  const startSec = view.scrollX;
156	  const endSec =
157	    view.scrollX + (width - view.keyboardWidth) / view.pixelsPerSecond;
158	
159	  // Determine grid step -- skip beats when zoomed out too far
160	  const minPxPerLine = 12;
161	  let step = secPerBeat;
162	  while (step * view.pixelsPerSecond < minPxPerLine) {
163	    step *= 2;
164	  }
165	
166	  const firstBeat = Math.floor(startSec / step) * step;
167	
168	  ctx.save();
169	  for (let t = firstBeat; t <= endSec; t += step) {
170	    const x = secondsToX(t, view);
171	    if (x < view.keyboardWidth || x > width) continue;
172	
173	    const nearestBar = Math.round(t / secPerBar) * secPerBar;
174	    const isBar = Math.abs(t - nearestBar) < 0.001;
175	    ctx.strokeStyle = COLOR.gray700;
176	    ctx.lineWidth = isBar ? 2 : 1;
177	
178	    ctx.beginPath();
179	    ctx.moveTo(x, PR_RULER_HEIGHT);
180	    ctx.lineTo(x, gridBottom);
181	    ctx.stroke();
182	  }
183	  ctx.restore();
184	}
185	
186	function drawNotes(rc: PianoRollRenderContext): void {
187	  const { ctx, view, height, notes, selectedNoteIds, velocityLaneHeight } = rc;
188	  const selectedSet = new Set(selectedNoteIds);
189	
190	  for (const note of notes) {
191	    const x = secondsToX(note.startTime, view);
192	    const w = note.duration * view.pixelsPerSecond;
193	    const y = pitchToY(note.pitch, view, height, velocityLaneHeight);
194	    const h = view.noteHeight;
195	
196	    // Skip notes fully out of view
197	    if (x + w < view.keyboardWidth || x > rc.width) continue;
198	    if (y + h < PR_RULER_HEIGHT || y > height - velocityLaneHeight) continue;
199	
200	    // Fill
201	    ctx.fillStyle = hexToRgba(COLOR.blue, 0.8);
202	    ctx.fillRect(x, y, w, h);
203	
204	    // Border
205	    const isSelected = selectedSet.has(note.id);
206	    ctx.strokeStyle = isSelected ? COLOR.white : COLOR.blue;
207	    ctx.lineWidth = BORDER_WIDTH;
208	    ctx.strokeRect(x, y, w, h);
209	  }
210	}
211	
212	function drawKeyboard(rc: PianoRollRenderContext): void {
213	  const { ctx, view, height, velocityLaneHeight } = rc;
214	  const gridBottom = height - velocityLaneHeight;
215	
216	  // Keyboard background
217	  ctx.fillStyle = COLOR.black;
218	  ctx.fillRect(
219	    0,
220	    PR_RULER_HEIGHT,
221	    view.keyboardWidth,
222	    gridBottom - PR_RULER_HEIGHT,
223	  );
224	
225	  const topPitch = view.scrollY;
226	  const visibleRows = Math.ceil(
227	    (gridBottom - PR_RULER_HEIGHT) / view.noteHeight,
228	  );
229	  const bottomPitch = topPitch - visibleRows;
230	
231	  for (let pitch = topPitch; pitch >= bottomPitch; pitch--) {
232	    const y = pitchToY(pitch, view, height, velocityLaneHeight);
233	    if (y + view.noteHeight < PR_RULER_HEIGHT || y > gridBottom) continue;
234	
235	    const black = isBlackKey(pitch);
236	
237	    // Key fill
238	    ctx.fillStyle = black ? COLOR.blackKey : COLOR.whiteKey;
239	    const keyWidth = black ? view.keyboardWidth * 0.6 : view.keyboardWidth - 1;
240	    ctx.fillRect(0, y, keyWidth, view.noteHeight);
241	
242	    // Key separator
243	    ctx.strokeStyle = COLOR.gray700;
244	    ctx.lineWidth = 1;
245	    ctx.beginPath();
246	    ctx.moveTo(0, y + view.noteHeight);
247	    ctx.lineTo(view.keyboardWidth, y + view.noteHeight);
248	    ctx.stroke();
249	
250	    // Label C notes
251	    if (pitch % 12 === 0) {
252	      const label = noteName(pitch);
253	      ctx.font = `${String(TEXT_XS)}px ${FONT_MONO}`;
254	      ctx.fillStyle = black ? COLOR.white : COLOR.black;
255	      ctx.textBaseline = "middle";
256	      ctx.textAlign = "left";
257	      ctx.fillText(label, 2, y + view.noteHeight / 2);
258	    }
259	  }
260	
261	  // Keyboard right border
262	  ctx.strokeStyle = COLOR.gray700;
263	  ctx.lineWidth = BORDER_WIDTH;
264	  ctx.beginPath();
265	  ctx.moveTo(view.keyboardWidth, PR_RULER_HEIGHT);
266	  ctx.lineTo(view.keyboardWidth, gridBottom);
267	  ctx.stroke();
268	}
269	
270	function drawVelocityLane(rc: PianoRollRenderContext): void {
271	  const { ctx, width, height, view, notes, velocityLaneHeight } = rc;
272	  const laneTop = height - velocityLaneHeight;
273	
274	  // Lane background
275	  ctx.fillStyle = COLOR.black;
276	  ctx.fillRect(
277	    view.keyboardWidth,
278	    laneTop,
279	    width - view.keyboardWidth,
280	    velocityLaneHeight,
281	  );
282	
283	  // Separator line
284	  ctx.strokeStyle = COLOR.gray500;
285	  ctx.lineWidth = 1;
286	  ctx.beginPath();
287	  ctx.moveTo(view.keyboardWidth, laneTop);
288	  ctx.lineTo(width, laneTop);
289	  ctx.stroke();
290	
291	  // Velocity bars
292	  for (const note of notes) {
293	    const x = secondsToX(note.startTime, view);
294	    const w = note.duration * view.pixelsPerSecond;
295	
296	    if (x + w < view.keyboardWidth || x > width) continue;
297	
298	    const barHeight = (note.velocity / 127) * (velocityLaneHeight - 4);
299	    const barY = laneTop + velocityLaneHeight - barHeight;
300	
301	    ctx.fillStyle = hexToRgba(COLOR.blue, 0.8);
302	    ctx.fillRect(x, barY, w, barHeight);
303	  }
304	}
305	
306	function drawPlayhead(rc: PianoRollRenderContext): void {
307	  const { ctx, height, view, cursorSeconds } = rc;
308	  const x = secondsToX(cursorSeconds, view);
309	
310	  if (x < view.keyboardWidth || x > rc.width) return;
311	
312	  ctx.strokeStyle = COLOR.red;
313	  ctx.lineWidth = 2;
314	  ctx.beginPath();
315	  ctx.moveTo(x, 0);
316	  ctx.lineTo(x, height);
317	  ctx.stroke();
318	}
319	
320	function drawRuler(rc: PianoRollRenderContext): void {
321	  const { ctx, width, view, bpm } = rc;
322	  const secPerBeat = 60 / bpm;
323	  const secPerBar = secPerBeat * 4;
324	
325	  // Ruler background
326	  ctx.fillStyle = COLOR.black;
327	  ctx.fillRect(0, 0, width, PR_RULER_HEIGHT);
328	
329	  // Bar labels
330	  ctx.font = `${String(TEXT_XS)}px ${FONT_MONO}`;
331	  ctx.fillStyle = COLOR.gray500;
332	  ctx.textBaseline = "middle";
333	  ctx.textAlign = "center";
334	
335	  const startBar = Math.max(0, Math.floor(view.scrollX / secPerBar));
336	  const endSec =
337	    view.scrollX + (width - view.keyboardWidth) / view.pixelsPerSecond;
338	  const endBar = Math.ceil(endSec / secPerBar) + 1;
339	
340	  for (let bar = startBar; bar < endBar; bar++) {
341	    const x = secondsToX(bar * secPerBar, view);
342	    if (x >= view.keyboardWidth && x <= width) {
343	      ctx.fillText(String(bar + 1), x, PR_RULER_HEIGHT / 2);
344	    }
345	  }
346	}
347	
348	// -- Public API ---------------------------------------------------------------
349	
350	export function renderPianoRoll(rc: PianoRollRenderContext): void {
351	  drawBackground(rc);
352	  drawNoteGrid(rc);
353	  drawTimeGrid(rc);
354	  drawNotes(rc);
355	  drawKeyboard(rc);
356	  drawVelocityLane(rc);
357	  drawPlayhead(rc);
358	  drawRuler(rc);
359	}
360

1	/**
2	 * Pointer interaction handlers for the piano roll canvas.
3	 * Manages draw, select, move, resize, erase, and lasso operations.
4	 * Pushes undo commands on completion.
5	 */
6	import { useCallback, useRef, useState } from "react";
7	import { useDawStore } from "@state/store";
8	import type { MIDINoteEvent } from "@state/track/types";
9	import { isMidiClip } from "@state/track/types";
10	import { sharedUndoManager } from "@state/undo";
11	import {
12	  AddNoteCommand,
13	  RemoveNoteCommand,
14	  MoveNoteCommand,
15	  ResizeNoteCommand,
16	  BatchNoteCommand,
17	} from "@state/track/midi-commands";
18	import type { PianoRollViewState, PianoRollTool } from "./piano-roll-renderer";
19	import {
20	  pianoRollHitTest,
21	  xToSeconds,
22	  yToPitch,
23	  pianoRollSnapToGrid,
24	  lassoSelectNotes,
25	  type PianoRollGridSnap,
26	} from "./piano-roll-hit-test";
27	import { PR_VELOCITY_LANE_HEIGHT } from "./constants";
28	
29	type DragState =
30	  | { kind: "idle" }
31	  | {
32	      kind: "move-note";
33	      noteId: string;
34	      clipId: string;
35	      startX: number;
36	      startY: number;
37	      origStartTime: number;
38	      origPitch: number;
39	    }
40	  | {
41	      kind: "resize-note";
42	      noteId: string;
43	      clipId: string;
44	      startX: number;
45	      origDuration: number;
46	    }
47	  | {
48	      kind: "draw-note";
49	      clipId: string;
50	      noteId: string;
51	      startTime: number;
52	      pitch: number;
53	    }
54	  | { kind: "rubber-band"; startX: number; startY: number };
55	
56	export type PianoRollInteractions = {
57	  cursor: string;
58	  onPointerDown: (e: React.PointerEvent<HTMLCanvasElement>) => void;
59	  onPointerMove: (e: React.PointerEvent<HTMLCanvasElement>) => void;
60	  onPointerUp: (e: React.PointerEvent<HTMLCanvasElement>) => void;
61	  deleteSelectedNotes: () => void;
62	};
63	
64	let noteCounter = 0;
65	function generateNoteId(): string {
66	  noteCounter += 1;
67	  return `note-${String(Date.now())}-${String(noteCounter)}`;
68	}
69	
70	function gridDuration(bpm: number, snap: PianoRollGridSnap): number {
71	  const secPerBeat = 60 / bpm;
72	  switch (snap) {
73	    case "1/4":
74	      return secPerBeat;
75	    case "1/8":
76	      return secPerBeat / 2;
77	    case "1/16":
78	      return secPerBeat / 4;
79	    case "1/8T":
80	      return secPerBeat / 3;
81	    case "1/16T":
82	      return secPerBeat / 6;
83	  }
84	}
85	
86	export function usePianoRollInteractions(
87	  clipId: string | null,
88	  view: PianoRollViewState,
89	  tool: PianoRollTool,
90	  gridSnap: PianoRollGridSnap,
91	): PianoRollInteractions {
92	  const dragRef = useRef<DragState>({ kind: "idle" });
93	  const [cursor, setCursor] = useState(
94	    clipId !== null && tool === "pencil" ? "crosshair" : "default",
95	  );
96	
97	  const getCanvasPos = useCallback(
98	    (e: React.MouseEvent<HTMLCanvasElement>): { x: number; y: number } => {
99	      const rect = e.currentTarget.getBoundingClientRect();
100	      return { x: e.clientX - rect.left, y: e.clientY - rect.top };
101	    },
102	    [],
103	  );
104	
105	  const getNotes = useCallback((): readonly MIDINoteEvent[] => {
106	    if (clipId === null) return [];
107	    const clip = useDawStore.getState().clips[clipId];
108	    if (clip === undefined || !isMidiClip(clip)) return [];
109	    return clip.noteEvents;
110	  }, [clipId]);
111	
112	  const onPointerDown = useCallback(
113	    (e: React.PointerEvent<HTMLCanvasElement>): void => {
114	      if (clipId === null) return;
115	
116	      const { x, y } = getCanvasPos(e);
117	      const state = useDawStore.getState();
118	      const notes = getNotes();
119	      const canvasHeight = e.currentTarget.getBoundingClientRect().height;
120	      const hit = pianoRollHitTest(
121	        x,
122	        y,
123	        view,
124	        notes,
125	        canvasHeight,
126	        PR_VELOCITY_LANE_HEIGHT,
127	      );
128	
129	      switch (tool) {
130	        case "pencil": {
131	          if (hit.kind === "empty-grid") {
132	            const snappedTime = pianoRollSnapToGrid(
133	              hit.timeSeconds,
134	              state.bpm,
135	              gridSnap,
136	            );
137	            const dur = gridDuration(state.bpm, gridSnap);
138	            const noteId = generateNoteId();
139	            const note: MIDINoteEvent = {
140	              id: noteId,
141	              pitch: hit.pitch,
142	              velocity: 100,
143	              startTime: Math.max(0, snappedTime),
144	              duration: dur,
145	            };
146	            const cmd = new AddNoteCommand(clipId, note);
147	            cmd.execute();
148	            sharedUndoManager.push(cmd);
149	
150	            e.currentTarget.setPointerCapture(e.pointerId);
151	            dragRef.current = {
152	              kind: "draw-note",
153	              clipId,
154	              noteId,
155	              startTime: note.startTime,
156	              pitch: note.pitch,
157	            };
158	          }
159	          break;
160	        }
161	        case "select": {
162	          if (hit.kind === "note-body") {
163	            if (e.shiftKey) {
164	              const current = [...state.selectedNoteIds];
165	              const idx = current.indexOf(hit.noteId);
166	              if (idx >= 0) {
167	                current.splice(idx, 1);
168	              } else {
169	                current.push(hit.noteId);
170	              }
171	              state.setSelectedNoteIds(current);
172	            } else {
173	              if (!state.selectedNoteIds.includes(hit.noteId)) {
174	                state.setSelectedNoteIds([hit.noteId]);
175	              }
176	            }
177	
178	            // Find note for drag
179	            const note = notes.find((n) => n.id === hit.noteId);
180	            if (note !== undefined) {
181	              e.currentTarget.setPointerCapture(e.pointerId);
182	              dragRef.current = {
183	                kind: "move-note",
184	                noteId: hit.noteId,
185	                clipId,
186	                startX: x,
187	                startY: y,
188	                origStartTime: note.startTime,
189	                origPitch: note.pitch,
190	              };
191	            }
192	          } else if (
193	            hit.kind === "note-left-edge" ||
194	            hit.kind === "note-right-edge"
195	          ) {
196	            state.setSelectedNoteIds([hit.noteId]);
197	            const note = notes.find((n) => n.id === hit.noteId);
198	            if (note !== undefined) {
199	              e.currentTarget.setPointerCapture(e.pointerId);
200	              dragRef.current = {
201	                kind: "resize-note",
202	                noteId: hit.noteId,
203	                clipId,
204	                startX: x,
205	                origDuration: note.duration,
206	              };
207	            }
208	          } else if (hit.kind === "empty-grid") {
209	            if (!e.shiftKey) {
210	              state.setSelectedNoteIds([]);
211	            }
212	            e.currentTarget.setPointerCapture(e.pointerId);
213	            dragRef.current = { kind: "rubber-band", startX: x, startY: y };
214	          }
215	          break;
216	        }
217	        case "erase": {
218	          if (
219	            hit.kind === "note-body" ||
220	            hit.kind === "note-left-edge" ||
221	            hit.kind === "note-right-edge"
222	          ) {
223	            const cmd = new RemoveNoteCommand(clipId, hit.noteId);
224	            cmd.execute();
225	            sharedUndoManager.push(cmd);
226	          }
227	          break;
228	        }
229	      }
230	    },
231	    [clipId, view, tool, gridSnap, getCanvasPos, getNotes],
232	  );
233	
234	  const onPointerMove = useCallback(
235	    (e: React.PointerEvent<HTMLCanvasElement>): void => {
236	      const { x, y } = getCanvasPos(e);
237	      const drag = dragRef.current;
238	      const state = useDawStore.getState();
239	
240	      if (drag.kind === "idle") {
241	        // Update cursor based on hover
242	        if (clipId === null) {
243	          setCursor("default");
244	          return;
245	        }
246	
247	        const notes = getNotes();
248	        const canvasHeight = e.currentTarget.getBoundingClientRect().height;
249	        const hit = pianoRollHitTest(
250	          x,
251	          y,
252	          view,
253	          notes,
254	          canvasHeight,
255	          PR_VELOCITY_LANE_HEIGHT,
256	        );
257	
258	        if (tool === "pencil") {
259	          setCursor("crosshair");
260	        } else if (tool === "select") {
261	          switch (hit.kind) {
262	            case "note-body":
263	              setCursor("pointer");
264	              break;
265	            case "note-left-edge":
266	            case "note-right-edge":
267	              setCursor("ew-resize");
268	              break;
269	            default:
270	              setCursor("default");
271	              break;
272	          }
273	        } else {
274	          setCursor("default");
275	        }
276	        return;
277	      }
278	
279	      switch (drag.kind) {
280	        case "move-note": {
281	          setCursor("grabbing");
282	          const deltaPx = x - drag.startX;
283	          const deltaSec = deltaPx / view.pixelsPerSecond;
284	          const newTime = pianoRollSnapToGrid(
285	            Math.max(0, drag.origStartTime + deltaSec),
286	            state.bpm,
287	            gridSnap,
288	          );
289	          const newPitch = yToPitch(y, view);
290	          state.moveNoteEvent(drag.clipId, drag.noteId, newTime, newPitch);
291	          break;
292	        }
293	        case "resize-note": {
294	          setCursor("ew-resize");
295	          const deltaPx = x - drag.startX;
296	          const deltaSec = deltaPx / view.pixelsPerSecond;
297	          const newDuration = Math.max(0.01, drag.origDuration + deltaSec);
298	          state.resizeNoteEvent(drag.clipId, drag.noteId, newDuration);
299	          break;
300	        }
301	        case "draw-note": {
302	          // Extend note duration as user drags
303	          const currentTime = xToSeconds(x, view);
304	          const snappedEnd = pianoRollSnapToGrid(
305	            currentTime,
306	            state.bpm,
307	            gridSnap,
308	          );
309	          const newDuration = Math.max(
310	            gridDuration(state.bpm, gridSnap),
311	            snappedEnd - drag.startTime,
312	          );
313	          state.resizeNoteEvent(drag.clipId, drag.noteId, newDuration);
314	          break;
315	        }
316	        case "rubber-band": {
317	          if (clipId === null) break;
318	          const notes = getNotes();
319	          const selected = lassoSelectNotes(
320	            drag.startX,
321	            drag.startY,
322	            x,
323	            y,
324	            view,
325	            notes,
326	          );
327	          state.setSelectedNoteIds([...selected]);
328	          break;
329	        }
330	      }
331	    },
332	    [clipId, view, tool, gridSnap, getCanvasPos, getNotes],
333	  );
334	
335	  const onPointerUp = useCallback(
336	    (e: React.PointerEvent<HTMLCanvasElement>): void => {
337	      const drag = dragRef.current;
338	
339	      if (drag.kind === "move-note") {
340	        const notes = getNotes();
341	        const note = notes.find((n) => n.id === drag.noteId);
342	        if (
343	          note !== undefined &&
344	          (note.startTime !== drag.origStartTime ||
345	            note.pitch !== drag.origPitch)
346	        ) {
347	          const cmd = new MoveNoteCommand(
348	            drag.clipId,
349	            drag.noteId,
350	            note.startTime,
351	            note.pitch,
352	          );
353	          // Already moved in store -- record for undo
354	          cmd.execute = (): void => {
355	            useDawStore
356	              .getState()
357	              .moveNoteEvent(
358	                drag.clipId,
359	                drag.noteId,
360	                note.startTime,
361	                note.pitch,
362	              );
363	          };
364	          sharedUndoManager.push(cmd);
365	        }
366	      } else if (drag.kind === "resize-note") {
367	        const notes = getNotes();
368	        const note = notes.find((n) => n.id === drag.noteId);
369	        if (note !== undefined && note.duration !== drag.origDuration) {
