393	        noteEvents: [...clip.noteEvents, note],
394	      };
395	      return { clips: { ...state.clips, [clipId]: updated } };
396	    });
397	  },
398	
399	  removeNoteEvent: (clipId: string, noteId: string) => {
400	    set((state) => {
401	      const clip = state.clips[clipId];
402	      if (!clip || !isMidiClip(clip)) return state;
