404	        ...clip,
405	        noteEvents: clip.noteEvents.filter((n) => n.id !== noteId),
406	      };
407	      return { clips: { ...state.clips, [clipId]: updated } };
408	    });
409	  },
410	
411	  moveNoteEvent: (
412	    clipId: string,
