437	        ...clip,
438	        noteEvents: clip.noteEvents.map((n) =>
439	          n.id === noteId ? { ...n, duration: newDuration } : n,
440	        ),
441	      };
442	      return { clips: { ...state.clips, [clipId]: updated } };
443	    });
444	  },
445	
446	  updateNoteVelocity: (clipId: string, noteId: string, velocity: number) => {
447	    set((state) => {
