2	import { createMidiRecorder } from "./midi-recorder";
3	import type { MidiRecorder } from "./midi-recorder";
4	import type { ValidatedMidiMessage } from "./midi-input-validator";
5	
6	describe("createMidiRecorder", () => {
7	  let recorder: MidiRecorder;
8	
9	  beforeEach(() => {
10	    recorder = createMidiRecorder();
11	  });
12	
13	  it("starts in idle state", () => {
14	    expect(recorder.state).toBe("idle");
15	  });
16	
17	  it("arm changes state to armed", () => {
18	    recorder.arm();
19	    expect(recorder.state).toBe("armed");
20	  });
21	
22	  it("startRecording changes state to recording", () => {
23	    recorder.arm();
24	    recorder.startRecording(0);
25	    expect(recorder.state).toBe("recording");
26	  });
27	
28	  it("startRecording does nothing if not armed", () => {
29	    recorder.startRecording(0);
30	    expect(recorder.state).toBe("idle");
31	  });
32	
33	  it("recordMessage captures note-on and note-off pair as MIDINoteEvent", () => {
34	    recorder.arm();
35	    recorder.startRecording(0);
36	
37	    const noteOn: ValidatedMidiMessage = {
38	      type: "note-on",
39	      note: 60,
40	      velocity: 100,
41	      channel: 0,
42	    };
43	    const noteOff: ValidatedMidiMessage = {
44	      type: "note-off",
45	      note: 60,
46	      channel: 0,
47	    };
48	
49	    recorder.recordMessage(noteOn, 1.0);
50	    recorder.recordMessage(noteOff, 2.0);
51	
52	    const notes = recorder.stopRecording();
53	    expect(notes).toHaveLength(1);
54	    expect(notes[0]?.pitch).toBe(60);
55	    expect(notes[0]?.velocity).toBe(100);
56	    expect(notes[0]?.startTime).toBe(1.0);
57	    expect(notes[0]?.duration).toBe(1.0);
58	  });
59	
60	  it("recordMessage computes correct duration from note-on to note-off", () => {
61	    recorder.arm();
62	    recorder.startRecording(10.0);
63	
64	    const noteOn: ValidatedMidiMessage = {
65	      type: "note-on",
66	      note: 72,
67	      velocity: 80,
68	      channel: 0,
69	    };
70	    const noteOff: ValidatedMidiMessage = {
71	      type: "note-off",
72	      note: 72,
73	      channel: 0,
74	    };
75	
76	    recorder.recordMessage(noteOn, 12.5);
77	    recorder.recordMessage(noteOff, 14.0);
78	
79	    const notes = recorder.stopRecording();
80	    expect(notes).toHaveLength(1);
81	    expect(notes[0]?.startTime).toBeCloseTo(2.5, 6); // 12.5 - 10.0
82	    expect(notes[0]?.duration).toBeCloseTo(1.5, 6); // 14.0 - 12.5
83	  });
84	
85	  it("recordMessage handles multiple simultaneous notes", () => {
86	    recorder.arm();
87	    recorder.startRecording(0);
88	
89	    // Two notes overlapping
90	    recorder.recordMessage(
91	      { type: "note-on", note: 60, velocity: 100, channel: 0 },
92	      0.0,
93	    );
94	    recorder.recordMessage(
95	      { type: "note-on", note: 64, velocity: 90, channel: 0 },
96	      0.5,
97	    );
98	    recorder.recordMessage({ type: "note-off", note: 60, channel: 0 }, 1.0);
99	    recorder.recordMessage({ type: "note-off", note: 64, channel: 0 }, 1.5);
100	
101	    const notes = recorder.stopRecording();
102	    expect(notes).toHaveLength(2);
103	
104	    const note60 = notes.find((n) => n.pitch === 60);
105	    const note64 = notes.find((n) => n.pitch === 64);
106	    expect(note60).toBeDefined();
107	    expect(note64).toBeDefined();
108	    expect(note60?.duration).toBeCloseTo(1.0, 6);
109	    expect(note64?.duration).toBeCloseTo(1.0, 6);
110	  });
111	
112	  it("stopRecording closes all open notes at stop time", () => {
113	    recorder.arm();
114	    recorder.startRecording(0);
115	
116	    recorder.recordMessage(
117	      { type: "note-on", note: 60, velocity: 100, channel: 0 },
118	      1.0,
119	    );
120	    // No note-off -- stop at 3.0 should close it
121	
122	    const notes = recorder.stopRecording();
123	    expect(notes).toHaveLength(1);
124	    // The open note started at transport 1.0, stop at the moment stopRecording is called
125	    // Duration is from 1.0 to whatever the last known time is
126	    expect(notes[0]?.pitch).toBe(60);
127	    expect(notes[0]?.startTime).toBe(1.0);
128	  });
129	
130	  it("stopRecording returns all captured notes and resets state", () => {
131	    recorder.arm();
132	    recorder.startRecording(0);
133	
134	    recorder.recordMessage(
135	      { type: "note-on", note: 60, velocity: 100, channel: 0 },
136	      0.0,
137	    );
138	    recorder.recordMessage({ type: "note-off", note: 60, channel: 0 }, 1.0);
139	
140	    const notes = recorder.stopRecording();
141	    expect(notes).toHaveLength(1);
142	    expect(recorder.state).toBe("idle");
143	
144	    // Second stop should return empty
145	    const notes2 = recorder.stopRecording();
146	    expect(notes2).toHaveLength(0);
147	  });
148	
149	  it("disarm resets to idle", () => {
150	    recorder.arm();
151	    expect(recorder.state).toBe("armed");
152	    recorder.disarm();
153	    expect(recorder.state).toBe("idle");
154	  });
155	
156	  it("ignores non-note messages during recording", () => {
157	    recorder.arm();
158	    recorder.startRecording(0);
159	
160	    const cc: ValidatedMidiMessage = {
161	      type: "cc",
162	      controller: 1,
163	      value: 64,
164	      channel: 0,
165	    };
166	    recorder.recordMessage(cc, 0.5);
167	
168	    const notes = recorder.stopRecording();
169	    expect(notes).toHaveLength(0);
170	  });
171	
172	  it("ignores messages when not recording", () => {
173	    recorder.recordMessage(
174	      { type: "note-on", note: 60, velocity: 100, channel: 0 },
175	      0.0,
176	    );
177	    recorder.recordMessage({ type: "note-off", note: 60, channel: 0 }, 1.0);
178	    // Not recording, so nothing captured; calling stop should be safe
179	    const notes = recorder.stopRecording();
180	    expect(notes).toHaveLength(0);
181	  });
182	});
