84	/**
85	 * Compute canvas x for a given time in seconds.
86	 * x = keyboardWidth + (time - scrollX) * pixelsPerSecond
87	 */
88	function timeToX(time: number, view: PianoRollViewState = defaultView): number {
89	  return view.keyboardWidth + (time - view.scrollX) * view.pixelsPerSecond;
