1	import { useCallback, useEffect, useMemo, useRef, useState } from "react";
2	import { useDawStore } from "@state/store";
3	import { isMidiClip } from "@state/track/types";
4	import { CommandRegistry } from "@ui/keyboard/command-registry";
5	import { ShortcutMap } from "@ui/keyboard/shortcut-map";
6	import { useKeyboardShortcuts } from "@ui/keyboard/useKeyboardShortcuts";
7	import {
8	  renderPianoRoll,
9	  type PianoRollViewState,
10	  type PianoRollTool,
11	} from "./piano-roll-renderer";
12	import type { PianoRollGridSnap } from "./piano-roll-hit-test";
13	import { usePianoRollInteractions } from "./use-piano-roll-interactions";
14	import {
15	  PR_DEFAULT_NOTE_HEIGHT,
16	  PR_KEYBOARD_WIDTH,
17	  PR_DEFAULT_PPS,
18	  PR_DEFAULT_SCROLL_Y,
19	  PR_VELOCITY_LANE_HEIGHT,
20	} from "./constants";
21	import styles from "./PianoRollEditor.module.css";
22	
23	const DEFAULT_VIEW: PianoRollViewState = {
24	  scrollX: 0,
25	  scrollY: PR_DEFAULT_SCROLL_Y,
26	  pixelsPerSecond: PR_DEFAULT_PPS,
27	  noteHeight: PR_DEFAULT_NOTE_HEIGHT,
28	  keyboardWidth: PR_KEYBOARD_WIDTH,
29	};
30	
31	const MIN_PPS = 20;
32	const MAX_PPS = 500;
33	const ZOOM_FACTOR = 1.1;
34	
35	const SNAP_OPTIONS: readonly PianoRollGridSnap[] = [
36	  "1/4",
37	  "1/8",
38	  "1/16",
39	  "1/8T",
40	  "1/16T",
41	];
42	
43	type PianoRollEditorProps = {
44	  clipId: string | null;
45	  onNotePreview?: (note: number, velocity: number) => void;
46	  onNotePreviewEnd?: (note: number) => void;
47	};
48	
49	export function PianoRollEditor({
50	  clipId,
51	  onNotePreview: _onNotePreview,
52	  onNotePreviewEnd: _onNotePreviewEnd,
53	}: PianoRollEditorProps): React.JSX.Element {
54	  const canvasRef = useRef<HTMLCanvasElement>(null);
55	  const rafRef = useRef(0);
56	  const [tool, setTool] = useState<PianoRollTool>("pencil");
57	  const [gridSnap, setGridSnap] = useState<PianoRollGridSnap>("1/8");
58	  const [view, setView] = useState(DEFAULT_VIEW);
59	
60	  const interactions = usePianoRollInteractions(clipId, view, tool, gridSnap);
61	
62	  // Store selectors
63	  const clips = useDawStore((s) => s.clips);
64	  const selectedNoteIds = useDawStore((s) => s.selectedNoteIds);
65	  const cursorSeconds = useDawStore((s) => s.cursorSeconds);
66	  const bpm = useDawStore((s) => s.bpm);
67	  const transportState = useDawStore((s) => s.transportState);
68	
69	  // Derive clip data
70	  const clip = clipId !== null ? clips[clipId] : undefined;
71	  const notes = useMemo(
72	    () => (clip !== undefined && isMidiClip(clip) ? clip.noteEvents : []),
73	    [clip],
74	  );
75	  const clipStartTime = clip !== undefined ? clip.startTime : 0;
76	  const clipDuration = clip !== undefined ? clip.duration : 4;
77	
78	  // Keyboard commands
79	  const registry = useMemo(() => {
80	    const reg = new CommandRegistry();
81	    reg.register({
82	      id: "piano-roll.tool.pencil",
83	      label: "Pencil Tool",
84	      execute() {
85	        setTool("pencil");
86	      },
87	    });
88	    reg.register({
89	      id: "piano-roll.tool.select",
90	      label: "Select Tool",
91	      execute() {
92	        setTool("select");
93	      },
94	    });
95	    reg.register({
96	      id: "piano-roll.tool.erase",
97	      label: "Erase Tool",
98	      execute() {
99	        setTool("erase");
100	      },
101	    });
102	    reg.register({
103	      id: "piano-roll.delete-selected",
104	      label: "Delete Selected Notes",
105	      execute() {
106	        interactions.deleteSelectedNotes();
107	      },
108	    });
109	    return reg;
110	  }, [interactions]);
111	
112	  const shortcuts = useMemo(() => {
113	    const map = new ShortcutMap();
114	    map.bind({ key: "p", commandId: "piano-roll.tool.pencil" });
115	    map.bind({ key: "s", commandId: "piano-roll.tool.select" });
116	    map.bind({ key: "e", commandId: "piano-roll.tool.erase" });
117	    map.bind({ key: "Delete", commandId: "piano-roll.delete-selected" });
118	    map.bind({ key: "Backspace", commandId: "piano-roll.delete-selected" });
119	    return map;
120	  }, []);
121	
122	  useKeyboardShortcuts(registry, shortcuts);
123	
124	  // Render loop
125	  const render = useCallback((): void => {
126	    const canvas = canvasRef.current;
127	    if (canvas === null) return;
128	    const ctx = canvas.getContext("2d");
129	    if (ctx === null) return;
130	
131	    const rect = canvas.getBoundingClientRect();
132	    renderPianoRoll({
133	      ctx,
134	      width: rect.width,
135	      height: rect.height,
136	      view,
137	      notes,
138	      selectedNoteIds: [...selectedNoteIds],
139	      cursorSeconds,
140	      bpm,
141	      clipStartTime,
142	      clipDuration,
143	      tool,
144	      velocityLaneHeight: PR_VELOCITY_LANE_HEIGHT,
145	    });
146	  }, [
147	    view,
148	    notes,
149	    selectedNoteIds,
150	    cursorSeconds,
151	    bpm,
152	    clipStartTime,
153	    clipDuration,
154	    tool,
155	  ]);
156	
157	  // RAF scheduling
158	  useEffect(() => {
159	    const tick = (): void => {
160	      render();
161	      if (transportState === "playing") {
162	        rafRef.current = requestAnimationFrame(tick);
163	      }
164	    };
165	
166	    rafRef.current = requestAnimationFrame(tick);
167	    return (): void => {
168	      cancelAnimationFrame(rafRef.current);
169	    };
170	  }, [render, transportState]);
171	
172	  // Canvas sizing with ResizeObserver
173	  useEffect(() => {
174	    const canvas = canvasRef.current;
175	    if (canvas === null) return;
176	    const parent = canvas.parentElement;
177	    if (parent === null) return;
178	
179	    const resizeCanvas = (): void => {
180	      const dpr = window.devicePixelRatio;
181	      const rect = parent.getBoundingClientRect();
182	      canvas.width = rect.width * dpr;
183	      canvas.height = rect.height * dpr;
184	      canvas.style.width = `${String(rect.width)}px`;
185	      canvas.style.height = `${String(rect.height)}px`;
186	
187	      const ctx = canvas.getContext("2d");
188	      if (ctx !== null) {
189	        ctx.scale(dpr, dpr);
190	      }
191	    };
192	
193	    if (typeof ResizeObserver === "undefined") return;
194	
195	    const observer = new ResizeObserver(resizeCanvas);
196	    observer.observe(parent);
197	    resizeCanvas();
198	
199	    return (): void => {
200	      observer.disconnect();
201	    };
202	  }, []);
203	
204	  // Wheel: ctrl+wheel for zoom, plain wheel for scroll
205	  const handleWheel = useCallback(
206	    (e: React.WheelEvent<HTMLCanvasElement>): void => {
207	      e.preventDefault();
208	
209	      if (e.ctrlKey || e.metaKey) {
210	        const factor = e.deltaY < 0 ? ZOOM_FACTOR : 1 / ZOOM_FACTOR;
211	        setView((prev) => ({
212	          ...prev,
213	          pixelsPerSecond: Math.min(
214	            MAX_PPS,
215	            Math.max(MIN_PPS, prev.pixelsPerSecond * factor),
216	          ),
217	        }));
218	      } else if (e.shiftKey) {
219	        setView((prev) => ({
220	          ...prev,
221	          scrollX: Math.max(0, prev.scrollX + e.deltaY / prev.pixelsPerSecond),
222	        }));
223	      } else {
224	        setView((prev) => ({
225	          ...prev,
226	          scrollX: Math.max(0, prev.scrollX + e.deltaX / prev.pixelsPerSecond),
227	          scrollY: prev.scrollY - e.deltaY / prev.noteHeight,
228	        }));
229	      }
230	    },
231	    [],
232	  );
233	
234	  return (
235	    <section data-testid="piano-roll-editor" className={styles["container"]}>
236	      <div className={styles["toolbar"]}>
237	        <button
238	          data-testid="tool-pencil"
239	          className={styles["toolButton"]}
240	          data-active={String(tool === "pencil")}
241	          onClick={() => {
242	            setTool("pencil");
243	          }}
244	        >
245	          Pencil
246	        </button>
247	        <button
248	          data-testid="tool-select"
249	          className={styles["toolButton"]}
250	          data-active={String(tool === "select")}
251	          onClick={() => {
252	            setTool("select");
253	          }}
254	        >
255	          Select
256	        </button>
257	        <button
258	          data-testid="tool-erase"
259	          className={styles["toolButton"]}
260	          data-active={String(tool === "erase")}
261	          onClick={() => {
262	            setTool("erase");
263	          }}
264	        >
265	          Erase
266	        </button>
267	        <select
268	          data-testid="snap-select"
269	          className={styles["snapSelect"]}
270	          value={gridSnap}
271	          onChange={(e) => {
272	            setGridSnap(e.target.value as PianoRollGridSnap);
273	          }}
274	        >
275	          {SNAP_OPTIONS.map((opt) => (
276	            <option key={opt} value={opt}>
277	              {opt}
278	            </option>
279	          ))}
280	        </select>
281	      </div>
282	      <div className={styles["canvasWrapper"]}>
283	        <canvas
284	          ref={canvasRef}
285	          className={styles["canvas"]}
286	          style={{ cursor: interactions.cursor }}
287	          onWheel={handleWheel}
288	          onPointerDown={interactions.onPointerDown}
289	          onPointerMove={interactions.onPointerMove}
290	          onPointerUp={interactions.onPointerUp}
291	        />
292	      </div>
293	    </section>
294	  );
295	}
