10	function normalizeKey(key: string): string {
11	  return key === " " ? "space" : key.toLowerCase();
12	}
13	
14	export class ShortcutMap {
15	  private bindings: ShortcutBinding[] = [];
16	
17	  bind(binding: ShortcutBinding): void {
18	    this.bindings.push(binding);
19	  }
20	
21	  unbind(commandId: string): void {
22	    this.bindings = this.bindings.filter((b) => b.commandId !== commandId);
23	  }
24	
25	  resolve(event: KeyboardEvent): string | undefined {
26	    const eventKey = normalizeKey(event.key);
27	    const match = this.bindings.find(
28	      (b) =>
29	        normalizeKey(b.key) === eventKey &&
30	        (b.ctrl === true) === event.ctrlKey &&
31	        (b.shift === true) === event.shiftKey &&
32	        (b.alt === true) === event.altKey &&
33	        (b.meta === true) === event.metaKey,
34	    );
35	    return match?.commandId;
36	  }
37	
38	  getBindingsForCommand(commandId: string): ShortcutBinding[] {
39	    return this.bindings.filter((b) => b.commandId === commandId);
40	  }
41	
42	  getAll(): readonly ShortcutBinding[] {
43	    return [...this.bindings];
