1	/**
2	 * Live MIDI recording -- captures validated MIDI messages into MIDINoteEvents.
3	 * Uses an open-note map to pair note-on/note-off events.
4	 */
5	
6	import type { MIDINoteEvent } from "@state/track/types";
7	import type { ValidatedMidiMessage } from "./midi-input-validator";
8	
9	export type MidiRecorderState = "idle" | "armed" | "recording";
10	
11	export type MidiRecorder = {
12	  readonly state: MidiRecorderState;
13	  arm(): void;
14	  startRecording(transportTimeSeconds: number): void;
15	  recordMessage(
16	    message: ValidatedMidiMessage,
17	    transportTimeSeconds: number,
18	  ): void;
19	  stopRecording(): readonly MIDINoteEvent[];
20	  disarm(): void;
21	};
22	
23	type OpenNote = {
24	  readonly id: string;
25	  readonly pitch: number;
26	  readonly velocity: number;
27	  readonly startTime: number; // relative to recording start
28	  readonly startAbsolute: number; // absolute transport time
29	};
30	
31	let nextNoteId = 0;
32	function generateNoteId(): string {
33	  return `rec-${String(Date.now())}-${String(nextNoteId++)}`;
34	}
35	
36	export function createMidiRecorder(): MidiRecorder {
37	  let currentState: MidiRecorderState = "idle";
38	  let recordingStartTime = 0;
39	  let lastMessageTime = 0;
40	  const openNotes = new Map<number, OpenNote>(); // keyed by channel * 128 + note
41	  const completedNotes: MIDINoteEvent[] = [];
42	
43	  function reset(): void {
44	    openNotes.clear();
45	    completedNotes.length = 0;
46	    recordingStartTime = 0;
47	    lastMessageTime = 0;
48	  }
49	
50	  return {
51	    get state(): MidiRecorderState {
52	      return currentState;
53	    },
54	
55	    arm(): void {
56	      currentState = "armed";
57	    },
58	
59	    startRecording(transportTimeSeconds: number): void {
60	      if (currentState !== "armed") return;
61	      reset();
62	      currentState = "recording";
63	      recordingStartTime = transportTimeSeconds;
64	      lastMessageTime = transportTimeSeconds;
65	    },
66	
67	    recordMessage(
68	      message: ValidatedMidiMessage,
69	      transportTimeSeconds: number,
70	    ): void {
71	      if (currentState !== "recording") return;
72	      lastMessageTime = transportTimeSeconds;
73	
74	      if (message.type === "note-on") {
75	        const key = message.channel * 128 + message.note;
